-- TMaaS clean production setup — apply on an empty Supabase public schema.
-- Generated 2026-06-15T11:55:30.346Z

-- =============================================================================
-- 01_catalog_schema.sql
-- =============================================================================
-- Catalog: categories, products, variants, features, bundles

CREATE TYPE category_type AS ENUM ('capability', 'sector', 'goal', 'navigation');
CREATE TYPE entity_status AS ENUM ('draft', 'published', 'archived');
CREATE TYPE delivery_complexity AS ENUM ('low', 'medium', 'high');

CREATE TABLE categories (
  id VARCHAR(64) PRIMARY KEY,
  parent_id VARCHAR(64) REFERENCES categories(id) ON DELETE SET NULL,
  label TEXT NOT NULL,
  category_type category_type NOT NULL DEFAULT 'navigation',
  sort_order INT NOT NULL DEFAULT 0,
  is_facetable BOOLEAN NOT NULL DEFAULT false
);

CREATE TABLE products (
  id SERIAL PRIMARY KEY,
  slug VARCHAR(255) NOT NULL UNIQUE,
  title TEXT NOT NULL,
  short_description TEXT,
  collection_id VARCHAR(64) NOT NULL REFERENCES categories(id),
  is_high_impact BOOLEAN NOT NULL DEFAULT false,
  audience TEXT,
  industry_relevance TEXT,
  department TEXT,
  business_impact TEXT,
  status entity_status NOT NULL DEFAULT 'published',
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE product_variants (
  id SERIAL PRIMARY KEY,
  product_id INT NOT NULL REFERENCES products(id) ON DELETE CASCADE,
  sku VARCHAR(64) NOT NULL UNIQUE,
  slug VARCHAR(255) NOT NULL UNIQUE,
  variant_name TEXT NOT NULL,
  service_type_id VARCHAR(32) NOT NULL,
  duration_display VARCHAR(64) NOT NULL,
  duration_weeks_min INT,
  duration_weeks_max INT,
  delivery_complexity delivery_complexity,
  implementation_model TEXT,
  badge VARCHAR(64),
  positioning TEXT,
  is_default_variant BOOLEAN NOT NULL DEFAULT false,
  status entity_status NOT NULL DEFAULT 'published',
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE product_category_map (
  product_id INT NOT NULL REFERENCES products(id) ON DELETE CASCADE,
  category_id VARCHAR(64) NOT NULL REFERENCES categories(id) ON DELETE CASCADE,
  PRIMARY KEY (product_id, category_id)
);

CREATE TABLE product_features (
  id SERIAL PRIMARY KEY,
  variant_id INT NOT NULL REFERENCES product_variants(id) ON DELETE CASCADE,
  feature_text TEXT NOT NULL,
  sort_order INT NOT NULL DEFAULT 0
);

CREATE TABLE product_tags (
  id SERIAL PRIMARY KEY,
  variant_id INT NOT NULL REFERENCES product_variants(id) ON DELETE CASCADE,
  tag_name VARCHAR(128) NOT NULL
);

CREATE TABLE variant_sector_titles (
  variant_id INT NOT NULL REFERENCES product_variants(id) ON DELETE CASCADE,
  sector_category_id VARCHAR(64) NOT NULL REFERENCES categories(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  PRIMARY KEY (variant_id, sector_category_id)
);

CREATE TABLE bundle_items (
  bundle_variant_id INT NOT NULL REFERENCES product_variants(id) ON DELETE CASCADE,
  included_variant_id INT NOT NULL REFERENCES product_variants(id) ON DELETE CASCADE,
  sort_order INT NOT NULL DEFAULT 0,
  quantity INT NOT NULL DEFAULT 1,
  discount_pct DECIMAL(5, 2),
  PRIMARY KEY (bundle_variant_id, included_variant_id)
);

CREATE TABLE product_timeline_milestones (
  id SERIAL PRIMARY KEY,
  variant_id INT NOT NULL REFERENCES product_variants(id) ON DELETE CASCADE,
  milestone_text TEXT NOT NULL,
  sort_order INT NOT NULL DEFAULT 0
);

CREATE INDEX idx_products_collection ON products(collection_id) WHERE status = 'published';
CREATE INDEX idx_variants_product ON product_variants(product_id);
CREATE INDEX idx_variants_service_type ON product_variants(service_type_id);
CREATE INDEX idx_product_tags_variant ON product_tags(variant_id);
CREATE INDEX idx_product_features_variant ON product_features(variant_id);

-- =============================================================================
-- 02_commerce_schema.sql
-- =============================================================================
-- Commerce: merchants, listings, prices, placements

CREATE TYPE listing_status AS ENUM ('active', 'out_of_stock', 'quote_only', 'hidden');
CREATE TYPE purchasability AS ENUM ('buy_now', 'request_quote', 'free', 'not_purchasable');
CREATE TYPE price_type AS ENUM ('list', 'sale', 'from', 'custom_floor');
CREATE TYPE billing_period AS ENUM ('one_time', 'monthly');
CREATE TYPE listing_placement AS ENUM ('best_seller', 'featured', 'homepage_shelf', 'category_hero');

CREATE TABLE merchants (
  id SERIAL PRIMARY KEY,
  slug VARCHAR(64) NOT NULL UNIQUE,
  name TEXT NOT NULL,
  status VARCHAR(16) NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'suspended'))
);

CREATE TABLE marketplace_listings (
  id SERIAL PRIMARY KEY,
  merchant_id INT NOT NULL REFERENCES merchants(id) ON DELETE CASCADE,
  variant_id INT NOT NULL REFERENCES product_variants(id) ON DELETE CASCADE,
  listing_status listing_status NOT NULL DEFAULT 'active',
  purchasability purchasability NOT NULL DEFAULT 'buy_now',
  lead_time_days INT,
  max_concurrent_orders INT,
  popularity_score INT NOT NULL DEFAULT 0,
  published_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE (merchant_id, variant_id)
);

CREATE TABLE variant_prices (
  id SERIAL PRIMARY KEY,
  listing_id INT NOT NULL REFERENCES marketplace_listings(id) ON DELETE CASCADE,
  price_type price_type NOT NULL DEFAULT 'list',
  amount DECIMAL(12, 2),
  currency CHAR(3) NOT NULL DEFAULT 'USD',
  price_display VARCHAR(64) NOT NULL,
  billing_period billing_period NOT NULL DEFAULT 'one_time',
  valid_from TIMESTAMPTZ NOT NULL DEFAULT now(),
  valid_to TIMESTAMPTZ,
  is_current BOOLEAN NOT NULL DEFAULT true
);

CREATE TABLE listing_placements (
  id SERIAL PRIMARY KEY,
  listing_id INT NOT NULL REFERENCES marketplace_listings(id) ON DELETE CASCADE,
  placement listing_placement NOT NULL,
  category_id VARCHAR(64) REFERENCES categories(id) ON DELETE SET NULL,
  rank INT NOT NULL DEFAULT 0,
  starts_at TIMESTAMPTZ,
  ends_at TIMESTAMPTZ
);

CREATE INDEX idx_listings_variant ON marketplace_listings(variant_id);
CREATE INDEX idx_listings_status ON marketplace_listings(listing_status) WHERE listing_status = 'active';
CREATE INDEX idx_listings_popularity ON marketplace_listings(popularity_score DESC);
CREATE INDEX idx_variant_prices_listing ON variant_prices(listing_id) WHERE is_current = true;
CREATE INDEX idx_listing_placements_listing ON listing_placements(listing_id);

-- =============================================================================
-- 03_content_schema.sql
-- =============================================================================
-- PDP content: product_content, deploy modules

CREATE TABLE product_content (
  variant_id INT PRIMARY KEY REFERENCES product_variants(id) ON DELETE CASCADE,
  description TEXT NOT NULL,
  positioning TEXT,
  overview_paragraphs JSONB,
  audience_description TEXT,
  why_it_matters JSONB,
  delivery_process_id INT
);

CREATE TABLE deploy_modules (
  id SERIAL PRIMARY KEY,
  variant_id INT NOT NULL REFERENCES product_variants(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  sort_order INT NOT NULL DEFAULT 0
);

CREATE TABLE deploy_module_features (
  id SERIAL PRIMARY KEY,
  module_id INT NOT NULL REFERENCES deploy_modules(id) ON DELETE CASCADE,
  feature_text TEXT NOT NULL,
  sort_order INT NOT NULL DEFAULT 0
);

CREATE INDEX idx_deploy_modules_variant ON deploy_modules(variant_id);

-- =============================================================================
-- 04_commerce_orders.sql
-- =============================================================================
-- Phase 2/3: carts, quotes, orders, service fulfillment

CREATE TYPE cart_status AS ENUM ('active', 'converted', 'abandoned');
CREATE TYPE quote_status AS ENUM ('draft', 'sent', 'accepted', 'expired');
CREATE TYPE order_status AS ENUM (
  'pending_payment',
  'confirmed',
  'in_fulfillment',
  'completed',
  'cancelled'
);
CREATE TYPE fulfillment_status AS ENUM (
  'pending',
  'in_progress',
  'delivered',
  'cancelled'
);
CREATE TYPE service_order_stage AS ENUM (
  'payment_confirmation_pending',
  'client_input_pending',
  'input_in_review',
  'in_delivery',
  'deliverables_pending_review',
  'closed'
);

CREATE TABLE carts (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID,
  session_id VARCHAR(128),
  status cart_status NOT NULL DEFAULT 'active',
  currency CHAR(3) NOT NULL DEFAULT 'USD',
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE cart_items (
  cart_id UUID NOT NULL REFERENCES carts(id) ON DELETE CASCADE,
  listing_id INT NOT NULL REFERENCES marketplace_listings(id) ON DELETE CASCADE,
  quantity INT NOT NULL CHECK (quantity > 0),
  unit_price_snapshot DECIMAL(12, 2),
  PRIMARY KEY (cart_id, listing_id)
);

CREATE TABLE quotes (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  cart_id UUID REFERENCES carts(id) ON DELETE SET NULL,
  order_id UUID,
  status quote_status NOT NULL DEFAULT 'draft',
  total_amount DECIMAL(12, 2),
  currency CHAR(3) NOT NULL DEFAULT 'USD',
  valid_until TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE orders (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  order_number VARCHAR(32) NOT NULL UNIQUE,
  user_id UUID,
  org_id UUID,
  merchant_id INT NOT NULL REFERENCES merchants(id),
  status order_status NOT NULL DEFAULT 'pending_payment',
  subtotal DECIMAL(12, 2) NOT NULL DEFAULT 0,
  tax DECIMAL(12, 2) NOT NULL DEFAULT 0,
  total DECIMAL(12, 2) NOT NULL DEFAULT 0,
  currency CHAR(3) NOT NULL DEFAULT 'USD',
  placed_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE order_items (
  id SERIAL PRIMARY KEY,
  order_id UUID NOT NULL REFERENCES orders(id) ON DELETE CASCADE,
  listing_id INT NOT NULL REFERENCES marketplace_listings(id),
  variant_id INT NOT NULL REFERENCES product_variants(id),
  product_title TEXT NOT NULL,
  variant_name TEXT NOT NULL,
  sku VARCHAR(64) NOT NULL,
  quantity INT NOT NULL DEFAULT 1,
  unit_price DECIMAL(12, 2) NOT NULL DEFAULT 0,
  line_total DECIMAL(12, 2) NOT NULL DEFAULT 0,
  price_display VARCHAR(64) NOT NULL,
  duration_display VARCHAR(64),
  fulfillment_status fulfillment_status NOT NULL DEFAULT 'pending'
);

CREATE TABLE service_orders (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  order_item_id INT NOT NULL UNIQUE REFERENCES order_items(id) ON DELETE CASCADE,
  service_order_number VARCHAR(32) NOT NULL UNIQUE,
  stage service_order_stage NOT NULL DEFAULT 'payment_confirmation_pending',
  delivery_lead TEXT,
  start_date DATE,
  end_date DATE,
  client_organisation TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE service_inputs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  service_order_id UUID NOT NULL REFERENCES service_orders(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  description TEXT,
  status VARCHAR(32) NOT NULL DEFAULT 'Pending',
  submitted_date TIMESTAMPTZ,
  review_feedback TEXT
);

CREATE TABLE service_deliverables (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  service_order_id UUID NOT NULL REFERENCES service_orders(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  description TEXT,
  status VARCHAR(32) NOT NULL DEFAULT 'Not Started',
  submission_date TIMESTAMPTZ,
  review_deadline TIMESTAMPTZ,
  client_feedback TEXT,
  accepted_by TEXT,
  accepted_date TIMESTAMPTZ
);

CREATE TABLE service_sessions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  service_order_id UUID NOT NULL REFERENCES service_orders(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  description TEXT,
  session_date TIMESTAMPTZ NOT NULL,
  duration_minutes INT NOT NULL DEFAULT 60,
  status VARCHAR(32) NOT NULL DEFAULT 'Scheduled',
  meeting_link TEXT,
  notes TEXT
);

CREATE TABLE service_audit_log (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  service_order_id UUID NOT NULL REFERENCES service_orders(id) ON DELETE CASCADE,
  timestamp TIMESTAMPTZ NOT NULL DEFAULT now(),
  actor TEXT NOT NULL,
  action TEXT NOT NULL,
  details TEXT,
  entry_type VARCHAR(32) NOT NULL DEFAULT 'message'
);

CREATE INDEX idx_cart_items_cart ON cart_items(cart_id);
CREATE INDEX idx_order_items_order ON order_items(order_id);
CREATE INDEX idx_service_orders_stage ON service_orders(stage);

-- =============================================================================
-- 05_search_index.sql
-- =============================================================================
-- PLP read model: views and materialized search index

CREATE OR REPLACE VIEW marketplace_listings_view AS
SELECT
  l.id AS listing_id,
  l.merchant_id,
  l.variant_id,
  l.listing_status,
  l.purchasability,
  l.popularity_score,
  v.product_id,
  v.sku,
  v.slug,
  v.variant_name,
  v.service_type_id,
  v.duration_display,
  v.duration_weeks_min,
  v.duration_weeks_max,
  v.delivery_complexity,
  v.implementation_model,
  v.badge,
  v.positioning,
  p.title AS product_title,
  p.short_description,
  p.collection_id,
  p.is_high_impact,
  p.audience,
  p.industry_relevance,
  p.department,
  p.business_impact,
  vp.price_display,
  vp.amount AS price_amount,
  vp.currency,
  (p.title || ' - ' || v.variant_name) AS display_title,
  (v.service_type_id = 'bundle') AS is_bundle
FROM marketplace_listings l
JOIN product_variants v ON v.id = l.variant_id
JOIN products p ON p.id = v.product_id
LEFT JOIN variant_prices vp ON vp.listing_id = l.id AND vp.is_current = true
WHERE l.listing_status = 'active'
  AND v.status = 'published'
  AND p.status = 'published';

CREATE MATERIALIZED VIEW product_search_index AS
SELECT
  l.id AS listing_id,
  v.id AS variant_id,
  p.id AS product_id,
  v.slug,
  (p.title || ' - ' || v.variant_name) AS display_title,
  COALESCE(pc.description, p.short_description) AS short_description,
  p.collection_id,
  v.service_type_id,
  vp.amount AS price_amount_min,
  vp.price_display,
  v.duration_display,
  v.duration_weeks_min,
  l.popularity_score,
  (v.service_type_id = 'bundle') AS is_bundle,
  l.purchasability,
  COALESCE(
    (
      SELECT jsonb_agg(DISTINCT pt.tag_name)
      FROM product_tags pt
      WHERE pt.variant_id = v.id
    ),
    '[]'::jsonb
  ) AS tags,
  COALESCE(
    (
      SELECT jsonb_agg(pcm.category_id)
      FROM product_category_map pcm
      WHERE pcm.product_id = p.id
    ),
    '[]'::jsonb
  ) AS category_ids,
  to_tsvector(
    'english',
    coalesce(p.title, '') || ' ' ||
    coalesce(v.variant_name, '') || ' ' ||
    coalesce(pc.description, p.short_description, '') || ' ' ||
    coalesce(
      (SELECT string_agg(pt.tag_name, ' ') FROM product_tags pt WHERE pt.variant_id = v.id),
      ''
    ) || ' ' ||
    coalesce(
      (SELECT string_agg(pf.feature_text, ' ') FROM product_features pf WHERE pf.variant_id = v.id),
      ''
    )
  ) AS search_vector
FROM marketplace_listings l
JOIN product_variants v ON v.id = l.variant_id
JOIN products p ON p.id = v.product_id
LEFT JOIN variant_prices vp ON vp.listing_id = l.id AND vp.is_current = true
LEFT JOIN product_content pc ON pc.variant_id = v.id
WHERE l.listing_status = 'active'
  AND v.status = 'published'
  AND p.status = 'published';

CREATE UNIQUE INDEX idx_product_search_index_listing ON product_search_index (listing_id);
CREATE INDEX idx_product_search_index_collection ON product_search_index (collection_id, popularity_score DESC);
CREATE INDEX idx_product_search_index_service_type ON product_search_index (service_type_id);
CREATE INDEX idx_product_search_index_price ON product_search_index (price_amount_min);
CREATE INDEX idx_product_search_index_duration ON product_search_index (duration_weeks_min);
CREATE INDEX idx_product_search_index_search ON product_search_index USING GIN (search_vector);

CREATE OR REPLACE FUNCTION refresh_product_search_index()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  REFRESH MATERIALIZED VIEW CONCURRENTLY product_search_index;
EXCEPTION
  WHEN OTHERS THEN
    REFRESH MATERIALIZED VIEW product_search_index;
END;
$$;

-- =============================================================================
-- 06_rls_policies.sql
-- =============================================================================
-- Row Level Security: public read on catalog, authenticated write on carts/orders

ALTER TABLE categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE products ENABLE ROW LEVEL SECURITY;
ALTER TABLE product_variants ENABLE ROW LEVEL SECURITY;
ALTER TABLE product_category_map ENABLE ROW LEVEL SECURITY;
ALTER TABLE product_features ENABLE ROW LEVEL SECURITY;
ALTER TABLE product_tags ENABLE ROW LEVEL SECURITY;
ALTER TABLE variant_sector_titles ENABLE ROW LEVEL SECURITY;
ALTER TABLE bundle_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE product_timeline_milestones ENABLE ROW LEVEL SECURITY;
ALTER TABLE merchants ENABLE ROW LEVEL SECURITY;
ALTER TABLE marketplace_listings ENABLE ROW LEVEL SECURITY;
ALTER TABLE variant_prices ENABLE ROW LEVEL SECURITY;
ALTER TABLE listing_placements ENABLE ROW LEVEL SECURITY;
ALTER TABLE product_content ENABLE ROW LEVEL SECURITY;
ALTER TABLE deploy_modules ENABLE ROW LEVEL SECURITY;
ALTER TABLE deploy_module_features ENABLE ROW LEVEL SECURITY;
ALTER TABLE carts ENABLE ROW LEVEL SECURITY;
ALTER TABLE cart_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE quotes ENABLE ROW LEVEL SECURITY;
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE order_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE service_orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE service_inputs ENABLE ROW LEVEL SECURITY;
ALTER TABLE service_deliverables ENABLE ROW LEVEL SECURITY;
ALTER TABLE service_sessions ENABLE ROW LEVEL SECURITY;
ALTER TABLE service_audit_log ENABLE ROW LEVEL SECURITY;

-- Public read: catalog + commerce listings
CREATE POLICY "Public read categories" ON categories FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "Public read products" ON products FOR SELECT TO anon, authenticated USING (status = 'published');
CREATE POLICY "Public read variants" ON product_variants FOR SELECT TO anon, authenticated USING (status = 'published');
CREATE POLICY "Public read product_category_map" ON product_category_map FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "Public read product_features" ON product_features FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "Public read product_tags" ON product_tags FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "Public read variant_sector_titles" ON variant_sector_titles FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "Public read bundle_items" ON bundle_items FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "Public read milestones" ON product_timeline_milestones FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "Public read merchants" ON merchants FOR SELECT TO anon, authenticated USING (status = 'active');
CREATE POLICY "Public read listings" ON marketplace_listings FOR SELECT TO anon, authenticated USING (listing_status = 'active');
CREATE POLICY "Public read prices" ON variant_prices FOR SELECT TO anon, authenticated USING (is_current = true);
CREATE POLICY "Public read placements" ON listing_placements FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "Public read product_content" ON product_content FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "Public read deploy_modules" ON deploy_modules FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "Public read deploy_module_features" ON deploy_module_features FOR SELECT TO anon, authenticated USING (true);

-- Carts: users manage own carts (session-based guest carts use service role in API layer)
CREATE POLICY "Users read own carts" ON carts FOR SELECT TO authenticated USING (user_id = auth.uid());
CREATE POLICY "Users insert own carts" ON carts FOR INSERT TO authenticated WITH CHECK (user_id = auth.uid());
CREATE POLICY "Users update own carts" ON carts FOR UPDATE TO authenticated USING (user_id = auth.uid());

CREATE POLICY "Users read own cart items" ON cart_items FOR SELECT TO authenticated
  USING (EXISTS (SELECT 1 FROM carts c WHERE c.id = cart_id AND c.user_id = auth.uid()));
CREATE POLICY "Users manage own cart items" ON cart_items FOR ALL TO authenticated
  USING (EXISTS (SELECT 1 FROM carts c WHERE c.id = cart_id AND c.user_id = auth.uid()));

-- Orders: buyers read own orders
CREATE POLICY "Users read own orders" ON orders FOR SELECT TO authenticated USING (user_id = auth.uid());
CREATE POLICY "Users read own order items" ON order_items FOR SELECT TO authenticated
  USING (EXISTS (SELECT 1 FROM orders o WHERE o.id = order_id AND o.user_id = auth.uid()));
CREATE POLICY "Users read own service orders" ON service_orders FOR SELECT TO authenticated
  USING (EXISTS (
    SELECT 1 FROM order_items oi
    JOIN orders o ON o.id = oi.order_id
    WHERE oi.id = order_item_id AND o.user_id = auth.uid()
  ));

GRANT SELECT ON marketplace_listings_view TO anon, authenticated;
GRANT SELECT ON product_search_index TO anon, authenticated;

CREATE OR REPLACE FUNCTION reset_catalog_sequences()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  PERFORM setval(pg_get_serial_sequence('products', 'id'), COALESCE((SELECT MAX(id) FROM products), 1));
  PERFORM setval(pg_get_serial_sequence('product_variants', 'id'), COALESCE((SELECT MAX(id) FROM product_variants), 1));
  PERFORM setval(pg_get_serial_sequence('marketplace_listings', 'id'), COALESCE((SELECT MAX(id) FROM marketplace_listings), 1));
  PERFORM setval(pg_get_serial_sequence('merchants', 'id'), COALESCE((SELECT MAX(id) FROM merchants), 1));
END;
$$;

