-- =============================================================================
-- 08_base_catalog_seed.sql
-- =============================================================================
-- Base catalog rows (35 products, 221 variants).
-- Card and PDP copy in this file are placeholders; migrations 09–10 apply the
-- authoritative non-generic copy from workspace/dba-catalog-copy (see handoff.md).

-- Seed: full marketplace catalog (35 products, 221 product_variants)
-- Prerequisites: migrations 20250610000001 … 20250610000006 must be applied first.
--
-- Regenerate: npm run db:migration:full-catalog
-- Standalone SQL copy: supabase/seed-data.sql
--
-- Run in Supabase Dashboard → SQL Editor, or: supabase db push
--
-- Re-seeding on a DB that already has catalog data: uncomment the TRUNCATE block below.

/*
TRUNCATE
  bundle_items,
  deploy_module_features,
  deploy_modules,
  listing_placements,
  variant_prices,
  marketplace_listings,
  product_timeline_milestones,
  product_tags,
  product_features,
  product_content,
  product_category_map,
  product_variants,
  products,
  merchants,
  categories
RESTART IDENTITY CASCADE;
*/

BEGIN;
SELECT reset_catalog_sequences();
SELECT refresh_product_search_index();
COMMIT;

-- =============================================================================
-- 09_card_content.sql
-- =============================================================================
-- Idempotent card-content update for an already-seeded catalog.
-- Do NOT use seed-data.sql on a populated database (that file is INSERT-only).
