INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (1, 'Web estate audit report', 'Page-level findings covering performance, accessibility, SEO, and conversion barriers, with each issue rated by severity and effort to fix.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (1, 'SEO gap analysis', 'Keyword coverage, crawlability issues, and content gaps mapped against organic visibility targets.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (1, 'Competitor benchmark', 'Side-by-side comparison of your top three competitors on journey quality, content depth, and search presence.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (1, 'Prioritised action roadmap', 'Sequenced recommendations with effort scores, expected business impact, and suggested owners so your team can begin immediately.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (1, 'What access do you need to run the audit?', 'Read-only access to Google Analytics or equivalent, Google Search Console, and your CMS is ideal. The DigitalQatalyst team agrees the exact access list during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (1, 'Do you audit every page on our site?', 'We crawl the full site but focus detailed analysis on the highest-traffic and highest-value pages. Scope is confirmed with your team at the start.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (1, 'Will we get specific fixes or just a list of issues?', 'Both. Each finding comes with a recommended fix, effort estimate, and expected impact so your teams have actionable instructions, not just a list of problems.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (1, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm scope, access requirements, and stakeholders before the engagement begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (2, 'User journey maps', 'Documented journeys for each visitor type, showing entry points, decision moments, and the actions needed to reach conversion.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (2, 'Information architecture and navigation design', 'Site structure, menu hierarchy, and content taxonomy validated against user expectations and business goals.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (2, 'Wireframe library', 'Annotated wireframes for every key template and interaction, with component-level specifications your developers can implement directly.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (2, 'Technical and integration specification', 'CMS requirements, third-party integration points, and API contracts documented to eliminate ambiguity during build.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (2, 'Do we need to have completed an assessment first?', 'Not mandatory, but recommended. The DigitalQatalyst team can work from your existing analytics and research if an assessment has not been done.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (2, 'Will the designs be handed off to our internal developers or to your team?', 'Either. The specification pack is tool-agnostic and includes everything an internal team or an external agency needs to build accurately.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (2, 'How much user research is included?', 'The engagement includes synthesis of existing data and targeted interviews or usability sessions. Larger primary research programmes can be scoped separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (2, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your existing assets, agree the design scope, and confirm the research approach before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (3, 'AI opportunity register', 'Ranked list of AI use cases for your web presence, each scored on visitor impact, data readiness, and build complexity.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (3, 'Responsible AI workflow designs', 'Process flows for each prioritised use case, including human-in-the-loop checkpoints, bias mitigation, and fallback logic.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (3, 'Data and model specification', 'Training data requirements, model selection criteria, and pipeline architecture for each approved use case.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (3, 'Deployment-ready build specification', 'Integration contracts, API requirements, and acceptance criteria your engineering team can build and test against.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (3, 'Which AI use cases are most common for web presence?', 'Personalised content recommendations, AI-powered site search, conversational chat assistants, and automated content tagging are the most frequently prioritised. The DigitalQatalyst team will validate which of these fits your data and visitor profile.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (3, 'What data do we need to have in place?', 'We assess your current data landscape as part of the engagement and identify gaps. You do not need a complete data platform before starting.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (3, 'How do you handle AI risks like hallucination or bias?', 'Every workflow design includes a responsible AI review covering bias testing, output validation, fallback logic, and human escalation paths.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (3, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm your AI readiness level and agree the discovery scope before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (4, 'Configured and tested website', 'Fully built site meeting the design specification, with all integrations live and accessibility checks passed.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (4, 'QA test report', 'Documented test results covering cross-browser compatibility, performance benchmarks, accessibility compliance, and resolved defects.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (4, 'Launch runbook', 'Step-by-step go-live procedure including DNS changes, cache warm-up, monitoring checks, and rollback instructions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (4, 'Operations handover pack', 'CMS user guides, integration documentation, and maintenance procedures your internal team needs to manage the site post-launch.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (4, 'Does the Deploy service include content creation?', 'Content migration is included. Content creation and copywriting are separate and can be quoted alongside this service.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (4, 'Which CMS platforms do you build on?', 'The DigitalQatalyst team works across the major platforms including WordPress, Contentful, Sanity, and custom headless stacks. The target platform is confirmed during design.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (4, 'How is change managed during the build?', 'Scope changes go through a formal change request process to protect the timeline and budget. Minor clarifications are absorbed; additions are quoted separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (4, 'What happens if a critical issue is found after launch?', 'The launch runbook includes a rollback procedure. The DigitalQatalyst team provides a defined hypercare window post-go-live to resolve priority defects.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (4, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the design specification, confirm the technical environment, and agree a delivery schedule.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (5, 'Deployed AI features', 'AI capabilities live on your website, integrated with your CMS and analytics stack, and confirmed against the agreed acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (5, 'Monitoring and alerting dashboard', 'Real-time view of model accuracy, response latency, and safety flags with configured alerts for your operations team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (5, 'Safety and moderation controls', 'Output filters, fallback logic, and escalation paths configured and tested to protect visitors and your brand.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (5, 'AI operations runbook', 'Step-by-step procedures for monitoring, retraining triggers, incident response, and routine maintenance of each deployed AI feature.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (5, 'Do we need in-house ML engineers to manage the AI features after launch?', 'Not necessarily. The DigitalQatalyst team designs the operational model around your team''s capability and can include an ongoing managed tier if needed.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (5, 'How do you handle model drift over time?', 'Monitoring dashboards flag accuracy degradation. The runbook includes retraining triggers and a process for re-deploying updated models without site downtime.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (5, 'What if an AI feature produces harmful or incorrect outputs?', 'Safety controls and fallback logic are configured and tested before launch. The moderation layer catches out-of-policy outputs before they reach visitors.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (5, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the AI Design specification and confirm the deployment environment before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (6, 'Monthly performance report', 'Traffic, SEO, speed, and conversion data with month-on-month trends and recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (6, 'Issue log and resolution record', 'Tracked log of every detected issue, time to resolution, and root cause, demonstrating SLA compliance.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (6, 'Quarterly optimisation plan', 'Prioritised improvements for the next quarter, each with expected impact and effort, agreed with your team in advance.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (6, 'Annual web health review', 'Full assessment of your web estate''s performance against goals, with strategic recommendations for the year ahead.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'What is included in the SLA?', 'Response and resolution times for critical, high, and standard issues, plus monthly reporting delivery dates. Exact SLA terms are agreed during onboarding.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'Can we make content updates ourselves or does everything go through your team?', 'You retain full CMS access. The DigitalQatalyst team handles governance, quality checks, and complex updates while your team handles day-to-day content.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'How are quarterly optimisation priorities set?', 'The DigitalQatalyst team analyses performance data and presents a prioritised list at the start of each quarter. You approve the plan before work begins.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'What happens if performance drops after go-live?', 'The DigitalQatalyst team monitors your website continuously and responds to critical performance incidents within four business hours. Non-critical issues are triaged and resolved in line with the SLA response targets agreed during onboarding.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'What happens if our website needs a major redesign during the managed contract?', 'Major redesigns are scoped as separate Design or Deploy engagements. The managed service continues uninterrupted during the project.', 4);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your current web setup, agree the SLA terms, and confirm the onboarding timeline.', 5);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (7, 'Social channel audit report', 'Platform-by-platform findings on content quality, posting frequency, engagement rates, and follower demographics.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (7, 'Brand consistency assessment', 'Review of voice, visual identity, and messaging coherence across your active social accounts.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (7, 'Competitor social benchmark', 'Comparison of your top three competitors on content strategy, audience growth rate, and engagement quality.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (7, 'Prioritised social action plan', 'Ranked recommendations with expected engagement impact and implementation effort for your marketing team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (7, 'Which social platforms do you cover in the audit?', 'All platforms where your organisation has an active presence. The DigitalQatalyst team confirms the channel list during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (7, 'Do you need admin access to our social accounts?', 'Read-only analytics access is sufficient. The DigitalQatalyst team agrees the exact access requirements before the engagement starts.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (7, 'Will you assess our paid social campaigns as well as organic content?', 'The standard assessment focuses on organic presence. Paid social campaign analysis can be added to scope during the initial consultation.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (7, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the channel scope and access requirements before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (8, 'Platform-specific content strategy', 'Audience-validated content approach for each active social channel, covering formats, tone, themes, and posting cadence.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (8, 'Content pillar and topic framework', 'Structured content pillars with topic clusters, format guidance, and a 90-day content calendar template.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (8, 'Editorial and approval workflow', 'End-to-end process for content creation, review, scheduling, and performance tracking, mapped to your team structure.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (8, 'Community management playbook', 'Response frameworks for comments, direct messages, and crisis scenarios, with example copy your team can adapt.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (8, 'Does the design include creating actual social content?', 'The engagement produces frameworks, templates, and examples rather than finished posts. Content production can be scoped as a separate service.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (8, 'What if our team is small? Will the workflows be too complex to run?', 'Workflow design is matched to your team''s size and capability. The DigitalQatalyst team designs for what your team can realistically sustain.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (8, 'Can you design for a new platform we have not used before?', 'Yes. The DigitalQatalyst team can include strategy for platforms you are launching on, with audience research to validate the channel choice.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (8, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your current channels and team structure before agreeing the design scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (9, 'AI opportunity assessment', 'Ranked list of AI use cases for social presence, each scored on audience impact, platform feasibility, and implementation effort.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (9, 'Social listening and sentiment workflow', 'Designed workflow for AI-powered monitoring, alerting, and escalation, including response thresholds for your community team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (9, 'Content AI specification', 'Requirements for caption assistance, hashtag optimisation, and scheduling tools, with vendor shortlist and integration contracts.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (9, 'Responsible moderation design', 'AI moderation rules, escalation paths, and human-review criteria that protect your brand without silencing legitimate audience voices.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (9, 'Can AI really help with social content creation without sounding robotic?', 'Yes, when implemented with your brand voice guidelines and human editorial review. The design includes tone guardrails and a human-approval step for all published content.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (9, 'Which social platforms support AI integrations?', 'Most major platforms expose APIs for scheduling, analytics, and moderation. The DigitalQatalyst team validates feasibility per platform during the design engagement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (9, 'How do you handle AI-generated content and transparency obligations?', 'The workflow design includes disclosure guidance aligned with current platform policies and relevant regulatory guidance in your region.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (9, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your current social stack and agree the AI design scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (10, 'Configured social management platform', 'All active channels connected, permission levels set, approval workflows active, and accounts verified across your social management tool.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (10, 'Analytics and reporting dashboard', 'Live reporting across all channels showing reach, engagement, follower growth, and content performance with automated monthly report templates.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (10, 'Training materials and guides', 'Role-specific guides for content creators, approvers, and community managers so your team runs every tool without ongoing support.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (10, 'Operations handover pack', 'All platform credentials, workflow documentation, and escalation contacts compiled and handed to your team at close.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (10, 'Which social management tools do you deploy?', 'Hootsuite, Sprout Social, Buffer, and similar platforms. If you have an existing tool, the DigitalQatalyst team configures it. If not, a recommendation is made during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (10, 'Is content creation included in the deploy?', 'Content deployment tools and workflows are included. Content creation and copywriting are separate and can be scoped alongside this service.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (10, 'How long does team training take?', 'Typically two to three sessions across the final weeks of deployment, tailored to each role. Self-service reference guides are provided for ongoing use.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (10, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm your current technology, account access, and deployment timeline.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (11, 'Deployed AI social tools', 'Listening, content assistance, and moderation AI live across your active channels, integrated with your social management platform.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (11, 'Monitoring and alerting configuration', 'Real-time dashboards for brand sentiment, keyword alerts, and moderation activity with configured escalation thresholds.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (11, 'Content AI guardrail configuration', 'Brand voice rules, topic restrictions, and human approval workflows configured and tested before any AI content reaches your audience.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (11, 'AI operations guide', 'Procedures for managing alerts, reviewing moderation decisions, updating content AI rules, and handling AI tool incidents.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (11, 'Will AI moderation remove comments our community should see?', 'Moderation rules are calibrated to your community standards and reviewed before activation. The system flags for human review rather than automatically deleting borderline content.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (11, 'How does the social listening AI handle multiple languages?', 'Multi-language support is configured based on your audience profile. The DigitalQatalyst team confirms language coverage during the deployment setup.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (11, 'What happens if an AI tool produces inappropriate content?', 'Editorial approval gates prevent AI-suggested content from publishing without human sign-off. The guardrail configuration is tested before any tool goes live.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (11, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the AI design specification and confirm the deployment infrastructure.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (12, 'Monthly content publishing report', 'Record of all published content with per-post engagement data, reach, and impressions by channel.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (12, 'Community management log', 'Tracked log of all monitored interactions, response times against SLA, and escalated items for your team''s attention.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (12, 'Monthly social performance report', 'Audience growth, engagement rate trends, and content effectiveness scores with recommended adjustments.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (12, 'Quarterly strategy review', 'Assessment of the quarter''s social performance against goals, with a revised content approach and priorities for the next period.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (12, 'Does your team create the social content or do we?', 'The DigitalQatalyst team creates and publishes content within agreed brand guidelines. You review and approve the monthly content calendar before publication.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (12, 'What response time is guaranteed for community management?', 'Response timeframes are defined in the SLA during onboarding. Typical configurations target four-hour response for standard comments and one-hour for urgent or crisis mentions.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (12, 'Can we adjust the content direction mid-contract?', 'Yes. The quarterly strategy review is the formal checkpoint, but the DigitalQatalyst team can accommodate urgent messaging changes outside of the review cycle.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (12, 'What happens during a social media crisis?', 'A crisis escalation protocol is agreed during onboarding. The DigitalQatalyst team alerts your communications lead immediately and follows the agreed response procedure.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (12, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm channel access, review your brand guidelines, and agree the SLA terms before onboarding begins.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (13, 'Mobile app audit report', 'Findings across UX quality, technical performance, app store ratings, and retention funnel, with each issue rated by severity.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (13, 'Journey friction analysis', 'Identified drop-off points in your key user journeys with specific causes and recommended fixes.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (13, 'Technical performance benchmark', 'App load times, crash rates, and API performance compared against category benchmarks for your app store category.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (13, 'Prioritised mobile roadmap', 'Sequenced improvement recommendations with user impact scores, engineering effort estimates, and suggested sprint sequencing.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (13, 'Do you audit both iOS and Android versions?', 'Yes. The audit covers both platforms unless the assessment scope is limited to one by mutual agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (13, 'What data access do you need?', 'Firebase or equivalent analytics, App Store Connect, and Google Play Console read-only access. The DigitalQatalyst team confirms the exact list during scoping.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (13, 'Can you assess an app still in development, not yet in production?', 'Yes. The assessment can be run on a staging build. Findings will focus on UX and technical architecture rather than live retention data.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (13, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the platform scope and access requirements before the engagement begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (14, 'Mobile user journey maps', 'Research-validated journeys for each user type across the key app flows, including edge cases and error states.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (14, 'Interaction design and prototype', 'Screen-by-screen designs with annotated interactions for iOS and Android, tested with real users before specification sign-off.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (14, 'Mobile design system', 'Component library, colour system, typography, and accessibility guidelines aligned to platform standards.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (14, 'Technical build specification', 'API contracts, data models, push notification flows, and offline behaviour documented for your engineering team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (14, 'Do you design for both iOS and Android in the same engagement?', 'Yes. The design system and specification cover both platforms, with platform-specific component guidance where the experiences diverge.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (14, 'How many rounds of usability testing are included?', 'One round of moderated usability testing is included. Additional rounds can be added to the scope during the initial consultation.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (14, 'Is the prototype interactive?', 'Yes. A clickable prototype is produced for usability testing and stakeholder sign-off. It covers the core journeys rather than every screen.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (14, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your product brief and existing research before agreeing the design scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (15, 'Mobile AI opportunity register', 'Ranked AI use cases for your app, each scored on user impact, technical feasibility, and privacy considerations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (15, 'On-device versus cloud analysis', 'Documented trade-offs for each use case covering latency, connectivity requirements, battery impact, and data privacy.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (15, 'Responsible AI specification', 'Bias testing requirements, consent flow designs, data minimisation rules, and human oversight checkpoints for each approved use case.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (15, 'Mobile AI build specification', 'SDK and API requirements, model delivery approach, and integration contracts your engineering team can build to.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (15, 'Can AI features work offline on mobile?', 'On-device AI models can operate without connectivity. The design engagement assesses which features are suitable for on-device deployment and which require cloud inference.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (15, 'How do you handle app store AI disclosure requirements?', 'The specification includes platform-specific disclosure requirements for iOS and Android, aligned to current App Store and Google Play policies.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (15, 'What if our app user base is privacy-sensitive?', 'Privacy-first AI design is the default. Data minimisation, on-device processing options, and explicit consent flows are designed into every use case.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (15, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your existing app architecture and agree the AI design scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (16, 'Production-ready mobile app', 'Fully built application on iOS and Android meeting the specification, passing QA, and live in both app stores.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (16, 'QA test report', 'Documented test results covering real-device performance, accessibility, offline behaviour, and resolved defects.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (16, 'App store submission package', 'App store listings, screenshots, metadata, and privacy disclosures prepared and submitted with review process managed.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (16, 'Technical handover documentation', 'Architecture overview, API documentation, build and deployment procedures, and maintenance guides for your engineering team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (16, 'Do you build native or cross-platform apps?', 'Both options are available. The DigitalQatalyst team recommends the approach best suited to your performance requirements, team capability, and budget during the design phase.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (16, 'How do you handle app store rejection during the review process?', 'App store review requirements are built into the QA checklist before submission. If a rejection occurs, the DigitalQatalyst team resolves the flagged issue and resubmits.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (16, 'What is included in the hypercare period?', 'Priority defect resolution, performance monitoring, and crash report triage for a defined window after launch. Duration is confirmed during scoping.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (16, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the design specification and agree the build schedule and technology stack.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (17, 'Deployed AI mobile features', 'AI capabilities live in your production app on iOS and Android, integrated with your backend services and confirmed against acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (17, 'Mobile AI monitoring dashboard', 'Real-time view of model accuracy, inference latency, battery impact, and error rates with configured alerts.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (17, 'Privacy and consent implementation', 'User consent flows, data handling disclosures, and privacy controls implemented, tested, and confirmed against platform policies.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (17, 'AI model management guide', 'Procedures for monitoring performance, triggering retraining, deploying model updates, and handling AI-related incidents.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (17, 'How do on-device model updates reach users?', 'Model updates can be delivered via app store releases or over-the-air model delivery frameworks. The deployment approach is documented in the model management guide.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (17, 'Will AI features increase our app''s data consumption or battery usage?', 'Battery and data impact are monitored as part of the production deployment. On-device model size and inference frequency are optimised during the build phase.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (17, 'How do we manage AI features if we do not have ML engineers in-house?', 'The handover documentation and training are designed for product and mobile engineering teams without dedicated ML expertise. The DigitalQatalyst team can also provide an ongoing managed tier.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (17, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the AI design specification and confirm the deployment environment and tooling.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (18, 'Monthly release report', 'Record of all releases including changes shipped, QA outcomes, and app store review status.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (18, 'Performance and stability report', 'Monthly crash rates, ANR rates, and performance benchmarks with trends and resolved issue log.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (18, 'App store optimisation report', 'Keyword rankings, rating trends, review response log, and listing update history by month.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (18, 'Quarterly product review', 'Retention analysis, user feedback synthesis, and prioritised feature and improvement recommendations for the next quarter.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (18, 'What is included in monthly release management?', 'Bug fixes, OS and device compatibility updates, and minor enhancements within agreed scope. Feature additions are quoted separately.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (18, 'How quickly are critical crashes resolved?', 'Critical crash SLA timeframes are agreed during onboarding. The DigitalQatalyst team monitors crash reporting continuously and escalates immediately for severity-one issues.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (18, 'Do you manage both the iOS and Android app store presences?', 'Yes. App Store Connect and Google Play management are both included in the managed service.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (18, 'What happens if a new OS version breaks our app?', 'The DigitalQatalyst team monitors OS beta releases and tests compatibility ahead of public releases, issuing a compatibility update before it affects users.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (18, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your app, agree the release cadence, and confirm the monitoring and SLA terms.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (19, 'Physical channel audit report', 'Location-by-location findings on service quality, process efficiency, staff tools, and customer experience consistency.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (19, 'Digital-to-physical handoff analysis', 'Mapped gaps where digital journeys fail to connect with in-person service, with specific causes and recommended fixes.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (19, 'Staff and process friction inventory', 'Identified workflow bottlenecks and tool gaps reducing frontline staff efficiency, with severity ratings.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (19, 'Prioritised physical channel roadmap', 'Sequenced improvement actions with customer experience scores, operational effort estimates, and suggested owners.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (19, 'How many locations do you visit for the audit?', 'A sample of locations is agreed during scoping based on your network size and geographic spread. Findings are extrapolated across the full estate.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (19, 'Do staff know they are being observed?', 'Mystery shopping visits are unannounced. Structured observation sessions are agreed with site managers in advance. The approach is confirmed with your team during scoping.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (19, 'Do you cover kiosks and automated service points as well as staffed counters?', 'Yes. All physical touchpoints within scope are included, whether staffed, self-service, or hybrid.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (19, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the location sample, access arrangements, and assessment scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (20, 'Redesigned service journey maps', 'Step-by-step service flows for each priority scenario, tested with frontline staff and validated against customer research.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (20, 'Standard operating procedures', 'Documented service steps, decision rules, tool requirements, and escalation paths for each redesigned journey.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (20, 'Digital-to-physical integration specification', 'Technical and process requirements for passing customer context between digital and in-person channels without friction.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (20, 'Environment and wayfinding guidance', 'Recommendations for signage, layout, and technology placement to align the physical environment with the redesigned service journeys.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (20, 'Do you design for a single location type or the whole network?', 'The design is built for your standard location model and adapted for variations (high-volume vs. smaller format, for example). Network rollout planning is included.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (20, 'How do you involve frontline staff in the design?', 'Structured interviews and co-design workshops with frontline teams are built into the engagement so the resulting SOPs reflect operational reality.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (20, 'Can the design accommodate different location formats across our estate?', 'Yes. The DigitalQatalyst team identifies the core journey standard and documents format-specific variations where needed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (20, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your existing location formats and agree the design scope and pilot approach.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (21, 'Physical channel AI opportunity register', 'Ranked AI use cases for your location network, each scored on operational impact, hardware feasibility, and privacy considerations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (21, 'Edge AI deployment assessment', 'Analysis of on-premise versus cloud AI options for locations with constrained connectivity, including hardware requirements.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (21, 'Responsible AI design for physical contexts', 'Consent mechanisms, data handling procedures, and bias mitigation requirements for camera-based or biometric AI systems.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (21, 'Physical channel AI build specification', 'Integration contracts, hardware specifications, and data flows connecting AI tools to your existing branch and retail systems.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (21, 'Can AI tools work in locations with poor internet connectivity?', 'Edge AI deployment is assessed as part of this engagement. Many queue management and decision support tools can operate on-premise with periodic cloud sync.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (21, 'What regulations apply to AI in physical retail or branch environments?', 'Camera-based and biometric AI systems are subject to specific regional regulations. The design engagement includes a regulatory landscape review for your operating regions.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (21, 'How do you get staff buy-in for AI tools in a physical environment?', 'Staff impact and change management are considered in the workflow design. The DigitalQatalyst team can include a change readiness assessment as part of the engagement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (21, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm your location types, existing technology, and regulatory context before agreeing the design scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (22, 'Deployed physical channel improvements', 'Technology configured, processes implemented, and staff trained across all agreed locations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (22, 'Pilot performance report', 'Measurement results from the pilot location including customer experience metrics, staff adoption rates, and identified adjustments applied to the network rollout.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (22, 'Staff training materials', 'Role-specific training guides, quick reference cards, and e-learning content for ongoing staff onboarding.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (22, 'Operations handover pack', 'System documentation, maintenance procedures, escalation paths, and SLA terms for each deployed capability.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (22, 'How is the rollout sequenced across a large location network?', 'The DigitalQatalyst team designs a location tiering approach based on volume, geography, and complexity. The rollout sequence is agreed with your operations team before deployment begins.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (22, 'What happens if a location has specific technical constraints?', 'Location-specific constraints are assessed during the pilot phase. Configuration variations are documented before the network rollout begins.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (22, 'How is staff training managed across multiple shifts and locations?', 'Training is delivered in-location by DigitalQatalyst team trainers, with self-service guides and refresher materials for staff who join after go-live.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (22, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the location scope, existing technology, and rollout timeline.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (23, 'Deployed physical channel AI tools', 'AI hardware and software live at all agreed locations, integrated with branch systems and confirmed against acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (23, 'Physical AI monitoring dashboard', 'Centralised view of AI tool performance, hardware health, and safety alerts across all locations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (23, 'Frontline staff training and reference materials', 'In-location training sessions and quick reference guides for every AI tool deployed, covering normal operation and escalation procedures.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (23, 'Physical AI operations guide', 'Maintenance schedules, incident response procedures, and escalation contacts for each deployed AI capability.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (23, 'Do you manage hardware procurement as part of this service?', 'Hardware specification and sourcing support are included. The DigitalQatalyst team can manage procurement or work alongside your existing vendor relationships.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (23, 'How do you handle locations where AI hardware fails?', 'The operations guide includes hardware fault escalation procedures and fallback processes so service continues without the AI tool until repair or replacement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (23, 'How do customers at each location know AI is being used?', 'Consent and disclosure requirements are implemented at each location in line with the responsible AI design specification. Signage, screen notices, and staff scripts are all included.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (23, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the AI design specification and confirm the hardware and infrastructure requirements.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (24, 'Monthly operations report', 'Technology uptime, incident log, maintenance activity, and customer flow metrics across all managed locations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (24, 'SLA compliance record', 'Tracked resolution times for every incident against agreed SLA tiers, with root cause notes for recurring issues.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (24, 'Quarterly experience review', 'Physical channel performance against goals, with customer feedback synthesis and prioritised improvement recommendations.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (24, 'Technology lifecycle report', 'Annual review of hardware age, software version currency, and replacement or upgrade recommendations for each location.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (24, 'Do you manage technology at every location or just a subset?', 'The managed service can cover your full network or a defined subset. Location scope is agreed during onboarding and can be expanded as your network grows.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (24, 'How are hardware faults handled when they need on-site attendance?', 'The DigitalQatalyst team coordinates with your facilities teams and approved vendors for on-site faults. Remote resolution is attempted first to minimise wait times.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (24, 'What is the escalation path during a major incident affecting multiple locations?', 'A major incident protocol is agreed during onboarding. The DigitalQatalyst team activates the protocol and provides hourly updates until resolution.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (24, 'Can the managed service cover newly opened locations?', 'Yes. New location onboarding is part of the managed service. The DigitalQatalyst team adds locations to monitoring as they open.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (24, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your location network, existing technology, and agree the SLA terms.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (25, 'Cross-channel experience audit', 'End-to-end journey findings across all in-scope channels, with each handoff point rated for continuity, effort, and customer satisfaction impact.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (25, 'Channel handoff analysis', 'Specific gaps where customer context is lost or repeated at channel transitions, with root cause and recommended fixes.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (25, 'Employee experience snapshot', 'Frontline tool and process gaps identified through staff interviews, rated by impact on service quality.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (25, 'Integrated experience roadmap', 'Prioritised recommendations spanning all channels, with expected cross-channel impact, effort estimates, and sequencing rationale.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (25, 'How many channels do you cover in the audit?', 'The scope is agreed during the initial consultation based on your active channels. A typical integrated assessment covers web, mobile, social, and at least one physical touchpoint.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (25, 'Do you assess B2B and B2C journeys in the same engagement?', 'Yes, if both are in scope. The DigitalQatalyst team maps journeys separately by customer type and identifies shared platform or process dependencies.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (25, 'What if we do not have data on cross-channel journeys?', 'Direct observation, customer interviews, and mystery shopping are used alongside analytics. Good findings are possible even without mature cross-channel tracking.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (25, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the channel scope, data access requirements, and stakeholder involvement before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (26, 'Unified customer journey maps', 'End-to-end journey designs spanning every in-scope channel, with detailed channel handoff specifications and no identified gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (26, 'Experience data architecture', 'Data model and flow design showing how customer context, preferences, and history are shared across channels and systems.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (26, 'Personalisation framework', 'Segmentation approach, trigger logic, and content strategy for delivering relevant experiences across touchpoints.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (26, 'Experience adoption plan', 'Rollout sequencing, change management steps, and training approach for CX, technology, and frontline teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (26, 'Does this design work if we have different technology platforms per channel?', 'Yes. The experience data architecture is designed to work across your existing platform mix. Integration requirements are documented for each channel''s technology.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (26, 'How detailed is the personalisation framework?', 'The framework covers segmentation criteria, trigger events, content slot definitions, and a testing approach. It is specification-level, ready for your technology team to implement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (26, 'Can the design cover employee-facing tools as well as customer journeys?', 'Yes. Employee journey design and frontline tool requirements are included in the integrated experience design by default.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (26, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your channel landscape and agree the design scope and channel coverage.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (27, 'Integrated experience AI opportunity register', 'Ranked AI use cases for your cross-channel environment, each scored on personalisation impact, data readiness, and implementation complexity.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (27, 'Data readiness assessment', 'Review of your customer data estate confirming which AI use cases are feasible today and what data gaps need addressing first.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (27, 'Responsible AI personalisation design', 'Consent mechanisms, explainability requirements, bias testing criteria, and data retention rules for customer-facing AI features.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (27, 'Cross-channel AI integration specification', 'API contracts and data flow design showing how AI model outputs reach the right channel at the right moment in the customer journey.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (27, 'What if our customer data is fragmented across multiple systems?', 'The data readiness assessment identifies fragmentation and prioritises the data consolidation needed before each AI use case. Not all use cases require a full data platform.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (27, 'How do you ensure personalisation AI respects customer privacy preferences?', 'Every personalisation workflow design includes consent integration, preference management, and data minimisation requirements aligned to your regulatory context.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (27, 'Can AI orchestrate the customer journey across channels in real time?', 'Real-time journey orchestration is assessed as a use case. Feasibility depends on your existing data infrastructure, which the assessment confirms.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (27, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your current AI maturity and agree the design scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (28, 'Integrated experience platform', 'All channels connected and integrated, with data flowing between systems and the unified customer view live and tested.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (28, 'QA and integration test report', 'Documented test results covering all cross-channel integration paths, data accuracy, and journey orchestration logic.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (28, 'Personalisation and orchestration configuration', 'All segments, triggers, and content rules configured and tested in the journey orchestration tool, with documented logic for each.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (28, 'Operations handover pack', 'Platform architecture documentation, data management procedures, and team training materials for CX, technology, and operations staff.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (28, 'How do you manage the complexity of integrating multiple channel platforms?', 'Integration is managed against a documented specification with each connection tested individually then end-to-end. A phased go-live reduces risk for complex multi-system environments.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (28, 'What if one of our channel platforms does not support the required integration?', 'Integration feasibility is confirmed during the design phase. Where platform limitations exist, the DigitalQatalyst team designs the best available workaround.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (28, 'How long does the team training take?', 'Training is scheduled across the final three weeks of deployment and tailored by role. Self-service guides cover every platform for ongoing reference.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (28, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the experience design specification and agree the deployment scope and timeline.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (29, 'Deployed AI experience capabilities', 'Personalisation, orchestration, and next-best-action AI live across all agreed channels, integrated with your customer data platform and CRM.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (29, 'AI monitoring and performance dashboard', 'Real-time view of model accuracy, recommendation click-through, segment coverage, and safety control activity across channels.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (29, 'AI safety and consent configuration', 'Consent integration, bias monitoring rules, and output audit logging configured and verified before full production release.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (29, 'CX AI operations guide', 'Procedures for managing segment updates, reviewing AI recommendation performance, overriding outputs, and responding to AI incidents.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (29, 'How do you prevent AI personalisation from feeling intrusive to customers?', 'Personalisation rules and content logic are calibrated during testing to ensure relevance without overreach. Customers can also manage their preferences through the consent controls.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (29, 'What happens when an AI recommendation is wrong?', 'CX teams are trained to review and override AI recommendations. The monitoring dashboard flags low-performing recommendations automatically so corrections can be made quickly.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (29, 'How does the orchestration AI handle customers who move between channels?', 'Journey orchestration uses the unified customer profile to maintain context across channel switches. The handoff logic is tested end-to-end before full release.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (29, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the AI design specification and confirm the deployment infrastructure and integration requirements.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (30, 'Monthly cross-channel performance report', 'Customer satisfaction, journey completion, channel adoption, and personalisation effectiveness across all managed channels.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (30, 'Monthly AI governance report', 'Personalisation accuracy, segment coverage, bias monitoring outcomes, and model performance trends with recommended adjustments.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (30, 'Content and segment management log', 'Record of all segment and content updates made during the month, with rationale and measured impact.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (30, 'Quarterly integrated experience review', 'Strategic assessment of cross-channel experience against business goals, with a prioritised improvement plan for the next quarter.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (30, 'Does the managed service cover both the technology and the experience strategy?', 'Yes. The DigitalQatalyst team manages technology performance and governance while the quarterly review covers experience strategy and improvement prioritisation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (30, 'How are AI models updated if personalisation accuracy degrades?', 'The monthly AI governance review identifies accuracy degradation. The DigitalQatalyst team recommends and implements model updates or retraining within the managed service.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (30, 'What if we want to add a new channel to the managed service?', 'New channels are onboarded through a scoped addition to the managed service. The DigitalQatalyst team confirms integration requirements and extends monitoring before the channel goes live.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (30, 'How is the cross-channel data kept accurate and current?', 'Data pipeline health is monitored continuously. The DigitalQatalyst team alerts your team to any pipeline issues and resolves them within agreed SLA timeframes.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (30, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your channel estate, existing platform access, and agree the SLA and governance terms before onboarding.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (31, 'CRM maturity scorecard', 'Ratings across data quality, adoption, pipeline hygiene, and integration coverage, with specific evidence for each score.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (31, 'Gap and root-cause register', 'Every identified gap linked to its business impact, so investment decisions are grounded in actual revenue and retention risk.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (31, 'Prioritised CRM improvement roadmap', 'Sequenced actions ranked by impact and effort, with suggested owners and logical dependencies your teams can execute.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (31, 'Executive summary', 'A concise brief for your leadership team covering findings, priorities, and the investment case for the next phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (31, 'What CRM platforms do you assess?', 'The DigitalQatalyst team works across Salesforce, HubSpot, Microsoft Dynamics, and other major CRM platforms. We confirm platform scope during the initial consultation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (31, 'What access do you need from us?', 'Primarily read-only access to CRM reports and configuration, plus 3-4 hours of stakeholder time across sales, marketing, and service leads. No write access is required.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (31, 'Will the roadmap tell us how much change will cost?', 'The roadmap includes effort estimates and sequencing. Detailed cost modelling comes in the Design or Deploy phase once scope is confirmed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (31, 'Is this assessment suitable if we are mid-implementation?', 'Yes. A mid-implementation assessment often catches misalignments before they become expensive to fix. The DigitalQatalyst team adjusts scope to focus on the most actionable findings.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (31, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm scope, stakeholders, and data access before any work begins.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (32, 'CRM workflow and journey designs', 'Role-specific journey maps and process flows for sales pipeline, account management, and customer service, validated with end users.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (32, 'Data model and field specification', 'Object structure, custom field definitions, validation rules, and data governance guidelines to ensure clean, reportable data from day one.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (32, 'Integration architecture document', 'Detailed specifications for each system integration including data flows, trigger logic, error handling, and API or middleware requirements.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (32, 'Adoption and change plan', 'Role-based training outlines, communication milestones, success metrics, and the criteria your team must meet before go-live.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (32, 'Do we need the Assess first?', 'Not necessarily. If you have clear goals and existing documentation, the Design engagement can begin with a condensed discovery phase. The DigitalQatalyst team will advise during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (32, 'Which teams need to be involved?', 'Typically sales, marketing, customer service, and IT representatives. We keep individual time commitments manageable through structured workshops rather than open-ended availability.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (32, 'Does the design cover custom development?', 'Yes, where configuration alone cannot meet a requirement, the specifications will include custom development scope so your delivery team has full clarity.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (32, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team reviews your existing documentation, confirms the CRM platform, and agrees workshop participants before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (33, 'AI use-case scorecard', 'Each candidate use case rated by business value, data availability, risk, and build feasibility, with a clear recommendation on what to pursue and in what order.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (33, 'Responsible AI workflow designs', 'Workflow diagrams showing AI decision points, human override logic, bias mitigation steps, and data handling in accordance with your privacy obligations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (33, 'Technical deployment specification', 'Model inputs, outputs, integration points, infrastructure requirements, and the acceptance criteria your team will use to validate production readiness.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (33, 'AI governance framework', 'Monitoring plan, escalation procedures, model refresh cadence, and the roles responsible for ongoing AI oversight within your CRM operations.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (33, 'Which AI capabilities are most commonly scoped for CRM?', 'Lead scoring, next-best-action recommendations, deal risk flagging, and customer churn prediction are the most frequently validated. The DigitalQatalyst team works through your specific pipeline to identify what your data actually supports.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (33, 'What data quality do we need before AI design is viable?', 'The data readiness assessment in week one determines this. Many organisations find targeted data cleaning in specific fields is sufficient; others discover the Assess or Design phases should come first.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (33, 'Does the output tell us which AI vendor or model to use?', 'Yes. The specifications include vendor and model recommendations with rationale based on your CRM platform, data volume, and budget constraints.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (33, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team reviews your CRM platform, existing data assets, and business priorities to shape the engagement scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (34, 'Configured CRM environment', 'A fully built, tested CRM instance covering all approved workflows, fields, automations, and role-based permissions, ready for user acceptance.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (34, 'Integration test results', 'Documented test evidence for every integration covering expected behaviours, edge cases, and the resolution record for any defects raised.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (34, 'User acceptance test report', 'Signed-off UAT outcomes per business scenario, showing which criteria passed, any accepted exceptions, and the agreed go-live decision.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (34, 'Operational handover pack', 'Administrator guides, escalation contacts, support procedures, and a 30-day post-launch check schedule so your team owns the platform from day one.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (34, 'Do we need a design specification before deploying?', 'Yes. The Deploy engagement builds from an agreed specification. If you do not have one, the DigitalQatalyst team can help you produce it through the Design engagement first.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (34, 'How is data migration handled?', 'Migration is scoped, mapped, and tested in a sandbox environment before production cutover. The DigitalQatalyst team runs data quality checks at each stage.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (34, 'What happens if issues arise after go-live?', 'The hypercare period provides direct access to the delivery team to resolve production issues quickly. After hypercare concludes, the Managed service can take over ongoing operations.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (34, 'How do we get started?', 'Share your approved specification or design outputs and the DigitalQatalyst team will confirm scope, resourcing, and a delivery timeline.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (35, 'Production AI deployment', 'AI capabilities fully integrated into your CRM environment, validated against the agreed performance and safety acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (35, 'Monitoring and alerting configuration', 'Dashboards and alert rules covering model accuracy drift, bias indicators, data pipeline health, and business outcome metrics.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (35, 'AI operations runbook', 'Step-by-step procedures for monitoring, incident response, model refresh, and escalation, so your team can manage the AI capability without external dependency.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (35, 'Handover and training completion record', 'Confirmed training completion for each operational role, sign-off on acceptance criteria, and a 30-day post-handover support schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (35, 'What does the safety testing cover?', 'The DigitalQatalyst team tests for model accuracy degradation, demographic bias, data pipeline failures, and downstream CRM data corruption. All tests run against your agreed acceptance thresholds.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (35, 'Can AI capabilities be deployed to a staging environment first?', 'Yes. The deployment follows a staged approach: sandbox validation, then staging with production data samples, then controlled production rollout.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (35, 'What happens if model performance drops after go-live?', 'The monitoring configuration triggers alerts at agreed thresholds. The operations runbook covers the response procedure, and the DigitalQatalyst team provides post-launch support during the handover period.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (35, 'How do we get started?', 'Provide your approved AI design specifications and the DigitalQatalyst team will confirm infrastructure requirements, deployment sequencing, and the production milestone schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (36, 'Monthly CRM performance report', 'Data quality scores, automation success rates, pipeline health metrics, and integration uptime, with commentary on trends and the next optimisation priorities.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (36, 'Optimisation change log', 'A record of every configuration change made, the business rationale, the test evidence, and the observed outcome, giving you a complete audit trail.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (36, 'Release and update management record', 'Documentation of all platform updates applied, compatibility tests run, and any issues resolved before changes reached production.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (36, 'Quarterly roadmap review', 'A structured review of your CRM roadmap priorities, incorporating new business requirements, platform capability updates, and usage data from the previous quarter.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (36, 'What does the SLA cover?', 'The SLA covers system availability monitoring, incident response for platform and integration failures, change management for configuration requests, and a monthly reporting cadence. Specific response and resolution targets are finalised during onboarding to reflect your operational requirements.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (36, 'Can we request new features or changes within the managed service?', 'Yes. A defined change request allowance is included each month. Larger scope changes are assessed and quoted separately so you remain in control of spend.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (36, 'How does the managed service interact with our internal IT team?', 'We operate as an extension of your team. Escalation paths, communication channels, and responsibility boundaries are agreed during onboarding and documented in the service agreement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (36, 'How do we get started?', 'Request an onboarding call. The DigitalQatalyst team reviews your current CRM environment, agrees the service baseline, and confirms the first reporting cycle.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (37, 'Marketing operations scorecard', 'Ratings across automation reliability, data quality, segmentation accuracy, and attribution credibility, each supported by specific evidence from your current campaigns.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (37, 'Attribution and measurement gap report', 'Identifies where your current measurement model is either over-crediting or under-crediting channels, and the specific changes needed to make investment decisions more accurate.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (37, 'Audience and segmentation review', 'Assessment of how well your segments reflect buying behaviour, with concrete recommendations for better targeting that your platform can execute.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (37, 'Prioritised improvement roadmap', 'Sequenced actions covering quick wins and longer-term changes, with effort scores so your team can plan resourcing alongside business-as-usual activity.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (37, 'Which marketing platforms do you assess?', 'The DigitalQatalyst team works across HubSpot, Marketo, Salesforce Marketing Cloud, Klaviyo, and other leading platforms. We confirm scope during the initial consultation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (37, 'What data do you need from us?', 'Campaign performance reports, automation audit logs, and audience configuration exports. No personal customer data is required for the assessment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (37, 'Can this help us if we are about to re-platform?', 'Yes. A pre-migration assessment is one of the most valuable applications, as it identifies what is worth replicating and what should be redesigned before committing to a new platform.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (37, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm the scope, data requirements, and stakeholder participants before the engagement begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (38, 'Campaign architecture blueprint', 'Structured campaign templates, channel strategy, trigger logic, and content cadence designs your marketing team can immediately begin building against.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (38, 'Audience segmentation model', 'Defined segments, scoring criteria, lifecycle stages, and the personalisation rules that govern how each audience receives communications.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (38, 'Measurement and attribution framework', 'A reporting structure aligned to your business objectives, covering the metrics, dashboards, and data sources that will give leadership credible campaign performance data.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (38, 'Integration and technology specification', 'Detailed connection specifications for your marketing platform, CRM, data warehouse, and any paid channel integrations, including sync frequency and data governance rules.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (38, 'Does the design cover content strategy or creative?', 'The design covers campaign structures, audience logic, and channel orchestration. Content strategy and creative direction are separate engagements; the DigitalQatalyst team can advise on scope.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (38, 'How do you handle multi-brand or multi-market complexity?', 'Brand and market segmentation is addressed in the architecture design. We have experience designing frameworks that accommodate multiple brands or regional variations within a single platform.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (38, 'Will the design work with our existing marketing technology?', 'Yes. The design starts from your current stack. Where platform limitations exist, the specifications will flag them with options rather than assuming a re-platform.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (38, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team reviews your existing documentation, confirms your platform landscape, and agrees the workshop participants before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (39, 'AI use-case prioritisation scorecard', 'Each candidate marketing AI use case rated by business value, data feasibility, risk, and implementation complexity, with a clear recommendation on what to build and when.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (39, 'Responsible AI workflow designs', 'Workflow diagrams showing model inputs, decision points, human review requirements, and the privacy and consent controls needed for compliance with your data obligations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (39, 'Data readiness report', 'Assessment of your marketing data against the requirements of each validated use case, including specific data quality actions needed before build can begin.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (39, 'Technical deployment specification', 'Model inputs, outputs, integration requirements, infrastructure needs, and the acceptance criteria your delivery team will use to validate production readiness.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (39, 'Which AI use cases are most commonly validated for marketing?', 'Predictive lead scoring, send-time optimisation, dynamic content personalisation, and budget allocation modelling are the most frequently scoped. The DigitalQatalyst team validates each against your specific data assets.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (39, 'What if our data is not ready for AI?', 'The data readiness report will tell you precisely what is missing. In many cases a targeted data improvement programme takes weeks rather than months. The DigitalQatalyst team will outline the options.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (39, 'Do we need to replace our existing marketing platform?', 'Usually not. The specifications are designed to integrate AI capabilities with your existing stack using available APIs or middleware. Re-platforming is only recommended when the current system creates an architectural barrier.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (39, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team reviews your marketing platform, data landscape, and AI ambitions to shape the engagement scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (40, 'Configured marketing platform', 'Fully built automation programmes, campaign templates, audience segments, and integrations, validated in a staging environment before production promotion.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (40, 'Integration test evidence pack', 'Test scenarios and results for every system integration, covering data sync accuracy, trigger reliability, and error handling behaviour.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (40, 'User acceptance test outcomes', 'Signed-off UAT results per campaign workflow and audience scenario, including accepted exceptions and the agreed launch decision.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (40, 'Marketing operations handover pack', 'Platform administration guide, campaign build procedures, escalation contacts, and a 30-day post-launch review schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (40, 'What if we need to migrate historical campaign data?', 'Data migration scope is defined and agreed upfront. The DigitalQatalyst team runs data mapping, transformation, and validation in a sandbox before any production migration.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (40, 'Can we run campaigns during the build period?', 'Yes, where the current platform remains available. The DigitalQatalyst team will advise on cutover sequencing to minimise disruption to active campaigns.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (40, 'How long does post-go-live support last?', 'The hypercare period and its terms are confirmed during scoping. After hypercare, the Managed service can provide ongoing operational support.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (40, 'How do we get started?', 'Share your approved design specifications and the DigitalQatalyst team will confirm scope, resourcing, and a delivery timeline.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (41, 'Production AI deployment', 'AI capabilities fully integrated into your marketing platform, validated against the agreed performance, accuracy, and safety acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (41, 'Privacy and consent validation report', 'Evidence that data handling, consent enforcement, and model inputs comply with your obligations, reviewed and signed off before production launch.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (41, 'Monitoring dashboard and alert configuration', 'Real-time visibility into model accuracy, data pipeline health, campaign impact metrics, and alert rules with defined response thresholds.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (41, 'AI operations runbook and training record', 'Step-by-step procedures for daily monitoring, incident response, model refresh, and escalation, with confirmed training completion for each operational role.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (41, 'How is personal data handled during model training and inference?', 'Data handling is governed by the specifications agreed in the AI Design phase. The DigitalQatalyst team validates compliance with those specifications before any model goes to production.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (41, 'What happens if a model starts producing poor results after launch?', 'The monitoring configuration triggers alerts when accuracy drops below agreed thresholds. The operations runbook covers the response procedure, including model rollback and the escalation path to the DigitalQatalyst team during the handover period.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (41, 'Can AI capabilities be deployed incrementally rather than all at once?', 'Yes. Staged deployment is the standard approach. Use cases go live in priority order so each is validated before the next is introduced.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (41, 'How do we get started?', 'Provide your approved AI design specifications and the DigitalQatalyst team will confirm infrastructure requirements, compliance obligations, and the deployment milestone schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (42, 'Monthly marketing operations report', 'Campaign performance KPIs, automation health metrics, data quality indicators, and integration uptime, with commentary on trends and the next optimisation priorities.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (42, 'Optimisation recommendations log', 'A record of every improvement implemented, the rationale behind it, the test evidence used, and the observed outcome, giving your team a full audit trail.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (42, 'Platform release and update record', 'Documentation of all platform updates applied, compatibility tests completed, and any issues resolved before changes were promoted to production.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (42, 'Quarterly campaign performance review', 'A structured review of campaign results, audience performance, attribution accuracy, and the priorities for the next quarter, informed by data rather than assumption.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (42, 'Does the managed service include campaign strategy or creative?', 'The managed service covers platform operations and performance reporting. Campaign strategy and creative production are separate; the DigitalQatalyst team can discuss how these services can be combined.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (42, 'Can we request new automations or campaign templates within the service?', 'Yes. A defined change request allowance is included each month. Larger build requests are assessed and quoted separately.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (42, 'How do you report against our marketing KPIs?', 'Each month you receive a performance dashboard connected to your analytics stack and presenting the KPIs that matter to your leadership. Every quarter the DigitalQatalyst team runs a business review to interpret trends and agree priorities for the next period. KPI alignment is confirmed during onboarding so the first report reflects what you actually measure.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (42, 'How do we get started?', 'Request an onboarding call. The DigitalQatalyst team reviews your current platform, agrees the service baseline, and confirms the first reporting cycle.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (43, 'Sales and quotation process scorecard', 'Ratings across process adherence, quotation accuracy, approval cycle times, and pricing consistency, each supported by evidence from your actual transaction data.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (43, 'Bottleneck and root-cause register', 'Every identified delay or error linked to its impact on quote turnaround time, conversion rate, or margin, so improvement priorities are grounded in commercial evidence.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (43, 'Pricing consistency analysis', 'Assessment of where pricing rules are being applied inconsistently across products, customer types, or sales team members, with specific recommendations for control improvements.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (43, 'Prioritised improvement roadmap', 'Sequenced actions covering process, platform, and governance improvements, with effort scores so your commercial leadership can plan the next phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (43, 'What sales and CPQ platforms do you assess?', 'The DigitalQatalyst team works across Salesforce CPQ, HubSpot, SAP CPQ, and bespoke quotation systems. Platform scope is confirmed during the initial consultation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (43, 'What data do you need from us?', 'Quotation logs, approval cycle time data, win and loss records, and any existing process documentation. No personal customer data is required.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (43, 'Is this relevant if we use a manual or spreadsheet-based quotation process?', 'Yes. Manual processes are often where the most significant improvement opportunities exist. The assessment will identify which improvements require a platform and which are process or governance changes alone.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (43, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm data requirements, stakeholder participants, and the assessment scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (44, 'Sales journey and workflow designs', 'End-to-end sales process flows from lead to signed quote, covering role responsibilities, decision points, and the data required at each stage.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (44, 'Quotation and pricing logic specification', 'Detailed rules for product configuration, pricing calculations, discount authorisation, and the conditions under which quotes require approval or escalation.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (44, 'Approval workflow and governance design', 'Defined approval tiers, delegation rules, exception handling, and the audit trail requirements needed for commercial governance and compliance.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (44, 'Integration and system architecture specification', 'Data flow diagrams and API or middleware specifications connecting your CPQ platform to CRM, ERP, and downstream contract management systems.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (44, 'Can the design accommodate multiple pricing models or product families?', 'Yes. The quotation logic specification is built around your actual product and pricing complexity. Multi-tier pricing, bundles, and regional variations are all addressed during the design phase.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (44, 'How do you handle commercial sensitivity during workshops?', 'Pricing data and commercial rules are treated as confidential. The DigitalQatalyst team operates under NDAs and data handling agreements before any commercial information is shared.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (44, 'Does the design tell us which CPQ platform to use?', 'If you have not yet selected a platform, the design includes vendor assessment and a recommendation based on your requirements. If a platform is already chosen, the design works within that constraint.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (44, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team reviews your current quotation process and confirms the stakeholders needed for design workshops.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (45, 'AI use-case scorecard for sales and quotation', 'Each candidate use case rated by commercial value, data feasibility, implementation risk, and governance complexity, with a clear build recommendation and sequencing.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (45, 'Responsible AI workflow designs', 'Workflow diagrams showing AI-suggested pricing recommendations, human authority boundaries, override logic, and the audit trail requirements for commercial compliance.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (45, 'Data readiness assessment', 'Evaluation of your transaction history, product data, and win-loss records against the data requirements of each validated AI use case, with specific data improvement actions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (45, 'Technical deployment specification', 'Model input and output specifications, CPQ and CRM integration requirements, infrastructure needs, and the acceptance criteria for production validation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (45, 'Can AI actually improve pricing decisions in a complex product environment?', 'AI-assisted pricing works best where there is sufficient historical transaction data with outcome labels. The use-case scoring phase determines whether your data supports this. Simpler applications, such as configuration assistance or win-probability scoring, often have lower data requirements.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (45, 'How do you ensure AI pricing recommendations do not override commercial authority?', 'The workflow designs define explicit human authority boundaries. AI produces recommendations; approval and override controls remain with authorised roles. This is a core design requirement, not an option.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (45, 'Do we need a CPQ platform in place before this engagement?', 'Not necessarily. The AI design can be completed in parallel with CPQ selection, with specifications written to accommodate the chosen platform. The DigitalQatalyst team will advise on the optimal sequencing.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (45, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your current sales and pricing data landscape and shape the engagement scope accordingly.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (46, 'Configured CPQ environment', 'Fully built CPQ platform covering approved pricing rules, product configurations, approval workflows, and role permissions, validated in a staging environment.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (46, 'Integration test evidence', 'Test scenarios and results for every system integration, covering data synchronisation accuracy, trigger reliability, and error handling across CRM, ERP, and contract management connections.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (46, 'Quotation accuracy validation report', 'Test evidence confirming that CPQ outputs match expected pricing outcomes across representative product configurations, discounting scenarios, and approval conditions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (46, 'Sales operations handover pack', 'Administrator guides, pricing rule update procedures, escalation contacts, and a post-launch support schedule so your team owns the platform from day one.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (46, 'How is pricing rule accuracy validated?', 'The DigitalQatalyst team builds a test matrix of representative product configurations, discount scenarios, and approval conditions, then validates CPQ outputs against your expected pricing outcomes before any user acceptance testing begins.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (46, 'What if we need to migrate existing quotes or contracts?', 'Migration scope is defined and agreed upfront. Historical data migration is mapped, transformed, and validated in a sandbox environment before production cutover.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (46, 'Can we continue taking manual quotes during the build period?', 'Yes. The DigitalQatalyst team designs the cutover approach to minimise disruption to active commercial activity, including parallel-running options where needed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (46, 'How do we get started?', 'Share your approved design specifications and the DigitalQatalyst team will confirm scope, the CPQ platform configuration approach, and a delivery timeline.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (47, 'Production AI deployment for CPQ', 'AI capabilities fully integrated into your CPQ and CRM environment, validated against pricing accuracy, recommendation quality, and commercial authority acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (47, 'Commercial authority control validation report', 'Evidence that override controls, approval boundaries, and escalation paths operate correctly across representative pricing scenarios before production launch.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (47, 'AI performance monitoring dashboard', 'Real-time visibility into recommendation acceptance rates, pricing accuracy trends, model confidence scores, and the business impact metrics agreed during design.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (47, 'AI operations runbook and training record', 'Procedures for daily monitoring, model performance review, incident response, and model refresh, with confirmed training completion for sales operations and commercial roles.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (47, 'How is the commercial authority boundary enforced technically?', 'Override controls are implemented at the CPQ integration layer. AI recommendations are presented as suggestions; the CPQ workflow requires authorised human approval before any non-standard pricing is accepted. The DigitalQatalyst team validates this in staging before production deployment.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (47, 'What if the AI recommendations are wrong more often than expected?', 'The monitoring dashboard surfaces acceptance rates and accuracy metrics in near-real time. If performance falls below agreed thresholds, the operations runbook covers the investigation and response procedure, including model rollback.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (47, 'Can AI recommendations be limited to specific product lines or deal sizes initially?', 'Yes. Staged rollout by product category or deal value threshold is the standard approach, allowing the team to build confidence before broader deployment.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (47, 'How do we get started?', 'Provide your approved AI design specifications and the DigitalQatalyst team will confirm CPQ integration requirements and the production deployment schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (48, 'Monthly CPQ operations report', 'Quote volume, approval cycle times, pricing exception rates, integration uptime, and a commentary on trends and next-period maintenance priorities.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (48, 'Pricing rule and catalogue update log', 'A record of every pricing rule or product catalogue change made, the commercial rationale, the test evidence, and the observed outcome in production.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (48, 'Platform release and test record', 'Documentation of all CPQ platform updates applied, pricing accuracy tests run, and any issues resolved before changes were promoted to the live environment.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (48, 'Quarterly commercial alignment review', 'A structured review of CPQ performance against commercial objectives, incorporating new product requirements, pricing model changes, and usage data from the previous quarter.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (48, 'What happens when we add new products or change pricing?', 'Pricing rule and product catalogue updates are included within the managed service. The DigitalQatalyst team tests changes in a staging environment and validates pricing accuracy before promoting to production.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (48, 'Can the managed service cover integration maintenance if a connected system changes?', 'Yes. Integration maintenance for connected CRM, ERP, and contract systems is included within the service scope. Major re-integrations caused by third-party platform changes are assessed and agreed separately.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (48, 'How do you handle urgent pricing changes that need to go live quickly?', 'Priority change procedures with defined response times are included in the service agreement. The DigitalQatalyst team confirms the specific turnaround commitments during onboarding.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (48, 'How is our commercial and customer data kept secure?', 'Your data is processed within the cloud region agreed at contract signature. Access to your CPQ environment is role-controlled and limited to the DigitalQatalyst team members assigned to your account. On contract end, data is deleted or returned in full per the terms agreed in your service agreement.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (48, 'How do we get started?', 'Request an onboarding call. The DigitalQatalyst team reviews your CPQ environment, agrees the service baseline and pricing rule audit, and confirms the first reporting cycle.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (49, 'Support operations scorecard', 'Ratings across resolution speed, first-contact resolution, customer effort, agent productivity, and escalation control, each supported by evidence from your actual case data.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (49, 'Customer effort and friction map', 'A channel-by-channel assessment of where customers are experiencing unnecessary effort, with specific process and tooling recommendations to reduce abandonment and escalation.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (49, 'Agent productivity gap report', 'Identifies the specific tooling limitations, knowledge gaps, and process inconsistencies adding handle time and reducing agent capacity to resolve cases at first contact.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (49, 'Prioritised improvement roadmap', 'Sequenced actions ranked by impact on customer experience and operational efficiency, with effort scores so your CX and operations leadership can plan the next phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (49, 'Which support platforms do you assess?', 'The DigitalQatalyst team works across Zendesk, Salesforce Service Cloud, ServiceNow, Freshdesk, and other platforms. Scope is confirmed during the initial consultation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (49, 'Do you interview frontline agents as well as managers?', 'Yes. Agent interviews are a core part of the assessment because they surface friction points that management reporting often does not capture. We keep sessions focused and respect agent time.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (49, 'Can this assessment cover digital self-service as well as live support?', 'Yes. The assessment covers all channels in scope, including knowledge bases, chatbots, and IVR, alongside live agent channels.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (49, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm data requirements, channel scope, and stakeholder participants before the engagement begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (50, 'Customer support journey maps', 'End-to-end journey designs for each support channel, covering contact entry points, resolution paths, escalation triggers, and handoff specifications between teams and systems.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (50, 'Knowledge management architecture', 'Structure, taxonomy, ownership model, and maintenance procedures for your support knowledge base, designed to serve both agent-assisted and customer self-service channels.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (50, 'Case routing and prioritisation logic', 'Rule definitions for case assignment, priority scoring, SLA clock management, and re-routing criteria, with the data fields required to power each rule.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (50, 'Agent workspace and adoption plan', 'Agent desktop layout specifications, knowledge access workflow designs, and an adoption plan covering training outlines, change communication milestones, and go-live criteria.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (50, 'Does the design cover chatbot or AI-powered self-service?', 'The journey and channel design includes self-service touchpoints. Detailed AI self-service design is addressed in the AI Design engagement, which can run in sequence or in parallel.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (50, 'How do you handle multi-tier or multi-region support complexity?', 'Tiered support structures and regional variations are addressed in the routing logic and escalation design. The DigitalQatalyst team has experience designing frameworks that scale across multiple support levels and geographies.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (50, 'Will the design work within our existing support platform?', 'Yes. The design starts from your current platform. Where platform limitations exist, the specifications will flag them with options rather than assuming a platform change.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (50, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team reviews your current support operation and confirms the stakeholders needed for design workshops.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (51, 'AI use-case scorecard for support', 'Each candidate AI use case rated by impact on resolution time, customer effort, agent productivity, and implementation feasibility, with a clear recommendation on what to build first.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (51, 'Responsible AI workflow designs', 'Workflow diagrams showing AI decision points, human escalation triggers, transparency requirements for customer-facing AI, and the bias controls needed for equitable service.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (51, 'Data readiness report', 'Assessment of your case history, knowledge base quality, and customer data against the requirements of each validated AI use case, with specific data preparation actions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (51, 'Technical deployment specification', 'Model inputs, outputs, platform integration requirements, infrastructure needs, and the acceptance criteria for validating AI performance before production deployment.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (51, 'Which AI use cases are most commonly validated for support operations?', 'Intelligent case triage and routing, agent next-best-action suggestions, knowledge article recommendation, and automated tier-one resolution are the most frequently scoped. The DigitalQatalyst team validates each against your specific case data and platform capabilities.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (51, 'How do you ensure AI does not make customer interactions feel impersonal?', 'Transparency and escalation requirements are designed into every customer-facing AI workflow. Customers are told when they are interacting with an automated system and can reach a human agent at any point. This is a core design requirement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (51, 'What data quality does our knowledge base need to support AI?', 'The data readiness assessment evaluates knowledge base completeness, consistency, and freshness against the requirements of each use case. Many organisations find targeted knowledge improvement is needed before AI can reliably recommend articles.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (51, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team reviews your support platform, case data, and AI ambitions to shape the engagement scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (52, 'Configured support platform', 'Fully built case management environment covering routing rules, queue configurations, SLA timers, permission sets, and knowledge base integration, validated in a staging environment.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (52, 'Integration test evidence pack', 'Test scenarios and results for every system integration, covering case sync accuracy, CRM data exchange, and error handling across connected platforms.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (52, 'Agent UAT outcomes report', 'Signed-off user acceptance test results per support scenario and channel, including accepted exceptions and the agreed go-live decision from service leadership.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (52, 'Support operations handover pack', 'Administrator guides, routing rule update procedures, escalation contacts, and a 30-day post-launch review schedule so your team owns the platform from day one.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (52, 'How is the knowledge base built and validated?', 'The DigitalQatalyst team works with your subject matter experts to structure, author or migrate, and then quality-check knowledge articles before publication. Agents validate accuracy during user acceptance testing.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (52, 'Can we continue handling cases on the existing system during the build?', 'Yes. The cutover approach is designed to minimise disruption to live case volumes. Parallel-running options and off-peak cutover windows are considered during planning.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (52, 'What happens to open cases at the point of cutover?', 'Open case migration is planned, mapped, and tested before cutover. The DigitalQatalyst team produces a cutover playbook covering data migration steps, rollback triggers, and the communication plan for agents and customers.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (52, 'How do we get started?', 'Share your approved design specifications and the DigitalQatalyst team will confirm scope, platform configuration approach, and a delivery timeline.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (53, 'Production AI deployment for support', 'AI capabilities fully integrated into your support platform, validated against resolution accuracy, escalation behaviour, and the accepted performance criteria before production sign-off.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (53, 'Human escalation control validation report', 'Evidence that escalation to live agents triggers correctly across representative contact scenarios, including edge cases where AI confidence is low or customer sentiment indicates distress.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (53, 'AI performance monitoring dashboard', 'Real-time visibility into AI resolution rates, escalation volumes, customer satisfaction indicators, and model accuracy metrics, with alert rules at agreed performance thresholds.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (53, 'Service team training record and AI operations runbook', 'Confirmed training completion for agents, team leads, and platform administrators, plus step-by-step procedures for monitoring, incident response, and model refresh.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (53, 'How do you test that customers can always reach a human agent?', 'The DigitalQatalyst team runs escalation scenario tests covering low-confidence AI responses, repeated failed resolution attempts, high-sentiment distress signals, and explicit customer requests for a human. All must trigger the correct handoff before production deployment proceeds.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (53, 'How will agents know when AI has already interacted with a customer?', 'AI interaction context is surfaced in the agent workspace as part of the deployment configuration. Agents see the contact history, what the AI attempted, and why the escalation was triggered, so they do not ask customers to repeat themselves.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (53, 'What happens if the AI starts producing inaccurate resolutions?', 'The monitoring configuration triggers alerts when resolution accuracy drops below agreed thresholds. The operations runbook covers the investigation and response procedure, including model rollback and the escalation path to the DigitalQatalyst team during the handover period.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (53, 'How do we get started?', 'Provide your approved AI design specifications and the DigitalQatalyst team will confirm platform integration requirements and the production deployment schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (54, 'Monthly support operations report', 'Resolution rates, SLA compliance by tier, first-contact resolution trends, customer satisfaction scores, and commentary on the next period optimisation priorities.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (54, 'Knowledge base maintenance log', 'A record of every knowledge article created, updated, or retired, the accuracy validation method used, and the agent or self-service usage data that informed each change.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (54, 'Platform change and update record', 'Documentation of all platform updates applied, regression tests completed, and any issues resolved before changes reached the production environment.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (54, 'Quarterly service review', 'A structured assessment of support performance against your agreed KPIs, incorporating business volume changes, new product requirements, and emerging customer contact drivers.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (54, 'What does the managed service cover for knowledge maintenance?', 'The DigitalQatalyst team reviews knowledge article accuracy monthly, updates content based on case trend analysis and agent feedback, and archives or retires articles that no longer reflect current products or processes.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (54, 'Can we request new routing rules or queue changes within the service?', 'Yes. A defined change request allowance is included each month. Larger structural changes are assessed and agreed separately so you remain in control of scope and spend.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (54, 'How do you track and report customer satisfaction?', 'The DigitalQatalyst team integrates with your existing CSAT or NPS tooling. Where no measurement is in place, we can recommend a lightweight approach to capture and report customer feedback within the managed service.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (54, 'How do we get started?', 'Request an onboarding call. The DigitalQatalyst team reviews your current support environment, agrees the service baseline and SLA framework, and confirms the first reporting cycle.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (55, 'Digital Workplace Maturity Assessment', 'Scored evaluation across collaboration, communication, knowledge management, and adoption dimensions with evidence from interviews and usage data.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (55, 'Gap and Friction Register', 'Documented pain points tied to specific tools and workflows, ranked by frequency and business impact.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (55, 'Prioritised Improvement Roadmap', 'Sequenced recommendations with effort estimates, dependencies, and ownership suggestions your IT and HR teams can execute against.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (55, 'Executive Summary', 'A concise read for senior stakeholders covering maturity position, top risks, and recommended first investments.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (55, 'Which platforms does the assessment cover?', 'Microsoft 365, Teams, SharePoint, and connected productivity tools are the primary focus. The DigitalQatalyst team confirms scope during the initial briefing.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (55, 'Do you need access to our Microsoft tenant?', 'Read-only access to usage analytics is helpful but not required. The assessment can run on interview data, screenshots, and documentation alone.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (55, 'Who should be involved from our side?', 'An IT or M365 lead, an HR or Internal Comms representative, and a handful of end users across different functions give us the breadth we need.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (55, 'What do we get at the end of the week?', 'A maturity scorecard, a gap register, a prioritised roadmap, and an executive summary, all walked through in a findings session.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (55, 'How do we get started?', 'Book a brief scoping call. The DigitalQatalyst team will confirm participants, access needs, and the week''s schedule before work begins.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (56, 'User Journey Maps', 'Step-by-step flows for the tasks employees perform most, showing where today''s tools create friction and where the redesign removes it.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (56, 'Information Architecture and Wireframes', 'Site structure, navigation taxonomy, and annotated wireframes for intranet pages and team spaces ready for a SharePoint developer to build against.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (56, 'Microsoft 365 Configuration Specification', 'Detailed settings, permissions, and integration requirements across Teams, SharePoint, and connected apps, formatted for the delivery team.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (56, 'Adoption and Launch Plan', 'A champions programme outline, training schedule, and communication templates to ensure employees actually shift to the new ways of working.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (56, 'What design tools do you produce artefacts in?', 'Wireframes are delivered in Figma by default. The DigitalQatalyst team can adapt to your preferred tooling if agreed at the start.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (56, 'Do we need to have completed an assessment first?', 'An assessment or equivalent discovery findings are helpful, but the design engagement includes its own discovery workshops so you can start here if your requirements are already clear.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (56, 'Can this cover a full intranet rebuild or just improvements?', 'Both. The scope is confirmed in week one and can range from targeted improvements to a full SharePoint intranet architecture.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (56, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm scope, stakeholder availability, and the week-one workshop schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (57, 'AI Use-Case Shortlist and Scoring Matrix', 'Validated workplace AI scenarios ranked by employee impact, data readiness, and risk level, with a recommended build sequence.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (57, 'Copilot Readiness Report', 'Assessment of your Microsoft 365 data governance, sensitivity labelling, and licence position against the requirements for a safe Copilot deployment.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (57, 'Responsible AI Workflow Specifications', 'Detailed workflow designs for the prioritised use cases, including human review points, override mechanisms, and audit trail requirements.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (57, 'Build and Rollout Plan', 'Phased deployment sequence with dependency mapping, pilot cohort definition, and success metrics for each AI capability.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (57, 'Does this only cover Microsoft Copilot?', 'Copilot for Microsoft 365 is the primary focus, but the DigitalQatalyst team can evaluate other AI tooling such as Viva Insights or third-party assistants within the same engagement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (57, 'What data governance work is needed before AI can go live?', 'That depends on your current labelling and access-control maturity. The Copilot readiness report identifies exactly what needs to be in place and in what order.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (57, 'Can we proceed straight to AI Deploy without a prior design engagement?', 'Only if you already have validated use cases and governance specifications. If not, this design engagement prevents costly rework during build.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (57, 'How do we get started?', 'Reach out to the DigitalQatalyst team. They will confirm your Microsoft 365 licence position, data landscape, and the workshop schedule before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (58, 'Configured SharePoint Intranet', 'A built and content-populated intranet matching the approved architecture, with templates, permissions, and search configured for your organisation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (58, 'Teams Governance Ruleset', 'Enforced naming conventions, provisioning policies, guest-access rules, and lifecycle settings keeping your Teams environment manageable at scale.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (58, 'Integration Build and Test Evidence', 'Documented and tested connections to HRIS, ITSM, and other agreed systems, with test scripts and sign-off records.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (58, 'Adoption Programme Outcomes Report', '30-day usage data, champion engagement summary, and recommended actions for sustaining adoption after handover.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (58, 'What Microsoft 365 licence do we need?', 'Business Premium or E3 covers the core scope. The DigitalQatalyst team confirms exact licence requirements during the kickoff sprint.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (58, 'Can you migrate content from our old intranet?', 'Yes. Content migration is scoped during weeks one to two. Volume, format, and metadata complexity determine the effort estimate.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (58, 'What if our employees do not adopt the new tools?', 'The adoption programme is built into the engagement, not bolted on. Champions are trained, communications are scheduled, and usage is tracked so issues surface early.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (58, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved design specification or existing requirements. They will confirm the sprint plan and environment access needed to begin.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (59, 'Copilot Deployment with Governance Controls', 'Microsoft 365 Copilot live for your user base with sensitivity labels enforced, usage policies published, and employee guidance distributed.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (59, 'AI Search and Knowledge Configuration', 'Microsoft Search or equivalent tuned to surface relevant, permission-correct results from SharePoint, Teams, and connected repositories.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (59, 'Automated Workflow Builds', 'Power Automate flows handling agreed employee request scenarios, tested and handed over with documentation for your support team.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (59, 'AI Monitoring Dashboard', 'A live view of Copilot usage, prompt patterns, and adoption by department so your IT team can optimise and govern AI use on an ongoing basis.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (59, 'What Microsoft licences are required for Copilot?', 'Microsoft 365 Copilot requires an E3 or E5 base licence plus the Copilot add-on. The DigitalQatalyst team confirms your exact licence position at kickoff.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (59, 'How do you prevent Copilot surfacing data employees should not see?', 'Sensitivity labels and permissions are audited and corrected before Copilot is enabled. The readiness checklist from the AI design phase drives this work.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (59, 'What happens if employees misuse AI tools?', 'Usage policies, monitoring alerts, and manager-visible reporting are all configured. The DigitalQatalyst team trains your IT team to act on the signals.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (59, 'How do we get started?', 'Share your AI design specification and current licence position with the DigitalQatalyst team. They will confirm the pilot cohort, governance prerequisites, and kickoff schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (60, 'Monthly Health and Adoption Report', 'Usage metrics, configuration status, and adoption trends across Teams, SharePoint, and connected apps, with recommended actions for the following month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (60, 'Configuration Change Log', 'Documented record of every setting change, policy update, and integration modification applied during the month, with rationale and sign-off.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (60, 'Feature Update Briefings', 'Monthly summary of incoming Microsoft 365 feature releases assessed for relevance and readiness, with a recommended rollout plan for your organisation.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (60, 'Quarterly Roadmap Review', 'A structured session with the DigitalQatalyst team to reassess priorities, adjust the backlog, and confirm the next quarter''s improvement focus.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (60, 'What does the managed service cover that our IT team does not already do?', 'Proactive configuration drift detection, adoption analytics interpretation, and Microsoft feature-update planning are typically the gaps. The DigitalQatalyst team handles these so your IT team can focus on internal requests.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (60, 'Can we add new capabilities under the managed service?', 'Minor enhancements are included. Larger additions are scoped as separate engagements. The monthly review session is the right place to flag new requirements.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (60, 'What are the SLA response times?', 'Response times are agreed at onboarding. The standard plan covers critical issues within four business hours and standard changes within five business days.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (60, 'How do we get started?', 'Contact the DigitalQatalyst team. They will complete a baseline health audit of your Microsoft 365 environment before the first SLA period begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (61, 'Process Inventory and Scoring Matrix', 'Every in-scope process documented and rated for automation potential, with volume, error rate, and complexity noted for each.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (61, 'Tool Fit Analysis', 'Assessment of which automation approach, RPA, low-code workflow, or API integration, suits each candidate given your existing platforms and IT constraints.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (61, 'Prioritised Automation Roadmap', 'Sequenced list of automation candidates with estimated effort, expected hours saved per month, and recommended tooling for each initiative.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (61, 'Business Case Summary', 'A concise document for COO and finance stakeholders covering total addressable saving and recommended first investment.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (61, 'Which processes are in scope?', 'Scope is agreed at the start of the week. Most assessments cover operations, finance approvals, HR onboarding, and IT service requests. Additional areas can be included.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (61, 'Do we need to have a specific automation tool already chosen?', 'No. The assessment is tool-neutral and will recommend the right approach, whether that is Power Automate, UiPath, Zapier, or custom API integration, based on your existing stack.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (61, 'What if we already know which processes we want to automate?', 'The DigitalQatalyst team will validate those candidates and assess them alongside others you may not have considered, ensuring the roadmap reflects the full opportunity.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (61, 'How do we get started?', 'Book a scoping call with the DigitalQatalyst team. They will confirm which departments to include and what documentation to prepare before day one.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (62, 'As-Is and To-Be Process Maps', 'Detailed flow diagrams for each automation candidate showing current manual steps and the redesigned automated flow, including all exception and escalation paths.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (62, 'Automation Configuration Specifications', 'Step-by-step build instructions for your chosen platform, covering triggers, actions, field mappings, conditions, and error-handling logic.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (62, 'Integration Architecture Document', 'API connection designs, data transformation rules, and authentication approaches for each system the automation touches.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (62, 'Test Plan and Acceptance Criteria', 'A ready-to-execute test script covering happy paths, edge cases, and failure scenarios with pass/fail criteria for each.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (62, 'How many automation workflows does the design engagement cover?', 'Typically three to five workflows depending on complexity. The DigitalQatalyst team confirms scope based on your prioritised roadmap during week one.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (62, 'Can you design for any automation platform?', 'Yes. The DigitalQatalyst team designs to your chosen platform, whether Power Automate, UiPath, Automation Anywhere, Make, or another tool.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (62, 'Do we need development resources available during the design phase?', 'A technical contact who understands your systems and APIs is helpful in weeks two and three to validate integration assumptions.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (62, 'How do we get started?', 'Share your prioritised automation roadmap or assessment output with the DigitalQatalyst team and confirm which platform you are building on.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (63, 'AI Use-Case Feasibility Report', 'Scored assessment of each AI candidate covering data readiness, model options, implementation complexity, and responsible AI considerations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (63, 'Intelligent Document Processing Specification', 'Design for AI-powered extraction and classification of unstructured documents, including field mapping, confidence scoring, and exception routing.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (63, 'AI Workflow Designs', 'Detailed workflow specifications for each prioritised use case, showing where AI decisions are made, where humans review, and where the audit trail is recorded.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (63, 'Governance and Model Management Plan', 'Confidence thresholds, human-in-the-loop rules, monitoring metrics, and retraining triggers for each AI model deployed in a process.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (63, 'What kinds of processes benefit most from AI rather than standard automation?', 'Processes involving unstructured data, variable inputs, or judgement-based decisions: invoice processing, contract review, complaint classification, and demand forecasting are common examples.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (63, 'Do we need to have our own AI models or data science team?', 'No. The DigitalQatalyst team designs for pre-built AI services, such as Azure AI Document Intelligence or AWS Textract, so you do not need in-house model training capability.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (63, 'How do you handle cases where the AI makes the wrong decision?', 'Confidence thresholds and human-review triggers are designed in from the start. Every AI decision that falls below the threshold routes to a human before any action is taken.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (63, 'How do we get started?', 'Bring your existing automation roadmap and the DigitalQatalyst team will identify which processes are candidates for AI extension. A brief scoping call is the first step.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (64, 'Built and Tested Automation Workflows', 'Live automations running in your production environment, tested against the agreed acceptance criteria and signed off by business stakeholders.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (64, 'API Integration Connections', 'Functioning and documented connections between your automation platform and the source systems each workflow depends on.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (64, 'Test Evidence Pack', 'Executed test scripts, defect log, and sign-off records covering all tested scenarios for audit and governance purposes.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (64, 'Operations Runbook and Training', 'Step-by-step runbooks for each automation, monitoring alert setup, and hands-on training for the team responsible for day-to-day oversight.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (64, 'How many workflows can be built in twelve weeks?', 'Typically five to ten workflows depending on complexity. The sprint plan confirms scope in week one based on the approved design specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (64, 'What if we discover a workflow is more complex than the design assumed?', 'Scope changes are assessed in the affected sprint. The DigitalQatalyst team will present options: simplify the design, adjust other scope, or extend with a change request.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (64, 'Do we need dedicated technical resources from our side?', 'A system access contact and a business owner for each workflow are required. Dedicated developer time from your side is helpful but not essential.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (64, 'How do we get started?', 'Provide your approved design specifications and the DigitalQatalyst team will confirm environment access, tooling licences, and the sprint-one schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (65, 'Deployed Intelligent Document Processing', 'AI document extraction and classification running in production with agreed field accuracy rates, confidence thresholds, and human-review queue configured.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (65, 'AI Decision-Routing Integration', 'AI-powered routing logic embedded in your workflow orchestration, with audit logs recording every decision and its confidence score.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (65, 'Monitoring and Alerting Configuration', 'Live dashboards and alert rules covering model accuracy, throughput, exception rates, and human-review queue depth for your operations team.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (65, 'Pilot Outcome Report', 'Accuracy benchmarks, exception rates, and throughput data from the pilot period, with recommendations for threshold adjustments before full production scale.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (65, 'What accuracy rates can we expect from intelligent document processing?', 'Accuracy depends on document quality and variability. The DigitalQatalyst team sets baseline targets during the pilot and tunes extraction rules before full rollout.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (65, 'What happens when an AI decision is wrong?', 'Every decision below the confidence threshold routes to a human reviewer before any downstream action is taken. The audit log records the AI output and the human decision.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (65, 'Can we use our existing document processing tool, or do we need a new one?', 'The DigitalQatalyst team will assess your existing tooling. If it meets the requirements, the engagement extends its capability rather than replacing it.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (65, 'How do we get started?', 'Share your AI workflow design specifications and the DigitalQatalyst team will confirm the pilot cohort, governance prerequisites, and environment access needed to begin.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (66, 'Monthly Automation Performance Report', 'Hours saved, exception rates, queue health, and SLA adherence for every automation in the managed estate, with a recommended actions list.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (66, 'Exception and Incident Log', 'Documented record of every automation failure, root cause, resolution action, and recurrence prevention measure taken during the month.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (66, 'Change Impact Assessments', 'Assessment of how upcoming system changes, such as ERP upgrades or API version changes, affect your automations, with remediation plans and effort estimates.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (66, 'Quarterly Optimisation Review', 'Structured session with the DigitalQatalyst team to review performance trends, retire underperforming bots, and prioritise new automation candidates.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (66, 'What is included in exception queue management?', 'The DigitalQatalyst team performs first-line triage on failed automation runs: diagnosing the cause, applying fixes where possible, and escalating to your team with a documented root cause when a code change is needed.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (66, 'How do you handle changes to the systems our automations connect to?', 'The DigitalQatalyst team monitors announced changes from your ERP, CRM, and other connected platforms and produces an impact assessment before each change lands.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (66, 'Can we add new automations under the managed service?', 'Minor enhancements and small new workflows are included within capacity. Larger additions are scoped as separate engagements and flagged in the quarterly review.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (66, 'How do we get started?', 'Contact the DigitalQatalyst team with an inventory of your current automation estate. They will complete a health baseline before the first SLA period begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (73, 'Operational Function Assessment Report', 'Documented review of your specialist function covering workflow maturity, tooling fit, bottleneck locations, and the specific gaps limiting throughput and control.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (73, 'Bottleneck and Tech Debt Register', 'Every identified constraint and workaround scored by operational impact and remediation effort, with risk flags for gaps carrying compliance or safety implications.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (73, 'Prioritised Improvement Roadmap', 'Sequenced recommendations with effort estimates, dependency mapping, and ownership suggestions your operational and IT leads can plan against immediately.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (73, 'Executive Briefing', 'A concise summary of findings, risk exposures, and recommended first investments formatted for your business unit and technology leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (73, 'What kinds of specialist operations does this cover?', 'Field service management, asset and facilities operations, quality management, supply chain execution, and other domain-specific functions. The DigitalQatalyst team confirms fit during the scoping call.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (73, 'Can you assess a function that uses a niche or legacy system we built internally?', 'Yes. The assessment is focused on the operational function, not just commercial platforms. Custom and legacy systems are reviewed as part of the tooling analysis.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (73, 'Who from our organisation needs to be available?', 'The operational function lead, two to three front-line staff, and the system owner for the primary operational platform are the minimum. Additional stakeholders can be included if scope warrants it.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (73, 'How do we get started?', 'Book a scoping call with the DigitalQatalyst team to confirm the operational function in scope, the stakeholders to involve, and any documentation to prepare in advance.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (74, 'Redesigned Process Maps', 'To-be workflow diagrams for each priority area, showing role, system, data, and decision at every step, with exceptions and escalations mapped and ready for build.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (74, 'System Configuration Specification', 'Detailed build instructions for your operational platform covering objects, fields, screens, rules, and automation triggers, formatted for your delivery team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (74, 'Integration Architecture Document', 'API contracts, data transformation rules, and connection design for each integration between your operational system and the platforms it depends on.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (74, 'Adoption and Change Plan', 'Training outline, communication timeline, and cut-over guidance for the operational staff and managers affected by the redesigned workflows.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (74, 'Can this cover a purpose-built or niche operational platform?', 'Yes. The DigitalQatalyst team designs to the platform your function uses, whether a leading field service tool, a bespoke case management system, or a sector-specific application.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (74, 'How do you capture what operational staff actually need versus what management thinks they need?', 'Week one includes structured sessions with front-line operational staff. Their task walkthroughs and friction points directly shape the to-be design.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (74, 'Do we need an existing system in place, or can this design a new one?', 'Both. The design engagement can specify a new operational platform or redesign the workflows in an existing one.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (74, 'How do we get started?', 'Contact the DigitalQatalyst team with details of your operational function and the platform in scope. They will confirm the week-one workshop schedule and participants.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (75, 'AI Use-Case Feasibility Assessment', 'Scored evaluation of each candidate AI use case covering data availability, model suitability, operational risk, and responsible AI considerations specific to your domain.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (75, 'Domain-Specific AI Workflow Designs', 'Detailed workflow specifications for prioritised use cases showing where AI acts, where humans review, and where the decision record is kept.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (75, 'Data Readiness Report', 'Assessment of whether your operational data, in terms of volume, quality, and labelling, supports the identified AI models, with remediation steps where gaps exist.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (75, 'Governance and Monitoring Specification', 'Confidence thresholds, override controls, audit logging requirements, and model performance metrics for each AI capability to be deployed.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (75, 'What types of AI are most relevant to specialist operations?', 'Predictive maintenance, intelligent scheduling, anomaly and quality defect detection, and AI-assisted case triage tend to offer the highest returns in domain-specific operations. The DigitalQatalyst team validates which apply to your function.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (75, 'What if our operational data is not clean enough for AI?', 'The data readiness report identifies exactly what needs to improve and in what order. Some use cases can proceed with targeted data remediation; others may need to wait.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (75, 'Are there safety or regulatory considerations for AI in our operational function?', 'Domain-specific risk is assessed in week two. Where regulatory or safety considerations apply, the DigitalQatalyst team incorporates them into the responsible AI framework for each use case.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (75, 'How do we get started?', 'Contact the DigitalQatalyst team with details of your operational function and the processes you think could benefit from AI. They will confirm scope and the week-one workshop schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (76, 'Configured Operational Platform', 'Your specialist operational system live in production, configured to the approved specification and signed off by operational stakeholders.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (76, 'Integration Connections', 'Tested and documented connections between your operational platform and ERP, scheduling, reporting, and other agreed systems.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (76, 'User Acceptance Test Evidence', 'Executed test scripts covering role-specific operational scenarios, with defect log and sign-off records for audit and governance.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (76, 'Administrator Runbooks and Training', 'Step-by-step operational guides, configuration documentation, and hands-on training for the team responsible for maintaining the system.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (76, 'Can you configure a niche or sector-specific operational platform?', 'Yes, provided the DigitalQatalyst team has the relevant platform expertise or you can provide a certified implementation partner to collaborate with. Scope is confirmed at kickoff.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (76, 'What happens if operational staff reject the new system during testing?', 'User acceptance testing in weeks nine and ten is designed to surface usability issues before go-live. Findings are addressed in the same testing window to protect the launch date.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (76, 'Do we need to migrate historical data?', 'Data migration scope is confirmed in weeks one to two. Volume, quality, and format complexity determine effort. Not all deployments require historical data migration.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (76, 'How do we get started?', 'Provide your approved design specification and the DigitalQatalyst team will confirm environment access, data migration scope, and the sprint-one schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (77, 'Deployed AI Models in Operational Workflows', 'Validated AI capabilities running in your operational platform, integrated into the workflows your staff use, with agreed accuracy benchmarks met before full rollout.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (77, 'Governance and Override Configuration', 'Confidence thresholds, human-review queues, and audit logging active for every AI decision that affects an operational outcome.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (77, 'Pilot Accuracy and Performance Report', 'Precision, recall, and throughput data from the pilot period with analysis of exception patterns and threshold recommendations for production.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (77, 'Staff Enablement Materials', 'Role-specific guidance on how to interpret AI recommendations, when to act on them, and how to escalate concerns through the override process.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (77, 'How do you validate that AI predictions are accurate enough for our operational context?', 'The pilot phase runs the model against real operational scenarios with monitoring against agreed accuracy thresholds. The DigitalQatalyst team does not move to full production until those thresholds are met.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (77, 'What if operational staff do not trust the AI recommendations?', 'The staff enablement programme explains how the model works and when its recommendations are reliable. Override controls are always available so staff remain in control.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (77, 'Can the AI models be retrained if operational conditions change?', 'Yes. The monitoring configuration includes triggers for retraining when accuracy degrades. The DigitalQatalyst team can advise on retraining cadence as part of the managed service.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (77, 'How do we get started?', 'Share your AI design specifications and the DigitalQatalyst team will confirm the pilot cohort, data pipeline requirements, and the governance prerequisites needed to begin.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (78, 'Monthly Operational System Performance Report', 'Uptime, throughput, data quality metrics, and SLA adherence for your specialist operational platform, with recommended actions for the following month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (78, 'Support and Incident Log', 'Documented record of every issue raised, resolution time, root cause, and recurrence prevention action taken during the month.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (78, 'Change Management Assessments', 'Impact assessment for each planned change to your operational system or connected integrations, with a risk rating and recommended implementation approach.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (78, 'Quarterly Operational Review', 'A structured session with the DigitalQatalyst team to review performance trends, address emerging operational requirements, and adjust the improvement backlog.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (78, 'What does domain-specific support mean in practice?', 'The DigitalQatalyst team assigned to your function understands both the platform and the operational context. They can resolve workflow configuration issues, data quality problems, and integration failures without needing extensive briefing from your team.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (78, 'Is user training included in the managed service?', 'Training for new users onboarded to the system is included within agreed limits. Larger training programmes for significant process changes are scoped separately.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (78, 'How quickly are operational system issues resolved?', 'Response and resolution times are set by the SLA agreed at onboarding. Critical issues affecting operational throughput are given the highest response priority.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (78, 'How do we get started?', 'Contact the DigitalQatalyst team with your current system documentation. They will complete a health baseline audit before the first SLA period begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (79, 'Enterprise Operating Model Assessment', 'Documented review of planning cadences, cross-functional handoffs, decision rights, and performance visibility across your enterprise functions, with identified failures and their business impact.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (79, 'Decision Rights and Coordination Gap Register', 'Every identified coordination failure and ambiguous decision right scored by impact on execution speed, with recommended ownership and resolution approach.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (79, 'Prioritised Improvement Roadmap', 'Sequenced recommendations covering operating model design, technology, and data, with effort estimates and ownership assignments your COO can act on.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (79, 'Executive Briefing Pack', 'A concise summary of findings, top coordination risks, and recommended first investments formatted for COO and board-level review.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (79, 'Is this focused on technology or on how the organisation operates?', 'Both. The assessment covers operating model design, decision rights, and coordination patterns alongside the technology that enables or constrains them.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (79, 'How many functions does the assessment cover?', 'Scope is agreed at the start of the engagement. Most assessments cover COO, finance, supply chain, and IT as a minimum, with additional functions added based on priority.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (79, 'Do you benchmark our operating model against industry standards?', 'The DigitalQatalyst team uses reference models for enterprise operations to contextualise findings, though benchmarking against named competitors is not included in this engagement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (79, 'How do we get started?', 'Book a scoping call with the DigitalQatalyst team. They will confirm the functions in scope, the stakeholders to involve, and any documentation to prepare in advance.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (80, 'Redesigned Cross-Functional Process Maps', 'Detailed to-be workflows for planning, performance review, escalation, and operational reporting, with roles, decision rights, and data flows documented for each.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (80, 'Governance Framework', 'Operating model governance structure specifying decision-making forums, cadences, accountabilities, and escalation paths across enterprise functions.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (80, 'Decision Authority Matrix', 'Role-level specification of what each function can decide independently, what requires cross-functional consensus, and what escalates to executive leadership.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (80, 'Platform Configuration Specification', 'Build instructions for ERP or operational platform changes required to support the redesigned processes, with data model updates and integration requirements included.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (80, 'Does the design engagement cover organisation design as well as process and technology?', 'The primary focus is process and technology design. Operating model decisions that affect team structure and reporting lines are flagged but formal organisation design is a separate workstream.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (80, 'How do you align stakeholders across multiple functions during the design?', 'Week one includes a cross-functional alignment workshop. The design is reviewed with representatives from each function in weeks two and three before sign-off in week four.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (80, 'Can the design cover a specific platform such as SAP or Oracle?', 'Yes. The DigitalQatalyst team designs to your target platform. Platform-specific expertise is confirmed during the scoping call.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (80, 'How do we get started?', 'Contact the DigitalQatalyst team with your assessment findings or a summary of the operational improvements you need to achieve. They will confirm the cross-functional stakeholders to engage from day one.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (81, 'Enterprise AI Use-Case Assessment', 'Scored evaluation of AI opportunities across enterprise operational functions, ranked by strategic impact, data readiness, and responsible AI risk profile.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (81, 'Data Readiness and Architecture Report', 'Assessment of enterprise data quality, accessibility, and lineage requirements for the prioritised AI use cases, with remediation steps for gaps.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (81, 'Responsible AI Framework', 'Governance principles, bias testing approach, explainability requirements, and human oversight rules designed for your enterprise operational decision context.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (81, 'AI Integration and Workflow Specifications', 'Detailed design for how AI outputs integrate with ERP, planning, and reporting systems, with data flow diagrams, API contracts, and monitoring requirements.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (81, 'Which enterprise AI use cases tend to deliver the most operational value?', 'Demand forecasting, supply chain risk detection, capacity optimisation, and operational anomaly alerting are consistently high-value. The DigitalQatalyst team validates which apply to your operational context.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (81, 'How do you handle AI explainability for enterprise decisions?', 'Explainability requirements are defined in the responsible AI framework for each use case. Where decisions affect employees, suppliers, or customers, the framework specifies how explanations are generated and made available.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (81, 'Our enterprise data is spread across multiple ERPs and data warehouses. Can AI still work?', 'The data readiness report maps exactly what is available, where quality issues exist, and what integration work is needed. Some use cases can proceed with targeted data remediation; others may need to wait.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (81, 'How do we get started?', 'Contact the DigitalQatalyst team with your enterprise operational priorities. They will confirm the use-case discovery scope and the stakeholders to involve in week one.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (82, 'Configured Enterprise Operational Platform', 'ERP and operational system modules live in production, configured to the approved specification and accepted by cross-functional business owners at each phase gate.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (82, 'Integrated Operational Data Flows', 'Tested and documented connections between ERP, data warehouse, and operational dashboards, delivering a consistent enterprise view of performance for decision-makers.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (82, 'Change Champion Network and Adoption Materials', 'Trained change champions within each function, with role-specific adoption guides, FAQs, and escalation paths for the post-go-live period.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (82, 'Post-Launch Adoption and Performance Baseline', '30-day measurement of process adherence, governance forum participation, and operational visibility metrics to evidence adoption and establish the improvement baseline.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (82, 'How do you manage cross-functional stakeholder alignment during a twelve-week build?', 'The sprint plan includes fortnightly review sessions with cross-functional business owners. Change impact is tracked and communicated as configuration decisions are made.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (82, 'What if our ERP does not support the configuration changes in the design?', 'Weeks one to two include a technical feasibility review. Any gaps between the design and platform capability are surfaced early with options: alternative configuration, middleware, or design adjustment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (82, 'How do you handle data migration from legacy operational systems?', 'Data migration scope is confirmed in weeks one to two. The DigitalQatalyst team designs the migration approach, validates data quality, and runs reconciliation checks before go-live.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (82, 'How do we get started?', 'Provide your approved design specification and the DigitalQatalyst team will confirm environment access, migration scope, and the sprint-one schedule with your cross-functional leads.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (83, 'Deployed Forecasting and Risk Detection Models', 'AI models running in production and integrated into your planning and operational systems, validated against agreed accuracy thresholds during the pilot phase.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (83, 'Operational Risk Alert Configuration', 'Alert rules, escalation routing, and notification templates configured for supply chain and operational risk scenarios, tested against historical data before go-live.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (83, 'AI Explainability Layer', 'Explanation outputs accompanying every AI recommendation, formatted for the operational managers who will act on or override them.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (83, 'Executive AI Governance Dashboard', 'Live view of model accuracy, override rates, alert volumes, and decision outcomes across enterprise functions, handed over with trained dashboard administrators.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (83, 'How do you validate forecasting accuracy before full production rollout?', 'During the pilot phase, forecasts are run against historical data and compared to actual outcomes. The DigitalQatalyst team sets accuracy targets at kickoff and does not proceed to full rollout until they are met.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (83, 'What if enterprise leaders override AI recommendations frequently?', 'Override rates are tracked in the governance dashboard. High override rates trigger a review of confidence thresholds and model assumptions with the DigitalQatalyst team.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (83, 'How does the AI handle unexpected events that fall outside its training data?', 'Model confidence scores drop for out-of-distribution scenarios, triggering human review rather than automated action. The governance framework defines the escalation path for these situations.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (83, 'How do we get started?', 'Share your AI design specifications and data pipeline documentation with the DigitalQatalyst team. They will confirm model configuration prerequisites and the pilot cohort before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (84, 'Monthly Enterprise Operations Report', 'System uptime, data quality metrics, AI model accuracy, and SLA adherence across your enterprise operational estate, with recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (84, 'AI Model Performance Review', 'Monthly accuracy and drift analysis for each AI model in production, with threshold recalibration recommendations and retraining triggers where needed.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (84, 'Change Impact Assessments', 'Assessment of every planned ERP update, data model change, or operational process change for impact on platform configuration and AI model performance.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (84, 'Quarterly Enterprise Roadmap Review', 'A structured session with the DigitalQatalyst team to review operational performance trends, prioritise improvement initiatives, and align the backlog to business priorities.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (84, 'What does AI model maintenance involve on an ongoing basis?', 'Monthly accuracy reviews compare model outputs against actual outcomes. When accuracy drifts below threshold, the DigitalQatalyst team initiates recalibration or retraining and documents the change.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (84, 'How do you handle major ERP upgrades under the managed service?', 'The DigitalQatalyst team assesses every planned ERP upgrade for impact on configuration, integrations, and AI data pipelines, providing a remediation plan before the upgrade lands.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (84, 'Can we add new operational capabilities under the managed service?', 'Minor enhancements are included within capacity. Significant new capabilities are scoped as separate engagements and discussed in the quarterly roadmap review.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (84, 'How do we get started?', 'Contact the DigitalQatalyst team with your current platform and AI estate documentation. They will complete a health baseline before the first SLA period begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (85, 'Control gap assessment', 'Every in-scope control rated against your target framework, with evidence reviewed and specific gaps documented for remediation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (85, 'Scored risk register', 'Risks ranked by likelihood and business impact so the highest-exposure items receive attention before lower-priority ones.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (85, 'Prioritised remediation roadmap', 'Sequenced actions with named owners, effort estimates, and dependencies your teams can execute against in the next quarter.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (85, 'Board-ready executive summary', 'A concise read on current exposure, priority actions, and recommended investment framed for non-technical stakeholders.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (85, 'Which compliance frameworks do you assess against?', 'ISO 27001, NIST CSF, SOC 2 Type II, and sector-specific standards such as PCI DSS and HIPAA. The DigitalQatalyst team confirms the target framework during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (85, 'What access do you need to our systems?', 'The assessment runs on documentation, policy evidence, and stakeholder interviews. If read-only access to a specific tool would accelerate evidence collection, we agree the exact scope with your IT security team in advance -- it is never a requirement to proceed.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (85, 'How quickly will we see results?', 'The full assessment, scored risk register, and remediation roadmap are delivered within one week of the engagement starting.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (85, 'Can the roadmap feed directly into our next budget cycle?', 'Yes. The roadmap includes effort estimates and business impact scores formatted to support prioritisation conversations with finance and leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (85, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm scope, target framework, and stakeholders before any work begins.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (86, 'GRC operating model', 'Defined roles, accountabilities, governance cadences, and escalation paths for ongoing risk and compliance operations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (86, 'Controls architecture', 'Specified controls mapped to gaps from assessment, with automation points, tooling choices, and integration requirements documented.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (86, 'Process and workflow designs', 'End-to-end workflow diagrams and process specifications for risk identification, compliance monitoring, and incident response.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (86, 'Build handover package', 'Complete implementation specifications, data requirements, acceptance criteria, and an adoption plan ready for a deployment team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (86, 'Do we need to have completed an assessment first?', 'An assessment is strongly recommended as it informs the design priorities. If you have existing audit findings or a gap analysis, the DigitalQatalyst team can use those as the starting point.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (86, 'Which GRC platforms do you design for?', 'We design platform-agnostic specifications and can align to ServiceNow GRC, Microsoft Purview, Archer, or your preferred tooling. Platform selection is confirmed during week one.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (86, 'How involved does our team need to be?', 'We run focused workshops in weeks one and three. Between sessions your team reviews drafts and provides feedback. We handle the documentation and specification work.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (86, 'What happens after the design is signed off?', 'The handover package goes directly to a deployment team, either your internal resources or the DigitalQatalyst team through a Deploy engagement.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (86, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team will review your objectives and any existing assessment findings before the engagement kicks off.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (87, 'AI use-case register', 'Validated list of AI applications for GRC, each assessed for feasibility, data readiness, regulatory compatibility, and expected value.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (87, 'Responsible AI assessment', 'Documented findings on bias risk, data quality, explainability obligations, and regulatory constraints for each prioritised use case.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (87, 'AI workflow designs', 'Process specifications showing how AI outputs integrate into risk identification, compliance monitoring, and incident escalation workflows.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (87, 'Deployment specification package', 'Technical and governance requirements for each use case: model criteria, human-in-the-loop controls, monitoring thresholds, and audit logging.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (87, 'What kinds of AI use cases typically emerge in GRC?', 'Common validated use cases include continuous control monitoring, anomaly detection in transaction data, automated regulatory change alerts, and AI-assisted policy review. The DigitalQatalyst team works with your context to identify which apply.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (87, 'How do you handle regulatory constraints on AI in compliance functions?', 'The responsible AI assessment covers applicable regulations, including explainability requirements under GDPR, sector-specific AI rules, and your own internal AI policy. Constraints are documented in the deployment spec.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (87, 'What data do you need access to during the design?', 'Primarily data inventories, schema documentation, and sample datasets for feasibility assessment. No production data is required; the design phase works from specifications.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (87, 'Can we run this without a prior GRC assessment?', 'Yes, though an assessment or existing gap analysis makes the use-case prioritisation more precise. The DigitalQatalyst team will review available materials during scoping.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (87, 'How do we get started?', 'Contact the DigitalQatalyst team to arrange a scoping call covering your current GRC tooling, data landscape, and AI objectives.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (88, 'Configured GRC platform', 'Your chosen GRC tooling fully configured to your control framework, risk taxonomy, and reporting requirements, with all agreed integrations live.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (88, 'Integration and data pipeline documentation', 'Documented connections between GRC platform and upstream data sources, with data flow diagrams and monitoring configurations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (88, 'Testing evidence pack', 'Full test results across functional, integration, and user acceptance phases, with defect resolution records for audit and assurance purposes.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (88, 'Operational handover package', 'Runbooks, administrator guides, user training materials, and a hypercare plan so your team can operate the GRC capability independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (88, 'Which GRC platforms can you deploy and configure?', 'ServiceNow GRC, Microsoft Purview Compliance, RSA Archer, LogicGate, and other leading platforms. The DigitalQatalyst team confirms platform fit during pre-deployment scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (88, 'How do you manage integration with our existing data sources?', 'Integration requirements are scoped in the first three weeks. The team builds and tests connections to HR, IT, financial, and operational data sources as agreed in the design specifications.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (88, 'What does the hypercare period cover?', 'Hypercare runs for two weeks post-launch and includes daily check-ins, priority defect resolution, and on-call support for your compliance and operations teams.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (88, 'What if we do not have a completed design?', 'A design specification is a prerequisite for deployment. The DigitalQatalyst team can run a condensed design phase before committing to the deployment schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (88, 'How do we get started?', 'Provide your design specification or assessment findings and the DigitalQatalyst team will scope the deployment timeline and resource requirements within five working days.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (89, 'Production AI deployment', 'Validated AI models live in your environment, connected to GRC data sources, and processing alerts within agreed latency and accuracy thresholds.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (89, 'Guardrails and safety controls documentation', 'Configured human-in-the-loop checkpoints, override procedures, and escalation paths documented for audit and regulatory review.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (89, 'Monitoring and performance dashboard', 'Real-time view of model outputs, alert volumes, false-positive rates, and compliance outcomes with configurable thresholds and alerting.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (89, 'Operations and retraining guide', 'Step-by-step procedures for your GRC team to manage model performance, trigger retraining, and document decisions for audit purposes.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (89, 'What AI use cases can you put into production for GRC?', 'Continuous control monitoring, transaction anomaly detection, regulatory change classification, and AI-assisted policy review are the most common production deployments. The DigitalQatalyst team works from your validated AI design specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (89, 'How do you ensure the AI does not make compliance decisions without human review?', 'Human-in-the-loop checkpoints are configured before deployment. High-risk alerts always route to a named reviewer before any action is taken. Guardrail logic is documented and auditable.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (89, 'What happens if model accuracy degrades after go-live?', 'The monitoring dashboard surfaces accuracy metrics weekly. The operations guide includes retraining triggers and the DigitalQatalyst team provides hypercare support during the first two weeks post-launch.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (89, 'Do we need a deployment specification before this engagement?', 'Yes, the AI Deploy engagement builds from the specifications produced in an AI Design phase. If those are not in place, the DigitalQatalyst team can scope a combined design and deployment programme.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (89, 'How do we get started?', 'Share your AI design specifications and the DigitalQatalyst team will confirm readiness, environment requirements, and the deployment timeline within one week.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (90, 'Monthly compliance performance reports', 'Structured reports covering control status, open exceptions, remediation progress, and framework compliance score, formatted for board and audit committee use.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (90, 'Quarterly control testing evidence packs', 'Documented test results for in-scope controls, suitable for internal audit review and external certification bodies.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (90, 'Exception and incident log', 'Running record of control exceptions, incidents, and remediation actions with timestamps and owner details for regulatory and audit purposes.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (90, 'Optimisation recommendations', 'Quarterly recommendations for control improvements, tooling adjustments, or process changes based on performance data and regulatory developments.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (90, 'What is included in the monthly service?', 'Continuous control monitoring, exception alerting, a compliance performance report, and ongoing liaison with your risk and audit teams. Quarterly deliverables include control testing and evidence packs.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (90, 'How quickly do you respond to a control failure or incident?', 'Response times depend on your service tier. Critical control failures are escalated within four hours. The DigitalQatalyst team confirms SLA thresholds during onboarding.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (90, 'Can the service scale if our regulatory obligations change?', 'Yes. The engagement is reviewed quarterly. New frameworks, expanded scope, or additional controls can be added through a change request without restarting the engagement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (90, 'How does the service handle a regulator audit or certification visit?', 'The DigitalQatalyst team prepares and packages evidence for the audit scope, attends readiness reviews, and supports your team throughout the audit process as part of the managed service.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (90, 'How do we get started?', 'The DigitalQatalyst team runs a two-week onboarding to establish baselines, confirm SLAs, and connect monitoring tooling before steady-state operations begin.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (91, 'ERP Process Coverage Assessment', 'Module-by-module review of finance, procurement, HR, and inventory processes showing where ERP covers the business need and where manual workarounds have filled the gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (91, 'Data Quality Report', 'Assessment of master data accuracy, transactional data completeness, and reporting consistency, with specific data domains flagged for remediation.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (91, 'Integration Gap Analysis', 'Documented review of data flows between ERP and connected systems, with gaps, duplications, and reconciliation failures identified and ranked by financial risk.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (91, 'Prioritised Remediation Roadmap', 'Sequenced improvement plan covering ERP configuration, data remediation, and integration fixes, with effort estimates and ownership assignments.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (91, 'Which ERP platforms does the assessment cover?', 'SAP, Oracle, Microsoft Dynamics 365, and Sage are the primary platforms covered. If your environment runs a different ERP, confirm with the DigitalQatalyst team during scoping -- most mid-market platforms can be assessed using the same methodology.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (91, 'Can you assess an ERP that is heavily customised?', 'Yes. Customised ERPs are a common source of the gaps this assessment finds. The review covers both standard module gaps and the technical debt from custom development.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (91, 'Do you need access to the ERP system itself?', 'Read-only access to the system and sample data extracts is helpful. The assessment can also run on documentation and stakeholder interviews if system access is restricted.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (91, 'How do we get started?', 'Book a scoping call with the DigitalQatalyst team. They will confirm the modules in scope, the stakeholders to involve, and any documentation or data extracts to prepare in advance.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (92, 'ERP Process Design Documents', 'To-be process flows for each in-scope ERP module covering every transaction type, approval path, exception, and reporting touchpoint.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (92, 'Master Data Standards Specification', 'Defined standards for chart of accounts, cost centres, supplier master, and employee data, with ownership rules and data quality criteria.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (92, 'ERP Configuration Blueprint', 'Module-level configuration specifications covering settings, approval workflows, validation rules, and reporting dimensions your ERP team can implement directly.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (92, 'Integration Architecture Document', 'Data flow diagrams and API specifications for connections between ERP and payroll, CRM, data warehouse, and other dependent systems.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (92, 'How many ERP modules does the design engagement cover?', 'Scope is agreed at the start of week one. Most engagements cover three to five modules. Finance, procurement, and HR are the most common combination.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (92, 'Does this produce artefacts that an SAP or Oracle implementer can use directly?', 'Yes. Configuration blueprints are produced in a format aligned to the conventions of your target platform. The DigitalQatalyst team confirms the artefact format at kickoff.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (92, 'Can you help with the chart of accounts redesign specifically?', 'Yes. Chart of accounts and cost centre structure redesign is a standard workstream within the master data specification deliverable.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (92, 'How do we get started?', 'Share your ERP assessment findings or a summary of the improvements needed and the DigitalQatalyst team will confirm scope, module coverage, and the week-one workshop schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (93, 'ERP AI Use-Case Assessment', 'Scored list of AI opportunities across finance, procurement, and HR, ranked by financial impact, data readiness, and audit risk.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (93, 'ERP Data Readiness Report', 'Assessment of transactional and master data quality, volume, and lineage against the requirements for each AI candidate, with remediation steps for gaps.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (93, 'Responsible AI Specifications for Finance Contexts', 'Control framework and audit trail requirements for each AI use case, designed to satisfy finance audit, SOX, and regulatory scrutiny.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (93, 'ERP AI Integration Specifications', 'Detailed API and data flow designs for embedding AI recommendations, alerts, and automated actions within ERP workflows.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (93, 'Which AI use cases are most mature for ERP environments?', 'Accounts payable matching, invoice exception detection, cash flow forecasting, and spend category classification are the most commonly deployed. The DigitalQatalyst team validates which are appropriate for your ERP data and processes.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (93, 'How do you address the audit trail requirements for AI-driven financial decisions?', 'Every AI action in a finance context is designed with a full audit record: the input data, model version, output, confidence score, and any human review action. This is specified in the control framework deliverable.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (93, 'Can AI work with the data quality we currently have in our ERP?', 'The data readiness report will tell you clearly. Some use cases are feasible with targeted remediation; others require a data quality programme first. The DigitalQatalyst team will not recommend AI deployment on data that does not meet minimum quality thresholds.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (93, 'How do we get started?', 'Contact the DigitalQatalyst team with your ERP platform details and the finance processes you are considering for AI. They will confirm the use-case discovery scope and week-one workshop participants.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (94, 'Configured ERP Modules', 'Finance, procurement, and HR modules live in production, configured to the approved specification and accepted by business module owners.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (94, 'Migrated and Reconciled Data', 'Master data and opening balances loaded to production with reconciliation evidence confirming accuracy against the source system.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (94, 'Integration Connections with Test Evidence', 'Functioning and documented data flows between ERP and connected systems, with executed test scripts and business sign-off records.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (94, 'Go-Live Operations Pack', 'Cutover runbook, rollback procedure, period-end close checklist, and administrator guide for your finance and IT teams to manage the post-go-live environment.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (94, 'How do you handle the cutover from our current ERP to the new configuration?', 'The DigitalQatalyst team designs a detailed cutover plan in weeks eleven to twelve, including a parallel run period, a reconciliation checklist, and a rollback procedure if issues arise post-go-live.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (94, 'What if data quality issues are discovered during migration?', 'Migration runs in weeks three to eight surface data quality issues before the production load. The DigitalQatalyst team works with your data owners to resolve issues and re-run migration before user acceptance testing begins.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (94, 'Can we run the ERP deployment while the business continues normal operations?', 'Yes. The programme is designed to run alongside business operations. The cutover is timed to minimise disruption to financial period-end activities.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (94, 'How do we get started?', 'Provide your approved ERP design specification and the DigitalQatalyst team will confirm environment access, data migration scope, and the sprint-one schedule with your finance and IT leads.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (95, 'Deployed Invoice Matching Automation', 'AI-powered three-way match running in your ERP accounts payable workflow, with agreed accuracy rates achieved during pilot before full production rollout.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (95, 'Cash Flow Forecasting Integration', 'Rolling cash flow forecast generated from live ERP data, displayed within the finance team''s planning environment with variance explanations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (95, 'Spend Anomaly Detection Alerts', 'Configured alert rules detecting policy breaches and spending pattern anomalies, routed to the appropriate procurement or finance approver.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (95, 'Finance-Grade Audit Log and Control Report', 'Complete audit trail for every AI decision during the deployment period, reviewed against the control framework and cleared for finance audit.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (95, 'What invoice matching accuracy rates can we expect?', 'Straight-through processing rates depend on invoice quality and supplier data consistency. The DigitalQatalyst team sets accuracy targets during the pilot and does not proceed to full rollout until they are met.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (95, 'How does AI cash flow forecasting work alongside our existing treasury models?', 'The AI forecast runs as a complementary input, not a replacement for treasury models. The integration design confirms how the two outputs are presented to the finance team.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (95, 'Can the AI be switched off for a specific invoice type or supplier without affecting everything else?', 'Yes. Inclusion rules are configured at a granular level so the finance team can exclude specific transaction types, suppliers, or currency categories from AI processing.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (95, 'How do we get started?', 'Share your AI design specifications and ERP environment details with the DigitalQatalyst team. They will confirm data pipeline prerequisites and the pilot cohort before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (96, 'Monthly ERP Health and AI Performance Report', 'System uptime, integration health, data quality metrics, AI model accuracy, and SLA adherence, with recommended actions for the following month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (96, 'Period-End Close Support Log', 'Record of every issue identified and resolved during monthly and quarterly period-end close, with root cause and prevention measure for recurring issues.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (96, 'AI Model Accuracy Review', 'Monthly comparison of invoice matching and forecasting accuracy against agreed thresholds, with recalibration actions taken and the next review date.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (96, 'ERP Change Impact Assessment', 'Assessment of every planned ERP patch, upgrade, or configuration change for impact on processes, integrations, and AI data pipelines, with a test plan and implementation recommendation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (96, 'What does period-end close support actually cover?', 'The DigitalQatalyst team is available during month-end and quarter-end windows to assist with reconciliation checks, posting run monitoring, and rapid resolution of system issues that arise during the close process.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (96, 'How do you manage ERP patches without disrupting production?', 'Every patch is assessed for impact, tested in a non-production environment, and approved by your finance IT lead before it is applied to production. Testing covers integration connections and AI data pipelines.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (96, 'What happens if an AI model starts producing inaccurate invoice matches?', 'The monthly accuracy review will identify the drift. The DigitalQatalyst team implements recalibration and, where necessary, initiates retraining. You are notified before any threshold breach affects your AP processing.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (96, 'How do we get started?', 'Contact the DigitalQatalyst team with your current ERP and AI configuration documentation. They will complete a health baseline audit before the first SLA period begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (97, 'Workforce maturity scorecard', 'Ratings across scheduling accuracy, labour visibility, coordination tools, and compliance controls, with evidence for each score.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (97, 'Gap and friction register', 'Documented breakdowns in scheduling, attendance tracking, and cross-team coordination, ranked by business impact.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (97, 'Prioritised improvement roadmap', 'Sequenced actions with named owners, effort estimates, and dependencies so your team knows what to tackle first.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (97, 'Stakeholder briefing pack', 'A concise summary of findings and recommended investment for HR, finance, and operations leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (97, 'What workforce models does this cover?', 'Distributed, shift-based, field, frontline, and knowledge worker models. The DigitalQatalyst team confirms which apply to your organisation during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (97, 'Do you need access to our scheduling or HR systems?', 'We review configuration and reporting outputs rather than live data. Any access required is read-only and agreed in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (97, 'What do we get at the end?', 'A maturity scorecard, a gap and friction register, a prioritised improvement roadmap, and a stakeholder briefing pack.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (97, 'How long does the assessment take?', 'One week from kick-off to findings delivery, assuming stakeholders are available for interviews in the first two days.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (97, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm scope, workforce categories in scope, and key stakeholders before work begins.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (98, 'Workforce journey maps', 'End-to-end flows for each role: how managers create rosters, how workers view and swap shifts, and how exceptions are handled.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (98, 'Scheduling and rostering specification', 'Rules, constraints, and business logic documented so development or configuration teams can build without interpretation.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (98, 'Integration design', 'Data flows, field mappings, and API or file-exchange patterns for every connected system including payroll and HRIS.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (98, 'Adoption and change plan', 'Phased rollout approach, training requirements by role, and success metrics to track uptake after launch.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (98, 'Does the design tie us to a specific platform?', 'No. The DigitalQatalyst team designs to your requirements first. Platform selection is informed by the design, not the other way around.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (98, 'What if we already have a platform in place?', 'We design around it, documenting configuration changes, integration updates, and any gaps the current platform cannot close.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (98, 'How do frontline workers feed into the design?', 'We include representative users in journey workshops to ensure scheduling and communication flows work for the people using them daily.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (98, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the workforce categories in scope and the systems we need to design around before the engagement begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (99, 'AI use-case feasibility register', 'Each candidate use case scored against data availability, technical complexity, and business value, with a go or no-go recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (99, 'Data readiness report', 'Gaps in training data, labelling, and integration coverage that must be closed before model development can begin.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (99, 'Responsible workforce AI workflows', 'Designed flows for approved use cases including human override points, fairness constraints, and worker-facing explainability.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (99, 'Deployment and monitoring specification', 'Model selection guidance, performance thresholds, drift detection triggers, and retraining schedules for production readiness.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (99, 'Which AI use cases are typically in scope?', 'Demand-based auto-rostering, absence and attrition prediction, shift-swap optimisation, and fatigue or compliance flagging are the most common starting points.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (99, 'What if our workforce data is incomplete?', 'The data readiness report identifies exactly what is missing. Many organisations begin with narrower use cases while filling data gaps in parallel.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (99, 'How do you address fairness in scheduling AI?', 'Fairness constraints, protected-attribute exclusions, and worker-facing explanations are built into the workflow design, not added later.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (99, 'How do we get started?', 'Book a consultation with the DigitalQatalyst team to identify your highest-value AI use cases and confirm your current data landscape.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (100, 'Configured workforce management platform', 'Production-ready scheduling, rostering, time tracking, and communication setup tested against your approved specifications.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (100, 'Integration test evidence pack', 'Test cases, execution results, and defect closure confirmation for every connected system including payroll and HRIS.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (100, 'User acceptance sign-off', 'Documented UAT results from managers, schedulers, and frontline representatives confirming the platform meets operational requirements.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (100, 'Operational handover kit', 'Administrator guides, support escalation paths, known-issues register, and a 30-day post-launch review schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (100, 'What happens if integration testing uncovers gaps in the design?', 'The DigitalQatalyst team documents and triages each gap. Minor issues are resolved within the deployment. Scope changes are raised with the project sponsor before proceeding.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (100, 'How are frontline workers involved in UAT?', 'We recruit representative workers from each shift category to test scheduling, shift-swap, and notification flows in a pre-production environment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (100, 'What does hypercare include?', 'Daily monitoring, prioritised defect fixes, and a dedicated point of contact for your operations team through the first two to four weeks of live operation.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (100, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the platform, integration scope, and cutover constraints before planning begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (101, 'Production AI deployment', 'Approved models live in your workforce management platform with data pipelines, override controls, and logging in place.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (101, 'Model performance dashboard', 'Real-time view of scheduling accuracy, forecast error rates, fairness indicators, and alert thresholds for your operations team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (101, 'Override and escalation playbook', 'Step-by-step procedures for managers when AI recommendations need to be overridden, and when to escalate to the DigitalQatalyst team.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (101, 'AI governance handover pack', 'Model cards, data lineage documentation, retraining schedule, and accountability assignments for ongoing responsible operation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (101, 'What happens if a model starts performing poorly after launch?', 'Monitoring dashboards alert the DigitalQatalyst team and your operations leads. Retraining or rollback procedures are defined in the governance handover pack.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (101, 'Can managers override AI scheduling recommendations?', 'Yes. Override workflows are embedded in the scheduling tool. All overrides are logged for quality review and model improvement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (101, 'How do you handle regulatory requirements around automated workforce decisions?', 'Accountability, explainability, and human oversight controls are designed into the deployment. We confirm applicable obligations during scoping.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (101, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved AI design specification to plan the production environment and pilot cohort.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (102, 'Monthly performance report', 'Scheduling fill rates, overtime trends, absenteeism patterns, and system health metrics with commentary and recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (102, 'Incident and change log', 'Transparent record of all incidents, configuration changes, and SLA performance across the reporting period.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (102, 'Quarterly optimisation review', 'Analysis of workforce trends, platform capability gaps, and prioritised improvement actions for the next quarter.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (102, 'Annual workforce management roadmap', 'Forward-looking plan covering platform updates, capability additions, and structural changes needed to support business growth.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (102, 'What is covered under the managed service?', 'Platform monitoring, incident response, configuration changes, monthly reporting, and quarterly optimisation reviews. Scope is confirmed in the service agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (102, 'What SLAs apply?', 'Response and resolution times are agreed during onboarding based on the criticality of your scheduling operations. Typical targets range from 4-hour response for critical incidents to next-business-day for low-priority items.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (102, 'Can we add new workforce categories or locations over time?', 'Yes. Configuration updates for new sites, roles, or scheduling rules are included within agreed change volumes. Larger changes are scoped and priced separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (102, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the platform in scope, current configuration baseline, and SLA requirements before the service agreement is drafted.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (103, 'Data platform maturity scorecard', 'A domain-by-domain rating of ingestion, transformation, storage, and consumption layers, with evidence for each score.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (103, 'Gap and root-cause register', 'Every identified gap mapped to its root cause, the business risk it carries, and the effort band required to close it.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (103, 'Prioritised roadmap', 'A sequenced action plan with owners, dependencies, and effort estimates so your teams can start closing the highest-risk gaps immediately.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (103, 'Executive summary pack', 'A concise board-ready presentation covering current state, priority findings, and recommended investment.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (103, 'What do you review during the assessment?', 'The DigitalQatalyst team reviews your ingestion pipelines, storage architecture, transformation logic, data quality controls, lineage tooling, and governance policies. We focus on what is actually in place, not what is documented.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (103, 'Do you need access to production systems?', 'We work primarily from architecture diagrams, pipeline configurations, and stakeholder interviews. Any read-only access to tooling is agreed upfront and scoped to the minimum needed.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (103, 'What if we are mid-way through a migration?', 'That is common. We assess your current and target state together so the roadmap accounts for in-flight work and avoids duplicating effort.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (103, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will align on scope, confirm the relevant stakeholders, and agree a kick-off date before any work begins.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (103, 'What does the roadmap look like?', 'A sequenced list of prioritised actions, each with an owner role, an effort band (days of work), key dependencies, and a recommended delivery sequence.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (104, 'Target-state architecture blueprint', 'A detailed diagram and narrative covering each platform layer, technology choices, and the rationale for each decision.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (104, 'Canonical data model and domain definitions', 'Domain-level entity definitions, ownership assignments, and the data contracts your teams will build to.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (104, 'Governance and quality framework', 'Policies, tooling recommendations, and process designs for lineage tracking, cataloguing, access control, and quality measurement.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (104, 'Phased build and adoption plan', 'A sequenced delivery roadmap with team roles, sprint milestones, and a change management guide to drive adoption across data consumers.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (104, 'Do you design for a specific cloud provider or technology stack?', 'The DigitalQatalyst team designs for your chosen stack. We are fluent across the major cloud data platforms and will work within your existing technology constraints or help you select where the choice is still open.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (104, 'How much input does our team need to provide?', 'We run structured workshops in weeks one and two. Your data engineers, architects, and domain leads will need half-day availability across those sessions. We handle the synthesis and design work between workshops.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (104, 'What is a data contract and why does it matter?', 'A data contract is a formal agreement between a data producer and its consumers specifying schema, quality guarantees, and SLAs. It prevents the silent breaking changes that erode trust in platform data.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (104, 'Does the design include a migration plan if we are replacing a legacy system?', 'Yes. Where a legacy system is in scope, the architecture blueprint includes a migration strategy covering data extraction, transformation, parallel running, and cutover.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (104, 'How do we get started?', 'Contact the DigitalQatalyst team to discuss your platform goals. We will confirm scope, identify the right stakeholders, and propose a kick-off schedule.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (105, 'AI use-case prioritisation matrix', 'Each candidate use case scored on data readiness, technical complexity, business value, and risk, with a clear build-or-defer recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (105, 'Responsible AI workflow designs', 'End-to-end workflow diagrams for each prioritised use case, including bias controls, explainability hooks, and human-in-the-loop decision points.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (105, 'Data readiness gap report', 'A precise list of the data quality, coverage, and lineage gaps that must be resolved before each use case can proceed to build.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (105, 'Deployment-ready AI specifications', 'Feature pipeline definitions, model requirements, inference architecture, and monitoring specifications your engineering team can build against.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (105, 'How do you decide which AI use cases to prioritise?', 'The DigitalQatalyst team scores each candidate against four factors: data readiness, technical feasibility, business value, and governance risk. Only use cases that score above a defined threshold proceed to full specification.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (105, 'What does responsible AI mean in practice for a data platform?', 'It means designing bias detection into training pipelines, defining explainability requirements before model selection, and specifying the human review points where an automated decision must be checked before acting.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (105, 'Do we need an existing ML platform to begin?', 'No. If you do not have an ML platform, the specifications will include platform requirements. If you do, we design within your existing tooling.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (105, 'How do we get started?', 'Reach out to the DigitalQatalyst team with your candidate use cases or business problems. We will assess your starting position and propose a scoped engagement.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Configured and tested data platform', 'A fully provisioned platform environment with all agreed pipelines live, tested against acceptance criteria, and confirmed ready for production traffic.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Integration test results and sign-off', 'Test evidence covering each source-to-destination data flow, with defects resolved and results signed off by your technical lead.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Operations runbook set', 'Step-by-step runbooks for pipeline monitoring, incident triage, scheduled maintenance, and common failure scenarios.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Handover and knowledge transfer pack', 'Session recordings, architecture documentation, and a competency checklist confirming your team can operate the platform independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'What does the knowledge transfer programme involve in practice?', 'Your operations and engineering teams join live sessions covering platform monitoring, pipeline triage, and incident response. They receive runbooks, architecture documentation, and a sign-off checklist before the DigitalQatalyst team steps back.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'How do you handle data quality during migration?', 'We define acceptance criteria for each pipeline before build. During testing, every pipeline output is validated against those criteria. Any deviation is classified and resolved before that pipeline goes live.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'What if a source system integration is more complex than expected?', 'Scope changes are assessed formally. The DigitalQatalyst team will identify the impact on timeline and budget and agree any adjustment with you before proceeding.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'How do we get started?', 'The deployment engagement follows directly from a completed design. Share your architecture blueprint with the DigitalQatalyst team and we will confirm scope, resourcing, and a kick-off date.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'Production AI deployment', 'AI models serving live predictions via governed endpoints, with version control, rollback capability, and environment isolation confirmed working.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'Monitoring and alerting configuration', 'Drift detection, performance dashboards, and alert thresholds configured so your team knows immediately when a model needs attention.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'Governance and audit controls', 'Audit logs, prediction traceability records, and access control configurations meeting your compliance and responsible AI requirements.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'ML operations handover pack', 'Incident playbooks, retraining triggers, monitoring guides, and a sign-off checklist confirming your ML team can operate and maintain the models independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'What does model drift monitoring look like?', 'We configure statistical checks on input feature distributions and prediction output distributions. When either drifts beyond agreed thresholds, your team receives an alert and the incident playbook tells them what to investigate first.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'How do you handle model versioning in production?', 'Every model version is tagged, stored in a model registry, and deployed with a documented rollback path. Promoting a new version requires a passing validation suite, so production is never overwritten without evidence.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'What if a model underperforms in production?', 'The incident playbook covers this. Your team can roll back to the previous version immediately. The DigitalQatalyst team will support a root-cause review if the underperformance is not explained by drift.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'How do we get started?', 'The AI deployment engagement follows from a completed AI design. Share your deployment specifications with the DigitalQatalyst team and we will confirm scope, ML infrastructure requirements, and a timeline.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Monthly data quality report', 'A scored view of platform data quality across completeness, accuracy, freshness, and lineage, with trend analysis and recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Incident log and resolution record', 'A complete log of every pipeline incident, the time to detect and resolve, the root cause, and the preventive action taken.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Quarterly performance and cost review', 'An analysis of platform query performance, compute and storage costs, and the optimisations applied or recommended for the next quarter.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Governance compliance summary', 'A periodic report confirming that access controls, lineage coverage, and data retention policies remain compliant with your governance framework.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'What SLAs apply to the managed service?', 'SLAs are agreed during onboarding and typically cover time to detect a pipeline failure, time to notify, and time to resolve by severity level. Your account is reviewed against these targets in the monthly report.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'What happens when a pipeline fails?', 'The DigitalQatalyst team receives an alert, assesses severity, and begins remediation within the agreed response window. You are notified immediately and kept updated until resolution.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'Can we request changes or new pipelines under the managed service?', 'Yes. Change requests are scoped and delivered within the service. Larger changes that exceed the included capacity are quoted separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'How do we get started?', 'The managed service typically follows a completed deployment. Contact the DigitalQatalyst team to discuss transition planning, agree SLAs, and schedule the onboarding period.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (109, 'BI maturity scorecard', 'A capability-by-capability rating of your current BI and analytics environment, with evidence and the specific gaps to close.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (109, 'Report and dashboard audit', 'An inventory of existing reports identifying duplication, conflicting definitions, stale data sources, and reports nobody uses.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (109, 'Decision-gap register', 'A log of the business decisions currently made without reliable data, the risk that carries, and the data changes needed to fix it.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (109, 'Prioritised BI improvement roadmap', 'A sequenced action plan covering quick wins and strategic investments, with effort estimates and recommended owners.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (109, 'Which BI tools do you review?', 'The DigitalQatalyst team reviews whatever tools you use, whether that is Power BI, Tableau, Looker, Qlik, or a custom-built solution. The assessment is tool-agnostic.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (109, 'How do you identify which gaps matter most?', 'We interview the people who make decisions and ask them which questions they cannot answer reliably, how often those questions arise, and what the cost of the uncertainty is. That drives the prioritisation.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (109, 'What if our biggest problem is data quality rather than the BI tools?', 'That is a common finding. The roadmap will distinguish between BI-layer fixes and upstream data fixes, and recommend which to tackle first based on the impact on decision-making.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (109, 'How do we get started?', 'Request a consultation with the DigitalQatalyst team. We will confirm scope, identify the right stakeholders for interviews, and agree a kick-off date.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (110, 'Metrics catalogue', 'Every agreed KPI defined with its calculation logic, source data, owner, refresh frequency, and the decisions it supports.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (110, 'Semantic layer and data model specification', 'A logical data model and semantic layer design ensuring every report calculates the same metric in the same way, regardless of which tool produces it.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (110, 'Dashboard and report specifications', 'Wireframes and functional specifications for each dashboard, mapped to the user roles and decision workflows they serve.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (110, 'Governance and certification design', 'Policies and process designs for report certification, data ownership, access control, and the lifecycle management of dashboards.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (110, 'What is a semantic layer and why does it matter for BI?', 'A semantic layer sits between your raw data and your BI tools, translating database fields into business terms and centralising metric calculation logic. It means every tool that queries it returns the same number for revenue, margin, or any other KPI.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (110, 'How do you get stakeholders to agree on metric definitions?', 'We run facilitated definition workshops in week one where each metric owner presents their current definition and we mediate towards a single agreed version. The DigitalQatalyst team documents every decision and its rationale.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (110, 'Do we need to replace our existing BI tools to benefit from the design?', 'No. The design works with your chosen tools. Where we identify tooling gaps, we make recommendations but do not require tool changes as a condition of the engagement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (110, 'How do we get started?', 'Contact the DigitalQatalyst team with your BI goals and a list of the decisions you want better data for. We will propose a scoped engagement and identify the stakeholders needed.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (111, 'AI use-case prioritisation assessment', 'Each proposed AI capability scored on data readiness, technical feasibility, business value, and responsible AI risk, with a build or defer recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (111, 'Responsible AI workflow designs', 'End-to-end workflow diagrams for each prioritised use case, specifying human review points, confidence thresholds, and the actions to take when the model is uncertain.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (111, 'Technical specifications', 'Model requirements, feature pipeline designs, and integration architecture for each approved use case, ready for your engineering team to build against.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (111, 'Data gap remediation plan', 'A targeted list of the data quality and coverage improvements needed before each AI use case can train and run reliably.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (111, 'What kinds of AI capabilities work well for BI and analytics?', 'Forecasting and scenario modelling, anomaly and outlier detection, natural language querying of data, automated narrative generation for reports, and smart alerting that identifies which metric changes actually matter.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (111, 'How do you assess data readiness for AI?', 'The DigitalQatalyst team reviews the data sources that would feed each use case, checking completeness, consistency, history depth, and refresh frequency against the minimum requirements for the proposed AI capability.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (111, 'Do we need a separate ML platform or does this work with our BI tool?', 'It depends on the use case. Some AI capabilities are native to modern BI tools. Others require a separate ML platform. The specifications will tell you exactly what infrastructure each use case needs.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (111, 'How do we get started?', 'Share your BI goals and the decisions you want to make faster or more accurately with the DigitalQatalyst team. We will assess your starting position and propose an engagement scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (112, 'Integrated and tested BI environment', 'Data sources connected, pipelines running to schedule, and the semantic layer in place with all agreed KPIs calculating correctly.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (112, 'Certified dashboard suite', 'All specified dashboards built, tested against acceptance criteria, and certified as the authoritative source for each metric they present.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (112, 'Self-service analytics configuration', 'Self-service workspace configured with governed data sets, access controls in place, and documentation enabling your analysts to build their own reports.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (112, 'Training materials and handover documentation', 'Role-based training guides, administrator documentation, and a handover pack confirming your team can maintain and extend the BI environment independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (112, 'What does dashboard certification mean?', 'Certification means a named data owner has reviewed the dashboard, confirmed its calculations against the agreed metric definitions, and approved it as the authoritative source. Certified dashboards are marked in the BI environment.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (112, 'How do you handle conflicting numbers found during testing?', 'When user acceptance testing reveals a metric discrepancy, the DigitalQatalyst team traces it to its source, applies the agreed metric definition, and resolves it before certification. No dashboard goes live with unresolved conflicts.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (112, 'Will our data team be able to add new dashboards after the engagement?', 'Yes. Self-service configuration and administrator training are included. Your team will be able to publish new reports against the governed data sets without our involvement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (112, 'How do we get started?', 'Provide your completed BI design specifications to the DigitalQatalyst team. We will confirm scope, agree the data sources to connect first, and schedule a kick-off.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Production AI analytics deployment', 'AI models serving live predictions integrated into your BI dashboards, with version control and rollback capability confirmed working before launch.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Monitoring and alert configuration', 'Drift detection, accuracy tracking, and alerting thresholds configured so degradation is caught and investigated before it affects decisions.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Governance and audit controls', 'Audit logs covering model predictions, access controls on model endpoints, and documentation of the human review points applied in each workflow.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Analytics team enablement pack', 'Training materials, interpretation guides, and escalation procedures giving your analytics team the confidence to act on AI outputs and challenge them when something looks wrong.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'How do AI insights appear inside our existing dashboards?', 'The integration architecture defined in your AI design connects model outputs to your BI tool''s data layer. Analysts see forecasts, anomaly flags, or narrative insights directly in the dashboards they already use.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'What happens when a model flags an anomaly?', 'The alert routes to the relevant analyst. The incident playbook tells them what to investigate, what to rule out, and when to escalate. The DigitalQatalyst team will support the first few live alerts to build team confidence.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'How do you validate that the AI is producing useful outputs before go-live?', 'We run a shadow period where models produce outputs alongside your existing analysis. Your analytics team reviews the outputs against known historical events before the model is promoted to production.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'How do we get started?', 'Share your completed AI design specifications with the DigitalQatalyst team. We will confirm infrastructure requirements, identify the first use case for deployment, and schedule a kick-off.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (114, 'Monthly analytics quality report', 'A scored view of metric accuracy, data freshness, report usage, and incident history with trend analysis and recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (114, 'Incident log and resolution record', 'A complete log of every report failure or data issue, the time to detect and resolve, root cause, and preventive action taken.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (114, 'Quarterly optimisation review', 'An analysis of report performance, dashboard usage, and the optimisations applied or planned for the next quarter.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (114, 'Change register', 'A documented record of every approved change to reports, metrics, or data sources, with the business justification and sign-off for each.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (114, 'What counts as an incident under the managed service?', 'A report failure, a data refresh that misses its SLA window, a metric that calculates incorrectly, or a dashboard that becomes inaccessible. All are classified by severity and handled within the agreed response times.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (114, 'How do we request new reports or metric changes?', 'Through the change request process included in the service. The DigitalQatalyst team scopes the request, estimates effort, and delivers it within the agreed capacity. Requests that exceed included capacity are quoted separately.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (114, 'What happens if our source data changes and breaks our reports?', 'Monitoring detects the failure. The DigitalQatalyst team investigates, identifies the source change, and either remediates or raises a change request to update the affected pipelines and dashboards.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (114, 'How do we get started?', 'The managed service typically follows a completed deployment. Contact the DigitalQatalyst team to discuss transition planning, agree SLAs and service scope, and schedule the onboarding period.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (115, 'AI opportunity map', 'A scored view of the AI and automation opportunities across your priority workflows, ranked by business value, feasibility, and time to first value.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (115, 'Readiness assessment', 'A gap analysis covering data quality, infrastructure, skills, and governance against the requirements of each priority use case.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (115, 'Risk and ethics register', 'The responsible AI risks specific to your use cases and sector, with the controls and governance requirements needed to address each one.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (115, 'Prioritised AI adoption roadmap', 'A sequenced action plan for closing readiness gaps and building your first AI capabilities, with the investment case for each priority use case.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (115, 'Do we need to have AI projects already underway to benefit from this assessment?', 'No. This assessment is designed for organisations at the start of their AI journey. It is equally valuable if you have existing AI experiments that need structure and prioritisation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (115, 'How do you identify which use cases are genuinely feasible?', 'The DigitalQatalyst team scores each candidate against four factors: the data available to train and run it, the technical complexity, the business value, and the responsible AI risk. Only use cases that score above a defined threshold make the roadmap.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (115, 'What does the responsible AI review cover?', 'It covers bias risk, explainability requirements, regulatory obligations relevant to your sector, and the human oversight needed for each use case. The output is a practical list of the controls you will need to put in place.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (115, 'How do we get started?', 'Request a consultation with the DigitalQatalyst team. We will confirm scope, identify the right stakeholders, and agree which workflows to focus on during the assessment.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (116, 'AI workflow designs', 'Detailed workflow diagrams for each prioritised use case, showing the AI or automation interactions, decision points, human touchpoints, and exception paths.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (116, 'Integration architecture specification', 'A technical specification mapping how each AI capability connects to your applications, APIs, and data sources, with the agreed integration patterns and data flow.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (116, 'Governance and control framework', 'Policies and process designs for decision audit trails, human override mechanisms, model governance, and escalation when an automated decision must be reviewed.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (116, 'Adoption and change management plan', 'A structured plan covering communication, training, role changes, and the success metrics that confirm adoption is working after go-live.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (116, 'How much involvement does our team need during the design phase?', 'We run workshops in weeks one and two requiring your process owners, technology leads, and end-user representatives. Half-day availability across those sessions is typically sufficient. The DigitalQatalyst team handles design synthesis between workshops.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (116, 'How do you design for human oversight in automated workflows?', 'We identify the decision points in each workflow where the automated output must be reviewed by a human before acting. The design specifies the trigger conditions, the review interface, the time window, and the escalation path if a reviewer is unavailable.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (116, 'What if we do not have a preferred technology platform yet?', 'The design engagement includes technology alignment. The DigitalQatalyst team will map your requirements against appropriate platforms and provide a recommendation with rationale before the integration specification is written.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (116, 'How do we get started?', 'Share your prioritised use cases or your AI opportunity assessment with the DigitalQatalyst team. We will scope the design engagement and propose a workshop schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (117, 'Use-case feasibility assessment', 'Each AI use case scored and assessed against data readiness, technical complexity, responsible AI risk, and business value, with a build or defer recommendation and supporting rationale.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (117, 'Responsible AI workflow designs', 'Detailed workflow designs for each approved use case, specifying the bias controls, explainability hooks, human oversight points, and the actions to take when the model output falls below the agreed confidence threshold.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (117, 'Model and infrastructure specifications', 'Training data requirements, model type recommendations, compute and serving infrastructure specifications, and monitoring requirements for each approved use case.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (117, 'Governance and compliance mapping', 'A record of the governance controls and regulatory obligations that apply to each AI workflow, and the specific design decisions that address each one.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (117, 'How is this different from the standard design engagement?', 'The AI design engagement focuses specifically on AI and machine learning use cases. It adds a responsible AI layer covering bias, explainability, and oversight requirements, and produces model-level specifications rather than just workflow designs.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (117, 'What if our data is not ready for all the use cases we want to build?', 'That is the point of the feasibility assessment. Use cases that fail the data readiness check are deferred. The gap remediation plan tells you exactly what data improvements are needed and in what sequence to prioritise them.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (117, 'How do you handle sector-specific AI regulations?', 'The DigitalQatalyst team maps each workflow against the applicable regulations for your sector, identifies the specific obligations that apply, and designs the controls to meet them. The compliance mapping deliverable records every decision for your legal and risk teams.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (117, 'How do we get started?', 'Share your candidate AI use cases or your AI opportunity assessment with the DigitalQatalyst team. We will confirm scope, assess your starting position, and propose an engagement plan.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (118, 'Configured and tested AI and automation platform', 'Production capabilities live and integrated with your existing systems, tested against agreed acceptance criteria and confirmed ready for operational use.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (118, 'Integration test evidence pack', 'Test results for every integration point, with defects resolved and sign-off from your technical lead before any capability goes live.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (118, 'Operations and incident runbook set', 'Step-by-step runbooks for monitoring the deployed capabilities, triaging incidents, handling exceptions, and managing scheduled maintenance.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (118, 'Handover and training pack', 'Role-based training materials, administrator guides, and a competency sign-off confirming your teams can operate and maintain the capabilities independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (118, 'How do you manage integration with legacy systems?', 'Integration patterns and constraints are identified during the design phase. During deployment, the DigitalQatalyst team builds and tests each integration point against agreed specifications, with a formal defect resolution process before sign-off.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (118, 'What if a workflow does not perform as expected during user acceptance testing?', 'UAT findings are classified by severity. Blockers are resolved before launch. Non-blocking findings are documented and addressed in a post-launch remediation sprint included within the engagement scope.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (118, 'How do you prepare end users for automated workflows that change how they work?', 'The change management plan from the design phase drives the training schedule. We run role-based training sessions during weeks ten and eleven, with materials left in place for ongoing onboarding.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (118, 'How do we get started?', 'Provide your completed AI and automation design specifications to the DigitalQatalyst team. We will confirm the delivery scope, agree integration priorities, and schedule a kick-off.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (119, 'Production AI deployment', 'AI capabilities live in production with model versioning, staged rollout controls, and rollback capability confirmed working before any model handles live decisions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (119, 'Monitoring and alerting platform', 'Real-time dashboards and alert configurations for model performance, input drift, prediction distribution, and infrastructure health.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (119, 'Audit and traceability controls', 'Complete audit logs covering model predictions, confidence scores, human review outcomes, and model version history, meeting the audit requirements of your governance framework.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (119, 'AI operations handover pack', 'Retraining triggers, model lifecycle management procedures, incident playbooks, and a sign-off checklist confirming your team can manage the AI capabilities independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (119, 'What is a shadow period and why does it matter?', 'During the shadow period, the AI produces outputs in parallel with your existing process without acting on them. Your team reviews the outputs against known outcomes to confirm the model is reliable before it takes over the decision.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (119, 'How do you handle model retraining in production?', 'The handover pack includes documented retraining triggers based on drift thresholds or scheduled frequency, the steps to retrain safely, and the validation checks that must pass before the retrained model replaces the current version.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (119, 'What audit evidence does the deployment produce?', 'Every model prediction is logged with its input features, confidence score, output, and the human review outcome where applicable. The audit log is queryable and retained for the period your governance framework requires.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (119, 'How do we get started?', 'Share your completed AI design specifications with the DigitalQatalyst team. We will confirm infrastructure requirements, validate the governance controls to implement, and agree a deployment schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (120, 'Monthly AI operations report', 'A performance view covering model accuracy, drift indicators, prediction volumes, incident history, and any retraining events completed during the month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (120, 'Incident log and resolution record', 'A complete log of every model degradation event, alert, or incident, with time to detect and resolve, root cause, and the preventive action applied.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (120, 'Quarterly model review', 'An assessment of each model''s performance trend, retraining schedule, and fitness for continued production use, with recommendations for upgrades or retirement.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (120, 'Governance compliance report', 'A periodic confirmation that audit logging, access controls, human oversight procedures, and responsible AI requirements remain active and compliant with your governance framework.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (120, 'What SLAs apply to AI model incidents?', 'SLAs are agreed during onboarding and cover time to detect a degradation alert, time to notify the relevant team, and time to resolve or escalate by severity. Performance against SLAs is reported monthly.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (120, 'How do you decide when a model needs retraining?', 'Retraining triggers are defined in the handover documentation from the deployment engagement. The DigitalQatalyst team monitors the agreed drift and performance thresholds and initiates retraining when a trigger is met, following the validated retraining procedure.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (120, 'What happens when a regulation changes and affects our AI governance requirements?', 'Regulatory changes relevant to your AI capabilities are flagged in the quarterly governance review. The DigitalQatalyst team will assess the impact on your current controls and recommend changes, which are then handled as a managed change request.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (120, 'How do we get started?', 'The managed service follows a completed AI deployment. Contact the DigitalQatalyst team to discuss transition planning, agree SLAs, and define the service catalogue for your AI capabilities.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (121, 'Technology governance maturity report', 'Scored assessment across portfolio management, architecture standards, vendor governance, and delivery controls, with evidence and specific gaps documented.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (121, 'Investment and portfolio control findings', 'Analysis of where technology spend is poorly governed, misaligned to strategy, or lacking accountability, with specific improvement recommendations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (121, 'Architecture standards gap analysis', 'Documented drift from agreed standards, concentration of technical debt, and non-standard choices creating future integration or compliance risk.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (121, 'Prioritised improvement roadmap', 'Sequenced actions across governance dimensions, with effort estimates and dependencies framed for CIO and board-level decision-making.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (121, 'What does the maturity model cover?', 'The assessment covers four dimensions: technology portfolio and investment governance, enterprise architecture standards and compliance, vendor and third-party oversight, and delivery and programme governance. The DigitalQatalyst team confirms which are in scope during the kick-off.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (121, 'What documentation do you need from us?', 'Portfolio records, architecture principles documents, vendor contracts, and delivery governance artefacts such as project status reports or gate review outputs. Gaps in documentation are themselves findings.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (121, 'How is the maturity model calibrated to our organisation?', 'The DigitalQatalyst team aligns the scoring model to your organisation''s size, sector, and regulatory context in the first day of the engagement so findings are relevant rather than generic.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (121, 'Can this support a broader digital or IT transformation programme?', 'Yes. The roadmap is designed to feed directly into transformation planning, enterprise architecture reviews, or an operating model redesign.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (121, 'How do we get started?', 'Request a consultation with the DigitalQatalyst team. We confirm scope, maturity model, and stakeholder availability before the engagement begins.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (122, 'Technology governance operating model', 'Documented decision rights, governance bodies, meeting cadences, escalation paths, and accountabilities across portfolio, architecture, vendor, and delivery governance.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (122, 'Architecture review board design', 'Membership, mandate, decision criteria, review process, and exception procedures for your architecture governance function, ready to stand up.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (122, 'Portfolio governance process specifications', 'Investment approval workflows, prioritisation criteria, performance tracking templates, and reporting formats for your technology portfolio function.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (122, 'Implementation handover package', 'Role descriptions, templates, tooling recommendations, and an adoption plan sequenced to minimise disruption to current delivery programmes.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (122, 'Do we need an assessment before starting the design?', 'An assessment provides the evidence base for design priorities. Existing audit findings, architecture reviews, or previous governance reports can substitute if a fresh assessment has not been run.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (122, 'How do you design governance that works with our existing structures?', 'The design phase begins with a current-state review. The DigitalQatalyst team maps existing committees, forums, and reporting lines before designing the new model so it complements rather than conflicts with what already works.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (122, 'Can the design be implemented in phases?', 'Yes. The implementation handover package includes a phased adoption plan sequenced by impact and readiness. Quick-win governance changes are separated from longer-term structural redesigns.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (122, 'What tooling do you recommend for technology governance?', 'Tooling recommendations are included in the handover package, covering portfolio management platforms, architecture repository tools, and reporting tooling. The DigitalQatalyst team aligns recommendations to your existing technology estate.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (122, 'How do we get started?', 'Book a scoping call with the DigitalQatalyst team. We review your current governance maturity, objectives, and any existing documentation before confirming the design scope.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (123, 'AI use-case register for technology governance', 'Validated use cases for AI in portfolio management, architecture review, vendor oversight, and delivery governance, each assessed for feasibility and regulatory compatibility.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (123, 'Responsible AI assessment', 'Documented findings on data quality, bias risk, explainability requirements, and applicable AI regulations for each prioritised use case.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (123, 'AI workflow designs', 'End-to-end workflow specifications showing how AI outputs integrate into governance decision points, with human-in-the-loop controls at each critical step.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (123, 'Deployment specification package', 'Technical and governance requirements for each approved use case, including model criteria, data pipelines, guardrails, and monitoring configurations.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (123, 'What AI use cases apply to technology governance?', 'Common validated use cases include portfolio health analytics, architecture compliance drift detection, vendor risk scoring from contract and performance data, and delivery performance prediction. The DigitalQatalyst team works with your governance context to prioritise.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (123, 'What data do you need access to during the design phase?', 'Data inventories, schema documentation, and sample datasets for feasibility assessment. No production data is processed during design; the engagement works from specifications and representative samples.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (123, 'How do you assess responsible AI risk for governance functions?', 'The assessment covers decision significance, explainability obligations, data provenance, and the consequences of model error in each governance context. High-risk decision points automatically require human-in-the-loop controls in the workflow design.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (123, 'Do we need an existing technology governance model before this engagement?', 'A functioning governance model makes use-case identification more precise, but the DigitalQatalyst team can run this engagement alongside a governance design phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (123, 'How do we get started?', 'Request a consultation with the DigitalQatalyst team. We will review your current governance tooling, data landscape, and AI objectives before confirming the scope.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (124, 'Configured technology governance platform', 'Portfolio management, architecture repository, or governance tooling fully configured to your operating model, with all agreed integrations live and reporting automated.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (124, 'Data integration documentation', 'Documented connections between governance tooling and portfolio, financial, vendor, and architecture data sources, with data flow diagrams and refresh schedules.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (124, 'Process activation evidence', 'Records of architecture review board, portfolio governance, and vendor oversight processes tested and signed off by your governance stakeholders.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (124, 'Operational handover package', 'Runbooks, administrator guides, training materials, and a first-cycle governance calendar so your teams operate without dependency on the DigitalQatalyst team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (124, 'Which governance platforms can you configure?', 'Planview, ServiceNow IT Business Management, LeanIX, Ardoq, and portfolio management tooling in Microsoft or Atlassian ecosystems. Platform selection is confirmed during pre-deployment scoping with the DigitalQatalyst team.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (124, 'What data sources do you typically integrate?', 'Financial systems for investment data, project management tools for delivery status, architecture repositories, vendor contract management systems, and HR systems for resource data. Integration scope is confirmed in week one.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (124, 'How do you handle governance process changes mid-deployment?', 'A change control process is established in week one. Minor changes are absorbed; significant scope changes are assessed and agreed before implementation to protect the timeline.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (124, 'What is the first governance cycle output we will see?', 'By the end of week twelve your portfolio reporting, architecture review calendar, and vendor oversight process will have completed their first cycle, producing real governance outputs rather than test artefacts.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (124, 'How do we get started?', 'Share your governance design specification and the DigitalQatalyst team will scope the deployment in detail and confirm the timeline within five working days.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (125, 'Production AI deployment for technology governance', 'AI models live in your environment, connected to portfolio, architecture, and vendor data sources, processing recommendations within agreed accuracy and latency thresholds.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (125, 'Human-in-the-loop workflow documentation', 'Configured approval checkpoints, escalation paths, and override procedures for each AI-supported governance decision, documented for audit and regulatory review.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (125, 'Governance AI monitoring dashboard', 'Real-time view of model outputs, recommendation volumes, acceptance rates, and governance decision outcomes with configurable thresholds and alerting.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (125, 'Operations and retraining guide', 'Step-by-step procedures for your governance teams to manage model performance, trigger retraining cycles, and document AI-influenced decisions for audit purposes.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (125, 'Which AI use cases can you put into production for technology governance?', 'Portfolio health analytics, architecture compliance drift detection, vendor risk scoring, and delivery performance prediction are the most common production deployments. The DigitalQatalyst team builds from your validated AI design specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (125, 'How do you ensure AI does not make governance decisions without approval?', 'Human-in-the-loop checkpoints are configured before production cutover. Every AI recommendation that influences a governance decision routes to a named accountable leader for approval. The approval audit trail is maintained in the governance platform.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (125, 'What happens if a model recommendation is consistently wrong?', 'The monitoring dashboard surfaces acceptance rates and override frequencies weekly. The operations guide includes retraining triggers and the DigitalQatalyst team provides hypercare support during the first two weeks post-launch.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (125, 'Do we need AI design specifications before this engagement?', 'Yes. The AI Deploy engagement builds directly from specifications produced in an AI Design phase. If those are not complete, the DigitalQatalyst team can run a combined design and deployment programme.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (125, 'How do we get started?', 'Share your AI design specifications and the DigitalQatalyst team will confirm environment readiness, integration requirements, and the deployment schedule within one week.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (126, 'Monthly technology portfolio report', 'Structured report covering investment alignment, delivery performance, risk indicators, and exception items, formatted for CIO and board-level review.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (126, 'Quarterly architecture review report', 'Assessment of architecture standards compliance, technical debt trends, non-standard exception status, and recommended actions for your enterprise architecture function.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (126, 'Vendor performance and risk summary', 'Ongoing view of vendor contract performance, risk indicators, upcoming renewals, and escalation items requiring CIO or commercial team attention.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (126, 'Governance optimisation recommendations', 'Quarterly recommendations for process improvements, tooling enhancements, or governance model adjustments based on performance data and changes in your technology landscape.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (126, 'What does the monthly managed service include?', 'Continuous portfolio and investment monitoring, a monthly performance report for CIO and board use, ongoing vendor oversight, and escalation support for governance issues requiring executive attention.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (126, 'How are architecture reviews structured in the managed service?', 'Quarterly architecture review cycles cover standards compliance, technical debt trends, and outstanding non-standard exceptions. Results feed into the quarterly governance performance review with your CIO and architecture leaders.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (126, 'Can the managed service adapt as our technology strategy changes?', 'Yes. Scope and reporting are reviewed quarterly. Changes to portfolio scope, new governance domains, or revised strategic priorities are incorporated through a change request without disrupting ongoing operations.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (126, 'How do you handle a governance escalation or investment decision under time pressure?', 'The DigitalQatalyst team provides named points of contact for escalations. Response SLAs are defined by issue severity. For investment decisions, the team can produce targeted analysis within agreed timescales to support the decision-making process.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (126, 'How do we get started?', 'The DigitalQatalyst team runs a two-week onboarding to establish governance baselines, confirm SLAs, connect monitoring tooling, and set the governance calendar before steady-state operations begin.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (127, 'DevSecOps maturity assessment', 'Ratings across pipeline automation, security integration, test coverage, and release reliability, with evidence and specific gaps for each dimension.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (127, 'Security control gap report', 'Missing or misconfigured controls in SAST, DAST, dependency scanning, secrets detection, and container security, ranked by exploitability.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (127, 'Delivery velocity baseline', 'Current lead time, deployment frequency, change failure rate, and mean time to restore, with analysis of the pipeline stages causing the most drag.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (127, 'Prioritised remediation roadmap', 'Sequenced actions addressing the highest-risk gaps first, with effort estimates and the expected improvement in release quality and speed.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (127, 'Which pipelines and platforms does the assessment cover?', 'Any CI/CD toolchain: GitHub Actions, GitLab CI, Jenkins, Azure DevOps, and others. The DigitalQatalyst team confirms scope during the initial scoping call.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (127, 'Do you need access to our source code?', 'We review pipeline configuration, scan results, and deployment logs. Source code access is not required unless specific vulnerability patterns need tracing.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (127, 'What do we get at the end?', 'A maturity assessment, a security control gap report, a velocity baseline, and a prioritised remediation roadmap.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (127, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm which pipelines and teams are in scope before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (128, 'Pipeline architecture blueprint', 'End-to-end design of your CI/CD stages including trigger logic, parallelisation, caching strategy, and failure-handling patterns.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (128, 'Security toolchain specification', 'Tools, scan configurations, threshold policies, and integration patterns for every security gate in the pipeline.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (128, 'Workflow and governance design', 'Branch strategy, environment promotion rules, approval gates, and audit trail requirements documented for implementation.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (128, 'Developer adoption plan', 'Training approach, inner-loop tooling recommendations, and rollout phasing to minimise disruption to active delivery teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (128, 'Can we keep our existing CI/CD platform?', 'Yes. The design is built around your current toolchain wherever it meets requirements. Replacements are only recommended where existing tools create unresolvable gaps.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (128, 'How do you balance security controls with developer speed?', 'Security gates are designed to run in parallel where possible and block only on critical findings. The developer experience plan ensures controls add minimal friction to the inner loop.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (128, 'How do we get started?', 'Contact the DigitalQatalyst team to share your current pipeline inventory and confirm which teams and platforms are in scope for the design.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (129, 'AI use-case feasibility register', 'Each candidate scored on data availability, toolchain compatibility, and expected quality or velocity improvement, with a clear go or no-go recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (129, 'Pipeline signal readiness report', 'Assessment of existing telemetry, scan outputs, and historical data quality against the inputs each AI model requires.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (129, 'Responsible DevSecOps AI workflows', 'Designed flows for approved use cases with human review gates, confidence thresholds, and audit logging at every decision point.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (129, 'Deployment and monitoring specification', 'Model selection guidance, performance baselines, drift detection thresholds, and feedback loop design for production use.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (129, 'Which AI use cases are most commonly explored?', 'AI-assisted code review, ML-based vulnerability prioritisation, predictive test selection to reduce pipeline duration, and anomaly detection on deployment telemetry.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (129, 'What if our pipeline telemetry is incomplete?', 'The signal readiness report identifies specific gaps. Organisations often start with lower-data-demand use cases while building telemetry coverage in parallel.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (129, 'How do you ensure AI recommendations do not block releases incorrectly?', 'Confidence thresholds, human override gates, and fallback logic are designed into every workflow so false positives never silently block deployments.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (129, 'How do we get started?', 'Book a consultation with the DigitalQatalyst team to identify your highest-value AI use cases and share current pipeline telemetry and toolchain details.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (130, 'Production DevSecOps pipeline', 'Fully configured CI/CD pipeline with security gates, test automation, environment promotion, and deployment controls live in your production environment.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (130, 'Security gate validation report', 'Evidence that each security control is running correctly, policies are enforced, and critical findings are blocking promotion as designed.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (130, 'Engineering onboarding kit', 'Pipeline documentation, developer quick-start guide, and runbooks for common operations and incident scenarios.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (130, 'Operational handover pack', 'Support contacts, escalation paths, known-issues register, and a 30-day post-launch review schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (130, 'Can we run the new pipeline alongside existing pipelines during transition?', 'Yes. The deployment plan includes a parallel-run period where both pipelines operate so teams can validate the new configuration before cutting over.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (130, 'How do security policies get agreed before implementation?', 'The DigitalQatalyst team runs a policy alignment session in the first two weeks with engineering and security stakeholders to agree scan thresholds and blocking rules.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (130, 'What happens if a security control creates too many false positives?', 'Policy tuning is included within the deployment scope. Thresholds are adjusted iteratively during the integration testing phase before go-live.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (130, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved pipeline design to plan toolchain access, environment scope, and team onboarding schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (131, 'Production AI pipeline capabilities', 'Approved models live in your CI/CD pipeline with telemetry ingestion, result logging, and developer-facing interfaces active.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (131, 'Model performance dashboard', 'Real-time view of recommendation accuracy, false-positive rates, pipeline duration impact, and alert thresholds for your platform team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (131, 'Override and feedback playbook', 'Developer procedures for overriding AI recommendations, submitting false-positive reports, and escalating model quality concerns.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (131, 'AI governance handover pack', 'Model cards, telemetry lineage, retraining schedule, and accountability assignments for ongoing responsible operation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (131, 'How do developers interact with AI recommendations in the pipeline?', 'Recommendations appear in pull request comments or pipeline dashboards, with one-click override and a mandatory reason field that feeds the model''s improvement loop.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (131, 'What happens if AI vulnerability prioritisation produces too many false positives?', 'Threshold adjustment is included in the deployment. The monitoring dashboard surfaces false-positive rates, and the DigitalQatalyst team tunes thresholds before full rollout.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (131, 'How do you maintain model accuracy as the codebase evolves?', 'Retraining triggers and schedules are defined in the governance handover pack. Model drift alerts notify the DigitalQatalyst team and your platform leads when retraining is needed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (131, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved AI design specification to plan the production environment, telemetry access, and pilot team selection.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (132, 'Monthly delivery and security report', 'DORA metrics, security finding volumes and age, policy exception counts, and pipeline health summary with recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (132, 'Incident and change log', 'Transparent record of pipeline incidents, policy changes, and SLA performance across each reporting period.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (132, 'Quarterly pipeline optimisation review', 'Analysis of stage durations, flaky test trends, and security tool false-positive rates, with prioritised improvement actions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (132, 'Annual pipeline roadmap', 'Forward-looking plan covering toolchain updates, new security integrations, and scalability improvements to support engineering growth.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (132, 'What is covered under the managed service?', 'Pipeline monitoring, incident response, policy and configuration updates, monthly reporting, and quarterly optimisation. Full scope is confirmed in the service agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (132, 'Can you manage pipelines across multiple cloud environments?', 'Yes. Multi-cloud and hybrid pipeline environments are in scope. The DigitalQatalyst team confirms the environment inventory during onboarding.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (132, 'How are security policy changes handled when compliance requirements change?', 'Policy update requests are assessed, implemented in a staging pipeline, validated, and promoted to production within the agreed change management process.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (132, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the pipelines, toolchains, and SLA requirements in scope before the service agreement is drafted.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (133, 'IT operations maturity scorecard', 'Ratings across incident management, change control, monitoring coverage, and automation maturity, each supported by evidence from your actual service desk and operations data.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (133, 'Incident and repeat failure analysis', 'Root-cause patterns behind your highest-volume and longest-duration incidents, with specific recommendations for eliminating repeat failures and reducing mean time to resolution.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (133, 'Change control risk assessment', 'Evaluation of your change management process against the frequency, impact, and rollback capability of recent changes, with recommendations for improving control without slowing delivery.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (133, 'Prioritised IT improvement roadmap', 'Sequenced actions covering process, tooling, and automation improvements, with effort scores so your IT leadership can plan the next phase around existing operational commitments.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (133, 'Which ITSM platforms do you assess?', 'The DigitalQatalyst team works across ServiceNow, Jira Service Management, BMC Helix, Freshservice, and other platforms. Scope is confirmed during the initial consultation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (133, 'What data do you need from us?', 'Incident, change, and problem ticket data for the previous 6-12 months, monitoring alert logs, and any existing runbooks or process documentation. No access to production systems is required for the assessment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (133, 'Can this assessment cover both on-premises and cloud operations?', 'Yes. The operational scope, including on-premises, cloud, or hybrid environments, is confirmed during the consultation and the assessment is tailored accordingly.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (133, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm data requirements, operational scope, and stakeholder participants before the engagement begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (134, 'ITSM process design', 'Defined workflows for incident, problem, change, and request management, covering roles, decision points, SLA tier assignments, and escalation paths tailored to your operational environment.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (134, 'Automation workflow specifications', 'Detailed designs for automated alert triage, ticket enrichment, routing logic, and routine resolution playbooks, with the trigger conditions, data requirements, and fallback paths for each.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (134, 'Monitoring and observability architecture', 'Coverage design for your infrastructure and application stack, defining what to monitor, alert thresholds, noise reduction rules, and the dashboards your operations team needs for effective incident response.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (134, 'Tooling integration and adoption plan', 'Integration specifications for ITSM, monitoring, asset, and CI/CD connections, plus an adoption plan covering training outlines, change communication, and go-live readiness criteria.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (134, 'Does the design cover both reactive incident management and proactive problem management?', 'Yes. Problem management process design, including root-cause analysis workflows and known error management, is included alongside the reactive incident procedures.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (134, 'Can the design accommodate a DevOps or SRE working model?', 'Yes. The DigitalQatalyst team can design ITSM processes that integrate with DevOps delivery pipelines and align with SRE practices, including error budget and reliability target definitions.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (134, 'How do you handle regulatory or compliance requirements for IT change control?', 'Compliance requirements, such as change freezes, approval audit trails, and segregation of duties, are addressed in the change management process design and the tooling integration specifications.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (134, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team reviews your current ITSM platform and operational environment, then confirms the stakeholders needed for design workshops.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'AI use-case scorecard for IT operations', 'Each candidate use case rated by operational impact, data feasibility, risk, and implementation complexity, with a clear build recommendation and the sequencing rationale.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'Responsible AI workflow designs', 'Workflow diagrams for each validated use case showing AI decision points, human approval gates, rollback triggers, blast-radius limits, and the conditions under which automated remediation is prohibited.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'Operational data readiness report', 'Assessment of your monitoring, log, and ITSM data against the requirements of each validated AI use case, with specific data improvement actions needed before build can begin.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'Technical deployment specification', 'Model inputs, outputs, ITSM and monitoring integration requirements, infrastructure needs, and the acceptance criteria for validating AI performance in a staging environment before production.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'Which AI use cases are most commonly validated for IT operations?', 'Intelligent alert correlation and noise reduction, anomaly detection for infrastructure metrics, predictive disk and capacity failure, and automated safe remediation playbooks are the most frequently scoped. The DigitalQatalyst team validates each against your specific operational data.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'How do you ensure AI remediation cannot cause a wider outage?', 'Blast-radius limits and scope boundaries are core design requirements, not optional additions. Every automated remediation workflow specifies what the AI is permitted to do, the conditions that must be true before action is taken, and the rollback trigger if the action does not produce the expected result.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'What monitoring data do we need before AI design is viable?', 'The data readiness assessment evaluates your monitoring coverage, log retention, and alert history. Gaps are identified with specific remediation steps. Many organisations find targeted monitoring improvements take weeks rather than months.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team reviews your ITSM platform, monitoring stack, and operational data landscape to shape the engagement scope.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (136, 'Configured ITSM environment', 'Fully built incident, change, problem, and request management workflows, routing rules, SLA configurations, and permission sets, validated in a staging environment before production promotion.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (136, 'Monitoring and alerting validation report', 'Evidence that monitoring covers the agreed infrastructure and application scope, alert thresholds produce the expected signals, and noise reduction rules are functioning correctly.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (136, 'Integration test evidence pack', 'Test scenarios and results for every ITSM integration, covering data synchronisation, trigger accuracy, and error handling across monitoring, asset management, and CI/CD connections.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (136, 'IT operations handover pack', 'Administrator guides, runbook library, escalation contacts, and a 30-day post-launch review schedule so your team owns the platform and processes from day one.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (136, 'How is monitoring coverage validated?', 'The DigitalQatalyst team runs a coverage validation against the agreed scope, confirming that each in-scope system and application is instrumented, alert thresholds produce the expected response, and noise reduction rules reduce false positives before go-live.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (136, 'What happens to open incidents and change requests at cutover?', 'Open ticket migration is planned and tested before cutover. The DigitalQatalyst team produces a cutover playbook covering data migration steps, rollback triggers, and the communication plan for operations staff.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (136, 'Can we continue using the existing ITSM during the build period?', 'Yes. The cutover is planned to minimise disruption to live operations. Parallel running options and low-risk migration windows are agreed during planning.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (136, 'How do we get started?', 'Share your approved design specifications and the DigitalQatalyst team will confirm scope, platform configuration approach, and a delivery timeline.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (137, 'Production AI deployment for IT operations', 'AI capabilities fully integrated into your ITSM and monitoring environment, validated against detection accuracy, automated resolution success rates, and the agreed safety acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (137, 'Safety control validation report', 'Evidence that blast-radius limits, human approval gates, and rollback triggers operate correctly across representative production scenarios before the capability goes live.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (137, 'AI operations dashboard and alerting', 'Real-time visibility into model detection accuracy, false positive and negative rates, automated resolution outcomes, and the alert rules that notify your team when AI performance moves outside agreed thresholds.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (137, 'Operations runbook and training record', 'Step-by-step procedures for AI monitoring, incident response, model performance review, and escalation, with confirmed training completion for operations engineers and team leads.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (137, 'How do you test that automated remediation cannot cause a wider outage?', 'The DigitalQatalyst team runs blast-radius tests in the staging environment, simulating remediation actions across representative failure scenarios to confirm that scope limits, rollback triggers, and human approval gates operate correctly before any production deployment.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (137, 'Can AI capabilities be deployed to non-critical systems first?', 'Yes. Staged rollout by system criticality or environment type is the standard approach, allowing the operations team to build confidence and refine thresholds before the AI manages business-critical infrastructure.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (137, 'How will our engineers know what the AI has done and why?', 'Every AI action is logged to the ITSM platform with the trigger condition, the action taken, the outcome, and the confidence level. Engineers have full audit trail access and the AI operations dashboard provides a real-time summary view.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (137, 'How do we get started?', 'Provide your approved AI design specifications and the DigitalQatalyst team will confirm infrastructure requirements, safety control specifications, and the production deployment schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (138, 'Monthly IT operations performance report', 'Incident volumes, resolution times, SLA compliance by tier, change success rates, and automation health, with commentary on trends and the next period optimisation priorities.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (138, 'Problem management and trend analysis report', 'Root-cause patterns behind repeat incidents, the problem records raised, and the improvement actions taken or recommended to eliminate recurring failures.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (138, 'ITSM platform change and update record', 'Documentation of all ITSM updates applied, regression tests completed, and any issues resolved before changes were promoted to the production environment.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (138, 'Quarterly IT service review', 'A structured assessment of IT operations performance against your agreed service objectives, incorporating business volume changes, new service onboardings, and emerging operational risks.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (138, 'Does the managed service cover problem management as well as incidents?', 'Yes. Problem management is an active part of the service. The DigitalQatalyst team identifies repeat failure patterns from monthly incident data, raises problem records, and tracks improvement actions to resolution.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (138, 'Can we request ITSM configuration changes within the managed service?', 'Yes. A defined change request allowance is included each month. Larger structural changes are assessed and agreed separately so you remain in control of scope and investment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (138, 'How do you manage the service if we have an in-house IT operations team?', 'The DigitalQatalyst team operates as an extension of your team. Responsibility boundaries, escalation paths, and communication channels are agreed during onboarding and documented in the service agreement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (138, 'How do we get started?', 'Request an onboarding call. The DigitalQatalyst team reviews your current ITSM environment, agrees the service baseline and SLA framework, and confirms the first reporting cycle.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Farming operations maturity scorecard', 'Ratings across yield tracking, resource management, planning accuracy, and equipment utilisation, with evidence and specific gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Operational gap register', 'Documented gaps in crop monitoring, irrigation scheduling, input management, and harvest coordination, ranked by cost and yield impact.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Prioritised improvement roadmap', 'Sequenced actions with owners, effort estimates, and dependencies your operations team can act on from the first season.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Leadership briefing pack', 'A concise summary of findings and recommended investment for agribusiness and farm operations leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (149, 'What farming models does the assessment cover?', 'Broadacre cropping, horticulture, livestock, and mixed operations. The DigitalQatalyst team confirms the applicable model during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (149, 'Do you need access to our farm management systems?', 'We review system outputs and operational records rather than live data. Any access required is read-only and agreed in advance.', 1);
