INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (151, 'Agricultural AI use-case feasibility register', 'Each candidate scored on data availability, model complexity, and expected yield or cost improvement, with a clear go or no-go recommendation.', 0);
