INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (165, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved AI design specification to plan the production environment, sensor pipeline access, and pilot asset class selection.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (166, 'Monthly asset health and maintenance report', 'Planned versus reactive maintenance ratios, work order completion rates, asset condition trends, and system health metrics with recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (166, 'Incident and change log', 'Transparent record of platform incidents, configuration changes, and SLA performance across each reporting period.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (166, 'Quarterly infrastructure optimisation review', 'Analysis of maintenance scheduling accuracy, field workforce productivity, and asset reliability trends with prioritised improvement actions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (166, 'Annual infrastructure technology roadmap', 'Forward-looking plan covering platform updates, new asset class integrations, and capability additions aligned to portfolio strategy and regulatory obligations.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'What is covered under the managed service?', 'Platform monitoring, incident response, configuration updates, monthly reporting, and quarterly optimisation reviews. Full scope is confirmed in the service agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'How are regulatory compliance updates to maintenance standards handled?', 'Compliance-driven configuration changes are assessed, implemented in a test environment, validated, and promoted to production within the agreed change management process.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'Can the service scale to cover additional asset classes or new sites?', 'Yes. New asset classes and sites are onboarded under the service. Large portfolio expansions are scoped and priced separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the EAM platform, asset portfolio scope, and SLA requirements before the service agreement is drafted.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (167, 'Government operations maturity scorecard', 'Ratings across citizen service delivery, back-office processing, cross-agency coordination, and transparency controls, with evidence and specific gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (167, 'Service delivery gap report', 'Documented process bottlenecks, coordination failures, and compliance control gaps ranked by citizen impact and operational risk.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (167, 'Prioritised improvement roadmap', 'Sequenced actions with named owners, effort estimates, and dependencies your programme team can act on within normal governance cycles.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (167, 'Leadership and ministerial briefing pack', 'A concise summary of findings and recommended investment for digital government and programme leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (167, 'Which government functions does the assessment cover?', 'The scope is confirmed with your programme leads before engagement. Common areas include licensing, grants, permits, benefits processing, and case management.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (167, 'Do you need access to case management or citizen data systems?', 'We review process documentation and system outputs rather than live citizen data. Any access required is read-only, data-minimised, and agreed with your data governance lead in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (167, 'What do we get at the end?', 'A maturity scorecard, a service delivery gap report, a prioritised improvement roadmap, and a leadership briefing pack.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (167, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the services and functions in scope, data access constraints, and key stakeholders before work begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Citizen journey maps', 'End-to-end service flows from initial application through processing, decision, notification, and appeals across all in-scope government services.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Back-office workflow specification', 'Approval queues, case assignment rules, compliance check procedures, and audit trail requirements documented for configuration and development teams.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Cross-agency integration design', 'Data sharing patterns, referral workflow logic, and privacy compliance controls for all inter-agency touchpoints in scope.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Public sector adoption plan', 'Phased rollout sequence with staff training requirements by role, accessibility compliance checklist, and service continuity plan during transition.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (168, 'How do you ensure the design meets accessibility obligations?', 'Accessibility requirements are incorporated from the first workshop. The DigitalQatalyst team aligns designs to the applicable standard, such as WCAG 2.1 AA, and documents compliance evidence.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (168, 'How are citizens involved in the design process?', 'Where the programme governance permits, representative citizen research or usability review is incorporated to validate that service journeys work for the intended audience.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (168, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the services and functions in scope, the platforms in use, and any procurement or governance constraints before the engagement begins.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (169, 'Government AI use-case feasibility register', 'Each candidate scored on data availability, regulatory permissibility, and expected service quality or processing efficiency improvement, with a go or no-go recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (169, 'Government data readiness report', 'Gaps in case management data quality, document classification coverage, and inter-agency sharing agreements that must be resolved before model development.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (169, 'Responsible government AI workflows', 'Designed flows for approved use cases with case officer review points, citizen-facing explainability, appeal rights preserved, and audit logging at every decision point.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (169, 'Public sector AI deployment specification', 'Model selection guidance, bias testing requirements, performance thresholds, audit log design, and accountability assignments aligned to applicable public sector AI policy.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (169, 'Which AI use cases are most commonly explored in government?', 'Automated eligibility pre-screening, intelligent document classification, risk-based case prioritisation, and back-office processing queue optimisation are the most common starting points.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (169, 'How do you handle the legal and policy requirements for automated government decisions?', 'Accountability, explainability, and citizen appeal rights are designed into every workflow from the start. The DigitalQatalyst team confirms the applicable legal framework during scoping.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (169, 'What if citizen data cannot be used for AI model training?', 'Synthetic data, anonymised record sets, and privacy-preserving training techniques are explored during the data readiness phase. Use cases requiring live citizen data are flagged for separate legal review.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (169, 'How do we get started?', 'Book a consultation with the DigitalQatalyst team to identify your highest-value AI use cases and confirm data availability, legal constraints, and programme governance requirements.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (170, 'Configured government operations platform', 'Production-ready citizen service portal, back-office case management, and cross-agency integration configured and tested against approved specifications.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (170, 'Integration test evidence pack', 'Test cases, results, and defect closure evidence for every connected system including identity platforms, document management, and inter-agency data exchanges.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (170, 'Staff acceptance sign-off', 'Documented UAT results from front-line staff, case officers, and supervisors confirming the platform meets service delivery requirements and accessibility obligations.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (170, 'Operational handover kit', 'Administrator guides, service manager quick-start pack, support escalation paths, compliance audit trail documentation, and a 30-day post-launch review schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (170, 'How do you handle legacy system migration within government environments?', 'Data migration plans are agreed with your data governance and records management leads. Migration is staged and validated before cutover to avoid service disruption.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (170, 'How is security clearance managed for team members working on the deployment?', 'The DigitalQatalyst team confirms security clearance requirements during scoping. Members working on sensitive environments are cleared or matched to the required level.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (170, 'What happens if integration testing reveals issues with a third-party government system?', 'Issues are documented and raised with the relevant system owner through your programme governance process. Workarounds are designed where the third-party timeline cannot be aligned.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (170, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the platform, integration scope, security requirements, and public sector procurement constraints before deployment planning begins.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (171, 'Production government AI capabilities', 'Approved models live in your government operations platform with data pipelines, decision logging, and case officer-facing recommendation interfaces active.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (171, 'Service performance monitoring dashboard', 'Real-time view of model accuracy, case officer override rates, processing time improvement, and bias indicators by service line and demographic group.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (171, 'Case officer override and appeal playbook', 'Procedures for accepting, overriding, and escalating AI recommendations, with citizen explanation and appeal right documentation for each service.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (171, 'Public sector AI governance handover pack', 'Model cards, data lineage documentation, bias testing records, quarterly accountability review schedule, and accountability assignments for ongoing responsible operation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (171, 'How do case officers override AI recommendations?', 'Override controls are built into the case management interface. All overrides are logged with a reason and reviewed in the quarterly accountability session.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (171, 'How do you monitor for bias in AI-assisted government decisions?', 'Demographic group outcome analysis runs continuously in the monitoring dashboard. Disparity alerts trigger immediate review and, where needed, model adjustment before the next processing cycle.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (171, 'What happens if AI recommendations are challenged through a citizen appeal?', 'Decision logs, model outputs, and case officer actions are retrievable through the audit trail to support the appeals process. The accountability playbook covers the specific steps for each service.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (171, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved AI design specification to plan the production environment, data pipeline access, and pilot service line selection.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (172, 'Monthly government service performance report', 'Processing times, case resolution rates, citizen satisfaction indicators, compliance control status, and system health metrics with recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (172, 'Incident and change log', 'Transparent record of platform incidents, policy-driven configuration changes, and SLA performance across each reporting period.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (172, 'Quarterly service optimisation review', 'Analysis of processing backlogs, case management bottlenecks, and compliance control gaps with prioritised improvement actions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (172, 'Annual government technology roadmap', 'Forward-looking plan covering platform updates, new service integrations, and capability additions aligned to digital government strategy and legislative obligations.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (172, 'What is covered under the managed service?', 'Platform monitoring, incident response, policy-driven configuration updates, monthly reporting, and quarterly optimisation reviews. Full scope is confirmed in the service agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (172, 'How quickly can configuration changes be made when policy or legislation changes?', 'The DigitalQatalyst team assesses change impact, agrees a timeline with your programme lead, and implements within your change management process. Emergency legislative changes are handled under a priority change procedure.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (172, 'Can the service support new citizen-facing services added to the platform over time?', 'Yes. New services are onboarded under the managed service. Services requiring significant new configuration or integration are scoped and priced separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (172, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the platform scope, current service inventory, SLA requirements, and compliance obligations before the service agreement is drafted.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (173, 'Guest-journey friction map', 'A stage-by-stage view of where service breaks down, with root causes and the measurable cost of each failure point.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (173, 'Operational capability assessment', 'Rated review of staffing models, handoff processes, and technology coverage against your service standards.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (173, 'Prioritised improvement roadmap', 'Sequenced actions ranked by guest-satisfaction impact, feasibility, and estimated effort so you start with highest-return fixes.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (173, 'Quick-win summary', 'A short list of changes your team can make without capital investment, ready to action within weeks of the assessment.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (173, 'Which parts of our operation does the assessment cover?', 'Front-of-house service, housekeeping coordination, F&B operations, reservations, and the technology systems that connect them. We confirm exact scope with the DigitalQatalyst team during kick-off.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (173, 'Do you need access to our PMS or POS systems?', 'We review system configurations and reporting outputs, not guest data. Any access is read-only and agreed in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (173, 'What does the roadmap look like?', 'A sequenced list of improvements ranked by guest-experience impact and effort, with owners, dependencies, and a suggested phasing for delivery.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (173, 'We are seasonal. Does timing matter?', 'We recommend scheduling the assessment in shoulder season so operational leaders are available for interviews and the findings land before your next peak.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (173, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm the scope, the key stakeholders to involve, and the assessment start date.', 4);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (174, 'Guest service blueprint', 'Detailed end-to-end journey maps for each guest segment, with service standards, touchpoints, and failure-prevention checkpoints built in.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (174, 'Operational workflow specifications', 'Step-by-step workflow definitions for housekeeping, F&B, concierge, and front desk, designed to reduce handoff errors and response time.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (174, 'Technology integration architecture', 'Data-flow and integration diagrams connecting PMS, POS, guest-messaging, and back-office tools into a coherent operational picture.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (174, 'Adoption and training plan', 'Role-specific onboarding materials, training outlines, and a communication plan to bring staff along during rollout.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (174, 'What do we need to prepare before the design engagement starts?', 'Current service standards, PMS/POS system documentation, and availability of department heads for two workshops in week one. The DigitalQatalyst team will share a preparation checklist.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (174, 'Does this engagement include visual design for guest-facing interfaces?', 'The focus is service and workflow design. UI/visual design for any guest-facing digital surfaces is scoped separately if needed.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (174, 'How are the specifications handed over to the delivery team?', 'Documented blueprints, annotated workflow diagrams, and integration specs in a shared workspace, formatted for handover to internal or third-party delivery teams.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (174, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team will review your current-state documentation and confirm the design sprint schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (175, 'Validated AI use-case register', 'Each candidate AI use case scored against data availability, guest-experience value, operational feasibility, and responsible-AI criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (175, 'Responsible workflow designs', 'Step-by-step workflow specifications for approved AI features, with human-oversight triggers, override mechanisms, and escalation paths defined.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (175, 'Data readiness report', 'Assessment of the guest data, operational signals, and integration sources required for each use case, with gaps and remediation steps identified.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (175, 'AI deployment specification', 'Build-ready documentation covering model selection, API integration points, monitoring metrics, and rollback procedures for each approved use case.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (175, 'What kinds of AI use cases are typically in scope for hospitality?', 'Guest personalisation, dynamic room allocation, predictive maintenance scheduling, demand forecasting, and AI-assisted concierge responses are common starting points. The DigitalQatalyst team validates which are feasible for your data and operation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (175, 'Do we need a mature data platform before starting?', 'Not necessarily. The data readiness assessment identifies what you have and what gaps need closing before each use case can proceed to build.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (175, 'How do you handle guest-data privacy in AI designs?', 'Privacy requirements and data-minimisation principles are built into every workflow specification. We flag regulatory constraints relevant to your region during the engagement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (175, 'How do we get started?', 'Request a scoping call. The DigitalQatalyst team will confirm which AI use cases to evaluate and what data access is needed to run the feasibility assessment.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (176, 'Configured operational platform', 'PMS, POS, and guest-communication systems configured to your service blueprint, with integrations tested and operational across all departments.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (176, 'Test results and sign-off report', 'Complete test evidence covering integration, workflow, and staff acceptance scenarios, with all critical issues resolved before go-live.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (176, 'Staff training completion record', 'Documented training completion by department and role, with assessed competency against the operational standards defined in the design phase.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (176, 'Operational handover pack', 'System configuration documentation, runbooks, escalation contacts, and first-90-days operational guidance for your management team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (176, 'Do we need to complete the design phase before deploying?', 'Yes. Deployment builds from approved specifications. If you do not have these, the DigitalQatalyst team can scope the design phase first.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (176, 'How is live-guest disruption avoided during the rollout?', 'Configuration and testing happen in a non-production environment. The go-live is phased by department or property and scheduled during low-occupancy periods where possible.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (176, 'What happens if critical issues are found during acceptance testing?', 'Issues are logged, triaged, and resolved before the go-live gate. No launch proceeds until critical and high-severity issues are closed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (176, 'How do we get started?', 'Share your approved design specifications with the DigitalQatalyst team and we will scope the deployment plan, environment setup, and timeline.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (177, 'Live AI capability suite', 'Approved AI features in production, integrated with your PMS, guest-data sources, and operational workflows, tested and accepted by department leads.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (177, 'Monitoring and alerting dashboard', 'Real-time view of model performance, guest-experience impact metrics, and operational KPIs, with alert thresholds set to your agreed tolerances.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (177, 'Governance and override documentation', 'Written policies and in-system controls covering when staff must override AI recommendations, escalation paths, and incident-response procedures.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (177, 'AI operations handover pack', 'Model cards, integration diagrams, monitoring runbooks, and retraining schedules handed to your technology and operations teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (177, 'Which AI capabilities are typically deployed in this engagement?', 'Those validated in the AI Design phase: commonly personalisation engines, predictive housekeeping scheduling, demand forecasting, and AI-assisted concierge. Scope is confirmed from your approved specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (177, 'How do you prevent AI errors from affecting guests?', 'Shadow-mode testing runs the models against live data without acting on outputs until performance thresholds are met. Staff override controls remain active after launch.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (177, 'Who owns the AI models after handover?', 'Your technology team, with the DigitalQatalyst team providing model cards, monitoring documentation, and retraining schedules as part of the handover pack.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (177, 'How do we get started?', 'Provide your approved AI deployment specifications and the DigitalQatalyst team will confirm the production environment requirements and phased activation plan.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (178, 'Monthly performance report', 'Guest satisfaction scores, system uptime, service throughput, and trend analysis across all monitored platforms, delivered every month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (178, 'Optimisation log', 'Record of every configuration change, workflow adjustment, and integration fix made during the service period, with outcomes noted.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (178, 'SLA compliance report', 'Monthly record of incidents, response times, and resolution times against agreed SLA targets, with root-cause notes for any breaches.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (178, 'Annual service roadmap', 'Forward-looking plan identifying optimisation priorities, technology refresh opportunities, and recommended investments for the next 12 months.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (178, 'What does the managed service cover?', 'Monitoring, incident response, and proactive optimisation of your hospitality operations platform, including PMS, POS, and guest-communication integrations. Exact scope is agreed during onboarding.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (178, 'What SLAs apply?', 'Response and resolution targets are confirmed during onboarding based on your platform criticality. Guest-facing system incidents receive priority-one treatment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (178, 'Can the service expand to cover new systems added after launch?', 'Yes. The DigitalQatalyst team can onboard additional platforms into the managed scope as your technology estate grows.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (178, 'How do we get started?', 'Contact the DigitalQatalyst team to schedule a service onboarding call. We confirm the systems in scope, SLA targets, reporting format, and the named contacts on both sides.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (179, 'Omnichannel operations audit', 'A channel-by-channel review of customer journey friction points, handoff failures, and inventory inconsistencies with root causes and impact estimates.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (179, 'Inventory visibility report', 'Assessment of real-time stock accuracy across stores, warehouses, and digital channels, with the gaps creating lost sales or excess markdown.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (179, 'Store productivity scorecard', 'Benchmark of task completion rates, scheduling efficiency, and service standards across your estate, with the highest-leverage improvement opportunities identified.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (179, 'Prioritised action roadmap', 'Sequenced improvement actions ranked by revenue impact and delivery effort, with suggested ownership and a phasing recommendation for your leadership team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (179, 'How many stores or channels does the assessment cover?', 'Scope is confirmed with the DigitalQatalyst team before the engagement starts. Typically one to three representative store formats and your primary digital channel are included.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (179, 'What data do you need access to?', 'Sales reports, inventory records, and operational metrics. No customer PII is required. Data access is read-only and agreed in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (179, 'Do you cover both physical retail and e-commerce?', 'Yes. The assessment maps the customer journey across all channels your business operates, including click-and-collect and returns flows.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (179, 'How do we get started?', 'Request a consultation with the DigitalQatalyst team. We confirm the channels in scope, the data required, and the assessment schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (180, 'Omnichannel journey designs', 'Detailed customer journey maps for each channel and segment, with service standards, touchpoints, and consistency checkpoints across store and digital surfaces.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (180, 'Inventory and order workflow specifications', 'Step-by-step process definitions for receiving, picking, packing, fulfilment, and returns, designed to eliminate the handoff errors identified in assessment.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (180, 'Technology integration architecture', 'Data-flow diagrams and integration specifications connecting POS, OMS, WMS, and customer-data platforms into a coherent retail operations picture.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (180, 'Adoption and rollout plan', 'Store-by-store and channel-by-channel rollout sequence with training materials, communication templates, and go/no-go criteria for each phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (180, 'Can we run the design engagement without completing an assessment first?', 'Yes, if you have clear objectives and existing operational data. The DigitalQatalyst team will confirm whether a design-only engagement is appropriate during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (180, 'Does the design cover both store and digital channels?', 'Yes. Journey designs and workflow specifications cover every channel in scope, including click-and-collect, ship-from-store, and returns.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (180, 'What format are the specifications delivered in?', 'Annotated journey maps, workflow diagrams, and integration specs delivered in a shared digital workspace formatted for handover to internal or third-party delivery teams.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (180, 'How do we get started?', 'Book a scoping call and the DigitalQatalyst team will confirm the channels in scope, the workshops required, and the design sprint schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (181, 'Validated retail AI use-case register', 'Candidate AI use cases scored against commercial value, data availability, regulatory constraints, and responsible-AI criteria specific to retail.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (181, 'Responsible workflow designs', 'Step-by-step AI-assisted workflow specifications for approved use cases, with pricing override controls, human-review triggers, and escalation paths.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (181, 'Retail data readiness report', 'Assessment of transactional, inventory, and customer-behaviour data required for each approved AI use case, with gaps and remediation steps.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (181, 'AI deployment specification', 'Build-ready documentation covering model selection, integration points, monitoring metrics, and rollback procedures for each approved retail AI use case.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (181, 'What AI use cases are most common in retail?', 'Demand forecasting, personalised product recommendations, dynamic markdown optimisation, inventory replenishment triggers, and AI-assisted loss prevention. The DigitalQatalyst team validates which are feasible for your data estate.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (181, 'Do we need a unified data platform before starting?', 'No. The data readiness assessment identifies what you have and what gaps need closing. Some use cases may be ready to build immediately; others need data infrastructure work first.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (181, 'How do you handle pricing AI responsibly?', 'Pricing and markdown AI workflow designs include mandatory human-review stages and override controls. We specify the governance process before any build investment is made.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (181, 'How do we get started?', 'Request a scoping call and the DigitalQatalyst team will confirm which AI use cases to evaluate and what data access is required for the feasibility assessment.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (182, 'Configured retail operations platform', 'POS, OMS, and WMS configured and integrated across your in-scope channels and store formats, with data flows tested end-to-end.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (182, 'Test results and channel sign-off report', 'Test evidence covering integration, fulfilment workflow, and acceptance scenarios for each channel, with all critical issues resolved pre-launch.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (182, 'Staff training completion record', 'Documented training completion by store format, role, and digital-operations function, with competency assessed against operational standards.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (182, 'Retail operations handover pack', 'System configuration documentation, runbooks, escalation contacts, and first-90-days operational guidance for store operations and digital teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (182, 'Can we deploy store and online channels simultaneously?', 'Usually not recommended. The DigitalQatalyst team designs a phased channel sequence that lets you validate in-store operation before activating digital fulfilment flows.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (182, 'How is existing inventory data migrated?', 'Migration is planned, validated, and tested in a non-production environment before go-live. The migration approach is confirmed with your operations team during weeks one to three.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (182, 'What if acceptance testing reveals issues with a specific store format?', 'Issues are logged, triaged, and resolved before that format proceeds to launch. Go-live gates are format-specific so a delay in one store type does not hold back others.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (182, 'How do we get started?', 'Share your approved design specifications with the DigitalQatalyst team and we will scope the deployment plan and environment requirements.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (183, 'Live retail AI capability suite', 'Approved AI features in production, integrated with POS, OMS, and inventory systems, accepted by merchandising and operations leads.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (183, 'Retail AI monitoring dashboard', 'Real-time view of model performance, revenue and inventory impact metrics, and alert thresholds set to your agreed commercial tolerances.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (183, 'Merchandising governance documentation', 'Written policies and in-system controls covering when merchandising teams must review or override AI pricing and replenishment recommendations.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (183, 'AI operations handover pack', 'Model cards, integration diagrams, monitoring runbooks, and retraining schedules for your technology and retail operations teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (183, 'Which AI features are typically activated in this deployment?', 'Those validated in the AI Design phase: commonly demand forecasting, personalised recommendations, and markdown optimisation. Scope is confirmed from your approved specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (183, 'How do you protect pricing integrity during AI activation?', 'Shadow-mode testing runs pricing AI against live data without acting on outputs until accuracy thresholds are met. Merchandising override controls remain active after full launch.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (183, 'Who is responsible for retraining AI models over time?', 'Your technology team, using the retraining schedules and model documentation handed over at the end of the engagement. The DigitalQatalyst team can provide managed-service support if needed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (183, 'How do we get started?', 'Provide your approved AI deployment specifications and the DigitalQatalyst team will confirm production environment requirements and the use-case activation sequence.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (184, 'Monthly omnichannel performance report', 'Conversion, fulfilment accuracy, inventory availability, and system-uptime metrics across all in-scope channels, delivered every month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (184, 'Optimisation log', 'Record of every workflow adjustment, configuration change, and integration fix made during the service period, with before-and-after metrics noted.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (184, 'SLA compliance report', 'Monthly record of incidents, response times, and resolution times against agreed SLA targets, with root-cause notes for any breaches.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (184, 'Annual retail technology roadmap', 'Forward-looking plan identifying optimisation priorities, platform upgrade opportunities, and recommended investments for the next 12 months.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (184, 'What systems does the managed service cover?', 'POS, OMS, WMS, and the integrations connecting them across your in-scope channels. Additional platforms can be onboarded as your estate grows.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (184, 'What SLA response times apply?', 'Targets are agreed during onboarding based on platform criticality. Customer-facing system failures receive priority-one treatment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (184, 'Does the managed service include peak-trading support?', 'Yes. The DigitalQatalyst team reviews your trading calendar during onboarding and confirms enhanced monitoring windows for peak periods.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (184, 'How do we get started?', 'Contact the DigitalQatalyst team to schedule a service onboarding call covering systems in scope, SLA targets, reporting format, and the named contacts on both sides.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (185, 'Service throughput diagnostic', 'Data-backed analysis of job completion rates, rework volumes, and first-visit resolution rates, with root causes identified for the highest-cost failure patterns.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (185, 'Scheduling and dispatch efficiency report', 'Assessment of your scheduling model, dispatch logic, and field coverage with the specific inefficiencies costing you capacity and response time.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (185, 'Customer experience gap map', 'Stage-by-stage view of where service commitments are missed, with the customer-satisfaction and retention impact of each gap quantified.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (185, 'Prioritised improvement roadmap', 'Sequenced action plan ranked by throughput and retention impact, with ownership suggestions and a phasing recommendation for leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (185, 'Which types of service operations does the assessment cover?', 'Field service, professional services delivery, maintenance and repair, technical support, and customer service operations. Scope is confirmed with the DigitalQatalyst team before start.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (185, 'What data do you need?', 'Job completion records, scheduling data, rework logs, and customer satisfaction scores. No customer PII is required beyond anonymised feedback data.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (185, 'Can the assessment cover remote and on-site service delivery?', 'Yes. The assessment maps both remote and field delivery models where your operation runs a combination of both.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (185, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm the operational scope, data requirements, and assessment schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (186, 'Job lifecycle workflow designs', 'End-to-end workflow specifications from job intake to closure, with quality checkpoints, escalation paths, and completion standards defined at each stage.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (186, 'Field service process specifications', 'Step-by-step field task definitions, completion-standard checklists, and sign-off requirements designed to reduce rework and improve first-visit resolution.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (186, 'Technology integration architecture', 'Data-flow diagrams connecting FSM, CRM, ERP, and mobile field-application data into a coherent operational picture for scheduling and reporting.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (186, 'Adoption and training plan', 'Role-specific onboarding materials for dispatch teams, field staff, and service managers, with a rollout sequence and go/no-go criteria.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (186, 'Does the design cover both back-office scheduling and field execution?', 'Yes. Job lifecycle designs span intake, scheduling, dispatch, field execution, and closure, with handoff specifications at each stage.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (186, 'What if we are replacing our FSM platform as part of this programme?', 'The integration architecture can be designed for your target FSM system if a platform migration is already planned. The DigitalQatalyst team confirms the approach during scoping.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (186, 'How are the specifications handed to the delivery team?', 'Annotated workflow diagrams, process specifications, and integration architectures in a shared workspace formatted for handover to internal or vendor delivery teams.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (186, 'How do we get started?', 'Book a scoping call and the DigitalQatalyst team will confirm the workflow scope, the workshops required, and the design sprint schedule.', 3);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (187, 'Validated service AI use-case register', 'Candidate AI use cases scored against throughput value, data availability, and responsible-AI criteria specific to service and field operations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (187, 'Responsible dispatch AI workflow designs', 'Step-by-step specifications for AI-assisted scheduling and dispatch, with dispatcher override controls, confidence thresholds, and escalation procedures.', 1);
